-- Poems batch 218
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('7c25d80a-00d0-4fcc-bc01-7c8eddadb5d7','又絕句二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','東閣郎君己貳卿，斡回嚴冷作和平。',32,'全唐诗/poet.song.202000.json','["東閣郎君己貳卿，斡回嚴冷作和平。", "專人昔暴於家靼，太傅今賢似父兄。"]'),
('6a860ef6-13b8-4ab9-8673-5de619aac0f4','又絕句二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','物貴皆由楮幣輕，近聞五嶺亦通行。',32,'全唐诗/poet.song.202000.json','["物貴皆由楮幣輕，近聞五嶺亦通行。", "舊時白葦黄茅裏，有犬鷄聲布有聲。"]'),
('ab113eb2-cc44-4e51-a577-8cdc1bdc4d5c','挽去華主簿姪二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','汝是家珍寶，虹光貫夜窗。',48,'全唐诗/poet.song.202000.json','["汝是家珍寶，虹光貫夜窗。", "友生墊巾慕，才子樹旗降。", "顔氏應難兩，黄香未易雙。", "向來有椽筆，老去付誰扛。"]'),
('5d9c3a10-3c82-4273-973c-3bebe0b37abc','挽去華主簿姪二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','子美尤稱位，昌黎若惜滂。',48,'全唐诗/poet.song.202000.json','["子美尤稱位，昌黎若惜滂。", "色空融佛性，冰炭置吾腸。", "未審生何國，猶疑在我傍。", "一條勝謝傅，老不廢朞喪。"]'),
('9a94ac0f-3af3-480d-8127-4f220ea8831f','羅浮寄公儲子洪二兄四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','片帆約我上羅浮，已戒籃輿與共遊。',32,'全唐诗/poet.song.202000.json','["片帆約我上羅浮，已戒籃輿與共遊。", "到得羅浮君不見，後期又是八千秋。"]'),
('e1f37eba-cb54-4668-91b0-6d8cb226cf3c','羅浮寄公儲子洪二兄四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','城中冠蓋匆匆散，老子空携影逐身。',32,'全唐诗/poet.song.202000.json','["城中冠蓋匆匆散，老子空携影逐身。", "追路餞余三百里，斯人心事異他人。"]'),
('3af8eb49-7828-43dc-961f-fe99ffbb8c36','羅浮寄公儲子洪二兄四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','別來怪雨挾顛風，想見江頭惱此翁。',32,'全唐诗/poet.song.202000.json','["別來怪雨挾顛風，想見江頭惱此翁。", "湖海元龍身九尺，可憐蟠屈葉舟中。"]'),
('94849ed3-b57d-4209-bc4f-a4db959fefc1','羅浮寄公儲子洪二兄四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','若見子期煩問訊，二詩真可續坡仙。',32,'全唐诗/poet.song.202000.json','["若見子期煩問訊，二詩真可續坡仙。", "捷材渠似雜弦箭，澀思儂如上水船。"]'),
('e76a4ee5-022e-4d6f-8350-0e8e53a2fcdc','容堂生日','劉克莊','宋','宋诗','song-poetry','','[]','玉守清無一點塵，泠泠笙鶴下青旻。',64,'全唐诗/poet.song.202000.json','["玉守清無一點塵，泠泠笙鶴下青旻。", "大期爵德尊三者，上界神仙第一人。", "經畫中原皆向化，燮調四序總如春。", "自憐九袠鬚眉老，籠鴿難陪祝壽賓。"]'),
('de31ffa0-0ad5-4ca4-8965-4656e2c2cc10','送大淵宰安溪七言三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','御堦人看放班回，誰記乾淳舊事哉。',64,'全唐诗/poet.song.202000.json','["御堦人看放班回，誰記乾淳舊事哉。", "進卷已嘗觀所主，聞絃上欲老其才。", "割鷄必待民謠著，峨豸多由縣譜來。", "莫道勝流俱不屑，艾軒做了到誠齋。"]'),
('7e38ce3a-8a8e-46f8-aa23-dd60208e9ed4','送大淵宰安溪七言三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','昏昏默默嗟衰朽，白白紅紅憶盛强。',64,'全唐诗/poet.song.202000.json','["昏昏默默嗟衰朽，白白紅紅憶盛强。", "自古人惟稱單父，至今我尚愛桐鄉。", "刈時留取葵根在，拔處無令薤本傷。", "邑有澹臺輩流否，不妨迎致向琴堂。"]'),
('3eee9c8c-73fb-43b0-94a8-fca8a8e78e44','送大淵宰安溪七言三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','吾觀明府毫端妙，傳得尊公肘後方。',64,'全唐诗/poet.song.202000.json','["吾觀明府毫端妙，傳得尊公肘後方。", "番俗尚歌漢東柳，莆人不剪召南棠。", "威驅未若心懷惠，內荏徒然外抑强。", "想見江鄉與閩嶠，家家各炷一爐香。"]'),
('76fe1a32-d04f-4be7-bd2f-9fdd8b193aaa','又五言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','子去臨民社，公私必小寬。',48,'全唐诗/poet.song.202000.json','["子去臨民社，公私必小寬。", "皆云官似水，誰道縣如灘。", "村絕追胥跡，溪無督賦瘢。", "自從陳李後，古調少人彈。"]'),
('03576d1e-2fe4-41b0-b3c5-1c8b7cb3d28b','又五言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','剖决時通夕，將迎或望塵。',48,'全唐诗/poet.song.202000.json','["剖决時通夕，將迎或望塵。", "官爲賢令尹，位下郡專人。", "尚欲平州欠，何曾歎縣貧。", "能容老夫否，負耒去爲民。"]'),
('f2cf6e9d-7e49-42e1-9973-a38122bd370f','柬惠安同安葉陳二明府併煩安溪林明府寄似','劉克莊','宋','宋诗','song-poetry','','[]','吾友二三子，聯翩有國都。',48,'全唐诗/poet.song.202000.json','["吾友二三子，聯翩有國都。", "平平雖縣譜，急急奈州符。", "亦既吹虀矣，還能吸醋無。", "高年頗更事，莫哂瞽言迂。"]'),
('7e2085e9-f6ee-48b9-9066-d0114b083034','和黄彥華帥機六言十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','世情喚做三絕，佛眼譬之六如。',28,'全唐诗/poet.song.202000.json','["世情喚做三絕，佛眼譬之六如。", "當日最宜爲誥，而今老不中書。"]'),
('4aa35c5f-6317-423c-b38e-4edbb3d236c8','和黄彥華帥機六言十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','子美花狂已減，玉川茶興方濃。',28,'全唐诗/poet.song.202000.json','["子美花狂已減，玉川茶興方濃。", "耕處偶逢沮溺，池邊懶送夔龍。"]'),
('0c159b27-b83b-4517-bc40-e4b254fc0847','和黄彥華帥機六言十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','老矣宦情素薄，天於書分尤慳。',28,'全唐诗/poet.song.202000.json','["老矣宦情素薄，天於書分尤慳。", "寧作一鷗浮海，長笑六鼇負山。"]'),
('fa6f5648-483e-43b1-801f-c4b01fadf4a9','和黄彥華帥機六言十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','吾嘗評論齊物，未知彭殤孰賢。',28,'全唐诗/poet.song.202000.json','["吾嘗評論齊物，未知彭殤孰賢。", "蒙莊略曉些子，分別小年大年。"]'),
('2875f97a-be34-4069-bcb3-5a63a0872099','和黄彥華帥機六言十首  其五','劉克莊','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','世無識面仙者，或言飛過洞庭。',28,'全唐诗/poet.song.202000.json','["世無識面仙者，或言飛過洞庭。", "望斗氣半空紫，衝秋霄一點青。"]'),
('c8da0ff2-82d4-4f95-beed-8b4cc6013307','和黄彥華帥機六言十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','遺稿六丁取盡，君王謾遣所忠。',28,'全唐诗/poet.song.202000.json','["遺稿六丁取盡，君王謾遣所忠。", "既友商山四皓，又容淮南八公。"]'),
('2f2f316d-b4a9-4cef-8f61-44ab6d765e65','和黄彥華帥機六言十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','似憐翁老吾老，寧論子才不才。',28,'全唐诗/poet.song.202000.json','["似憐翁老吾老，寧論子才不才。", "皆云法當止矣，况於身要扶哉。"]'),
('224d2b4c-9094-418c-8a62-c98ee727edb1','和黄彥華帥機六言十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','老閲萬般交態，病無一點世情。',28,'全唐诗/poet.song.202000.json','["老閲萬般交態，病無一點世情。", "但憶懶殘芋熟，都忘太乙藜青。"]'),
('3c316fcc-b7a0-4336-9cdf-e34a6d450959','和黄彥華帥機六言十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','骯髒倚門如敖，滑稽玩世非顛。',28,'全唐诗/poet.song.202000.json','["骯髒倚門如敖，滑稽玩世非顛。", "坡即崇寧奎宿，白是開元謫仙。"]'),
('c24373fb-4d8d-4c45-b903-59eac3c58348','和黄彥華帥機六言十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','已邀入真率會，更約過天津橋。',28,'全唐诗/poet.song.202000.json','["已邀入真率會，更約過天津橋。", "從此年年歲歲，莫負月夕花朝。"]'),
('23f381f6-b467-43e5-8edc-bd731b8b4846','縱筆六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','賦金屋信美矣，記玉樓果如何。',28,'全唐诗/poet.song.202000.json','["賦金屋信美矣，記玉樓果如何。", "人間國艷難得，天上才子不多。"]'),
('ede06766-5590-4298-8acd-c288cdc50d02','縱筆六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','蒯酈提趨沸湯，信越狗烹弓藏。',28,'全唐诗/poet.song.202000.json','["蒯酈提趨沸湯，信越狗烹弓藏。", "向來猛士盡矣，與誰共守四方。"]'),
('fb4dc943-ecbf-43c4-8539-dbb2909b59ab','贈天隠李君瑞一首','劉克莊','宋','宋诗','song-poetry','','[]','唱名納祿尤崖異，誓墓休官更崛奇。',64,'全唐诗/poet.song.202000.json','["唱名納祿尤崖異，誓墓休官更崛奇。", "先輩翔而皆集矣，廣文得此欲逃之。", "聖門豈不高曾晳，列傳何爲首伯夷。", "虎帥聽君誰敢犯，莫欺此老白鬚眉。"]'),
('3fb9ecbe-208c-44cd-9ee9-9a23ee0c0657','次韵鄉侯計院二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','諸老皆曾接典型，鵞湖一輩亦豪英。',64,'全唐诗/poet.song.202000.json','["諸老皆曾接典型，鵞湖一輩亦豪英。", "晚持師說尤堅壘，不怕兵家會斫營。", "晴色極佳宜歲事，郊行因好訪民情。", "朝家要採風謠否，第一君侯號治平。"]'),
('34eda188-b545-43ad-8328-8e2248b97f8c','次韵鄉侯計院二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','還山非敢厭承明，鶴唳鶑啼若個清。',64,'全唐诗/poet.song.202000.json','["還山非敢厭承明，鶴唳鶑啼若個清。", "警句摘稀慚傑思，博封冰少見交情。", "當年扈蹕重金貴，他日飛空一劍輕。", "莫問路頭何處去，出門萬里水雲程。"]'),
('fcc8a7ba-ca21-4025-ac2c-130ebf8059d7','詠史五言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','西都生昴宿，東井聚奎星。',48,'全唐诗/poet.song.202000.json','["西都生昴宿，東井聚奎星。", "僅可尊秦陛，安能肅漢廷。", "收圖懲滅籍，起蕝欠嵇經。", "何况杯羹語，書之涴汗青。"]'),
('6e96b48d-8d6c-45e0-b926-f6ef96065c23','詠史五言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','雖化家爲國，其如夏變夷。',48,'全唐诗/poet.song.202000.json','["雖化家爲國，其如夏變夷。", "可汗僭天子，蕭后作閼氏。", "玉檢無升頂，珠襦有裸尸。", "未應長樂老，飲酒又吟詩。"]'),
('4a168c24-e297-42cc-a156-c3fcce367235','道釋六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','蕭衍老公苦行，捨身之舉壯哉。',28,'全唐诗/poet.song.202000.json','["蕭衍老公苦行，捨身之舉壯哉。", "祇怕侯丞相者，不許梁朝贖回。"]'),
('39430ae9-8d4e-4776-81cd-12ae766941da','道釋六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','大榼酒時酩酊，小瓢藥自貴珍。',28,'全唐诗/poet.song.202000.json','["大榼酒時酩酊，小瓢藥自貴珍。", "老去修持如故，向來符呪通神。"]'),
('34191a44-23d4-4d4c-b9b4-6176f945d473','記漢事六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','紛然擊柱諸將，付之起蕝叔孫。',28,'全唐诗/poet.song.202000.json','["紛然擊柱諸將，付之起蕝叔孫。", "向來常駡儒腐，今日方知帝尊。"]'),
('80471dbb-5c39-4dcb-8357-bfadf295d1e5','記漢事六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','始欲報五世相，末不願萬戶留。',28,'全唐诗/poet.song.202000.json','["始欲報五世相，末不願萬戶留。", "少從黄石公授，晚與赤松子游。"]'),
('405885a2-1e4b-4814-a324-2b3f272edabc','兩朝口號六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','堯舜若稽古外，烈祖聖謨洋洋。',28,'全唐诗/poet.song.202000.json','["堯舜若稽古外，烈祖聖謨洋洋。", "道理一句最大，卓冠萬世帝王。"]'),
('45815c18-e0e5-4aa4-9b6d-e3a4070dd30f','兩朝口號六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','宇宙包吾仁內，充之惟天惟堯。',28,'全唐诗/poet.song.202000.json','["宇宙包吾仁內，充之惟天惟堯。", "昊穹敬此一字，千載以待永昭。"]'),
('fe040618-bb63-4c5d-80d8-a9cfb599ed28','記漢唐事六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','黄鵠之歌高古，大風之作激昂。',28,'全唐诗/poet.song.202000.json','["黄鵠之歌高古，大風之作激昂。", "橫汾酒酣樂作，其如感慨悲傷。"]'),
('da02224c-3755-4a32-9068-5e29f01993f7','記漢唐事六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','輦路感春草句，殿閣賦薰風人。',28,'全唐诗/poet.song.202000.json','["輦路感春草句，殿閣賦薰風人。", "聯句未聞筆諫，凭高空憶侍臣。"]'),
('a562d065-b929-4607-a3db-abe3c414a2ec','送君用姪判官','劉克莊','宋','宋诗','song-poetry','','[]','天官長榜該差久，公相繁機押敕遲。',64,'全唐诗/poet.song.202000.json','["天官長榜該差久，公相繁機押敕遲。", "佩玉徐行真上介，著鞭先發任羣兒。", "方慚當宁詢黄髮，絕喜吾宗見白眉。", "聞說守侯留禰墨，水衡召拜必同時。"]'),
('6761e584-8cb7-4f25-aeac-b6bdbf6fd105','題近稿','劉克莊','宋','宋诗','song-poetry','','[]','簞瓢久已甘顔巷，筆橐先曾侍漢廷。',64,'全唐诗/poet.song.202000.json','["簞瓢久已甘顔巷，筆橐先曾侍漢廷。", "杜視王侯等螻蟻，坡輕名利比蝸蠅。", "更無荐鮪儀登俎，時有求羊炬入陵。", "老矣終身作傖父，諸公努力佐中興。"]'),
('3659bde8-a996-4cd5-8912-84a3c4ebd8ad','絕句三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','定本蘭亭傳贋久，党公薑字發蒙初。',32,'全唐诗/poet.song.202000.json','["定本蘭亭傳贋久，党公薑字發蒙初。", "兒童若問何人寫，向道樗翁八十餘。"]'),
('a33614ba-8841-4ced-bb52-21a70163b48e','絕句三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','愁腸一飲輒無算，病眼四時常有花。',32,'全唐诗/poet.song.202000.json','["愁腸一飲輒無算，病眼四時常有花。", "舊日讀書垂釣處，重尋如到別人家。"]'),
('0aa2a648-47c0-4fa7-aa3a-6bb334b9293a','絕句三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','潘郎鬢豈春能綠，東野肩非雪亦寒。',32,'全唐诗/poet.song.202000.json','["潘郎鬢豈春能綠，東野肩非雪亦寒。", "世外那無仙可學，人間惟有老難瞞。"]'),
('6c4040d7-1825-44b8-b2fa-2d95602a9fe1','戊辰重陽絕句','劉克莊','宋','宋诗','song-poetry','','[]','馮唐白首尚含香，衛武諄諄肯惰荒。',32,'全唐诗/poet.song.202000.json','["馮唐白首尚含香，衛武諄諄肯惰荒。", "萬一享年如二老，猶堪爛醉十重陽。"]'),
('733cf5d6-66b5-4d0e-b061-0396e61514ae','和居厚弟韵','劉克莊','宋','宋诗','song-poetry','','[]','端嘉已羨谷鶑遷，不覺龍飛又幾年。',64,'全唐诗/poet.song.202000.json','["端嘉已羨谷鶑遷，不覺龍飛又幾年。", "坡老嘗稱少公勝，伯淳曾道二哥賢。", "騰箋內舉雖如此，秉筆中書豈必然。", "歲晚偶同耆舊傳，瞎翁安得似癯仙。"]'),
('e0e2f08d-6142-4a43-b134-d0b4aca6dc91','畫笥有二粉頭各題一絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','裕陵臨御始，像祭武襄公。',24,'全唐诗/poet.song.202000.json','["裕陵臨御始，像祭武襄公。", "郜六何爲者，圖形一禁中。"]'),
('b2f63e06-0d1e-4bef-8967-6957039dd413','畫笥有二粉頭各題一絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','高帝開江左，如天有太陽。',24,'全唐诗/poet.song.202000.json','["高帝開江左，如天有太陽。", "迎歸皇太后，放出小流娘。"]'),
('fa10f636-3a82-45d6-adc3-4e2108b8c853','狂吟','劉克莊','宋','宋诗','song-poetry','','[]','兩輪屋角走如梭，爭奈樗翁老病何。',64,'全唐诗/poet.song.202000.json','["兩輪屋角走如梭，爭奈樗翁老病何。", "富貴時來年少去，神仙者少死人多。", "形羸全頼兒扶掖，詩退猶須友切磋。", "莫嗟狂吟無律呂，古人不廢飯牛歌。"]'),
('2e4dfc8c-93ba-4050-af30-48ea8435cac8','題趙志仁南溪雙蓮','劉克莊','宋','宋诗','song-poetry','','[]','迺翁去記玉樓成，歲帥鄉人祀洛英。',64,'全唐诗/poet.song.202000.json','["迺翁去記玉樓成，歲帥鄉人祀洛英。", "文耀可無田助祭，象賢頼有谷傳聲。", "奇葩融結雙蓮瑞，奕葉追攀五桂榮。", "纍將重侯何足道，幾人三世有詩名。"]'),
('62e9fd7e-5998-4780-b7b2-a44c6ace9e55','挽趙倅','劉克莊','宋','宋诗','song-poetry','','[]','半刺官雖滯，全人世所稀。',48,'全唐诗/poet.song.202000.json','["半刺官雖滯，全人世所稀。", "生無瑕可指，古以死爲歸。", "故笥斑衣在，新阡鶴表飛。", "銘幽仍相挽，老淚拭還揮。"]'),
('521c69b6-21b5-44a3-b220-cc662ce1beb9','應真二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','五百逋逃士，劉郎不放心。',24,'全唐诗/poet.song.202000.json','["五百逋逃士，劉郎不放心。", "教醒阿羅漢，飛空無處尋。"]'),
('b8331e29-20cc-48e5-8119-64587f473120','應真二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','支解讎人毒，香塗施主恩。',24,'全唐诗/poet.song.202000.json','["支解讎人毒，香塗施主恩。", "對天剖腸胃，倒海洗親冤。"]'),
('e702c98e-5f7d-4ac1-b465-5564b09b69b6','贈東塔璵老','劉克莊','宋','宋诗','song-poetry','','[]','南寺上人禪學苦，東岡老子法筵開。',32,'全唐诗/poet.song.202000.json','["南寺上人禪學苦，東岡老子法筵開。", "遥知大設伊蒲供，送汝挑包去撈齋。"]'),
('d7d57849-0fd0-49b3-847f-aeb5203be36c','題倪魯玉詩後二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','梅經御史鞫成案，村荷先皇敕扁堂。',64,'全唐诗/poet.song.202000.json','["梅經御史鞫成案，村荷先皇敕扁堂。", "少日不容人入社，暮年甘被子侵疆。", "不應愚谷知名姓，惟許孤山擅影香。", "豈獨江湖酬唱者，卷中諸老半存亡。"]'),
('2fa86bcd-02fc-4ff6-ae05-3ba1a12932d6','題倪魯玉詩後二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','自從風雅陵夷後，吟到梅村世豈多。',64,'全唐诗/poet.song.202000.json','["自從風雅陵夷後，吟到梅村世豈多。", "曠達知章歸後作，軒昂予美醉時歌。", "擊蒙何止聞童稚，譴瘧猶堪去病魔。", "一聽牙絃三歎息，今無鍾子奈詩何。"]'),
('f7a281bd-7b36-4846-9c3d-9f213d8a58b7','雜詠五言八首  其一','劉克莊','宋','宋诗','song-poetry','','[]','夢中求荐寢，此事有還無。',24,'全唐诗/poet.song.202000.json','["夢中求荐寢，此事有還無。", "幸得東安女，爲王洗厚誣。"]'),
('27b8aa73-ee12-404e-aba5-3b552f96bb7a','雜詠五言八首  其二','劉克莊','宋','宋诗','song-poetry','','[]','魏帝恩雖重，川靈禮自防。',24,'全唐诗/poet.song.202000.json','["魏帝恩雖重，川靈禮自防。", "不曾簪美珥，安有獻明璫。"]'),
('58ac0b5c-6a3e-4689-b37a-e088d956e350','雜詠五言八首  其三','劉克莊','宋','宋诗','song-poetry','','[]','燕燕鶑鶑喻，工於狀婦容。',24,'全唐诗/poet.song.202000.json','["燕燕鶑鶑喻，工於狀婦容。", "不如洛神賦，比擬作驚鴻。"]'),
('d692b062-843b-4223-89ac-2609391cdd87','雜詠五言八首  其四','劉克莊','宋','宋诗','song-poetry','','[]','園令詞章妙，君王悔悟深。',24,'全唐诗/poet.song.202000.json','["園令詞章妙，君王悔悟深。", "能回九重眷，只賣百斤金。"]'),
('fdba9f9d-b028-4126-9966-ac4ee7572a5f','雜詠五言八首  其五','劉克莊','宋','宋诗','song-poetry','','[]','斷絃難續矣，讀者尚悲辛。',24,'全唐诗/poet.song.202000.json','["斷絃難續矣，讀者尚悲辛。", "不似窮馮衍，甘爲薄倖人。"]'),
('8fb06120-0ad6-4506-ba83-b71565931d83','雜詠五言八首  其六','劉克莊','宋','宋诗','song-poetry','','[]','難尋楚三戶，不記漢千門。',24,'全唐诗/poet.song.202000.json','["難尋楚三戶，不記漢千門。", "獨有靈光殿，長因一賦存。"]'),
('791ef4ad-2843-4543-a2ae-953c4047c00e','雜詠五言八首  其七','劉克莊','宋','宋诗','song-poetry','','[]','有劍彈驩鋏，無金築隗臺。',24,'全唐诗/poet.song.202000.json','["有劍彈驩鋏，無金築隗臺。", "孝王雖貴介，猶解客鄒枚。"]'),
('b109f891-9690-4a9e-8da6-1f67e2788d19','雜詠五言八首  其八','劉克莊','宋','宋诗','song-poetry','','[]','埋向西陵裏，千年不復晨。',24,'全唐诗/poet.song.202000.json','["埋向西陵裏，千年不復晨。", "未知臺上妓，歌舞樂何人。"]'),
('c215f9fc-dfc6-44fe-8dd4-eeae959bdb70','兩曜二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','朝朝出陽谷，夜夜入虞淵。',24,'全唐诗/poet.song.202000.json','["朝朝出陽谷，夜夜入虞淵。", "且看烏輪轉，休論蟻磨旋。"]'),
('32c6ffb3-3478-4a4d-92b0-b5d307c7a35b','兩曜二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','不甘蟇蝕月，泣獻磔蟇詩。',24,'全唐诗/poet.song.202000.json','["不甘蟇蝕月，泣獻磔蟇詩。", "却效玉川子，仍曾是退之。"]'),
('f9077db0-2ea0-40a2-8f2f-f8184ddba983','風雪二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','大塊號萬竅，强名之曰風。',24,'全唐诗/poet.song.202000.json','["大塊號萬竅，强名之曰風。", "楚人無意義，亂說有雌雄。"]'),
('b8879897-c7ca-4544-a3fe-87f0ff6ffc3e','風雪二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','持帚通樵徑，搘筇過蘚橋。',24,'全唐诗/poet.song.202000.json','["持帚通樵徑，搘筇過蘚橋。", "不知及門者，若箇肯埋腰。"]'),
('cd3013f3-b43a-4a78-83ee-77d7eb26807a','放言五首  其一','劉克莊','宋','宋诗','song-poetry','','[]','丹劑乾鉛汞，紅塵掃粃糠。',24,'全唐诗/poet.song.202000.json','["丹劑乾鉛汞，紅塵掃粃糠。", "只消一隻鶴，安用萬頭羊。"]'),
('2b33cc9d-7640-4fa1-a128-bf983fd69eea','放言五首  其二','劉克莊','宋','宋诗','song-poetry','','[]','戀闕子牟遠，還鄉賀監狂。',24,'全唐诗/poet.song.202000.json','["戀闕子牟遠，還鄉賀監狂。", "老人忘節序，有菊即重陽。"]'),
('4d263e3f-6f71-4224-9e71-4d711d043124','放言五首  其三','劉克莊','宋','宋诗','song-poetry','','[]','鏡悲鸞獨舞，射感雉雙飛。',24,'全唐诗/poet.song.202000.json','["鏡悲鸞獨舞，射感雉雙飛。", "早認色空是，晚知婚宦非。"]'),
('6a38f464-ebfc-4397-ac03-f92243635f1e','放言五首  其四','劉克莊','宋','宋诗','song-poetry','','[]','萬里先行脚，三家晚閉關。',24,'全唐诗/poet.song.202000.json','["萬里先行脚，三家晚閉關。", "曾求詩入海，亦作史藏山。"]'),
('8f17393e-6d3e-46a8-9e24-01cf2ae63cef','放言五首  其五','劉克莊','宋','宋诗','song-poetry','','[]','有酒聊排悶，無書可訂頑。',24,'全唐诗/poet.song.202000.json','["有酒聊排悶，無書可訂頑。", "君看鸞鎩羽，不若早知還。"]'),
('68576781-2dc4-42c4-9040-42c287be9fc3','贈日者陳達夫六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','昔有君平季主，今無韓慥林開。',28,'全唐诗/poet.song.202000.json','["昔有君平季主，今無韓慥林開。", "終日垂帷閉肆，或時戴笠盤街。"]'),
('df5cb666-de16-4277-9b28-e16bb1f4493b','贈日者陳達夫六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','樗翁書題閑慢，萬言不直豪芒。',28,'全唐诗/poet.song.202000.json','["樗翁書題閑慢，萬言不直豪芒。", "奪了巡官行貨，攙他太卜牙郎。"]'),
('c3210137-5c80-489f-af8f-7a45466fb862','記將李事','劉克莊','宋','宋诗','song-poetry','','[]','藐予小子衰殘迫，惜我先人老壽稀。',64,'全唐诗/poet.song.202000.json','["藐予小子衰殘迫，惜我先人老壽稀。", "厚幣能牽四皓出，畫圖幸送二疎歸。", "子玄亙古芬芳史，伯始終身糞上譏。", "頴叔資深俱已矣，豈無來者判聃非。"]'),
('4aa6ccd3-7039-4955-ad17-129b081c0d47','贈庸齋','劉克莊','宋','宋诗','song-poetry','','[]','挾策端平偶見遺，不旋踵已遇嘉熙。',64,'全唐诗/poet.song.202000.json','["挾策端平偶見遺，不旋踵已遇嘉熙。", "雖聞栖楚叩墀語，不見陽城伏閤時。", "下殿君能和富范，上房吾願讓夷夔。", "或疑廉藺曾相避，知兩翁心更有誰。"]'),
('a5d4218e-32b5-409b-b9e9-d99575efb1b6','縱茟一首','劉克莊','宋','宋诗','song-poetry','','[]','不與人爭鹿，常留客膾鯨。',48,'全唐诗/poet.song.202000.json','["不與人爭鹿，常留客膾鯨。", "遍參埋雪立，輕舉御風行。", "鳴止三千歲，游觀數十城。", "前篇方出喙，又報後篇成。"]'),
('96fe8f1d-375a-46d0-966c-5eeda5037709','病起五首  其一','劉克莊','宋','宋诗','song-poetry','','[]','躬圭寶箑俱藏起，出入惟消笠與簑。',64,'全唐诗/poet.song.202000.json','["躬圭寶箑俱藏起，出入惟消笠與簑。", "農說雨暘差有準，客談間諜易傳訛。", "豐年海熟田尤熟，聖代朝和野亦和。", "縱使大寒并大暑，小車時出至行窩。"]'),
('555b4388-c631-460c-91c4-cb119a31f092','病起五首  其二','劉克莊','宋','宋诗','song-poetry','','[]','鬻文賣賦今能幾，窮薄常因病折磨。',64,'全唐诗/poet.song.202000.json','["鬻文賣賦今能幾，窮薄常因病折磨。", "寧作地仙事思邈，不教天女惱維摩。", "乞骸幸已逃空谷，養氣難於塞决河。", "豈是先生老而健，修方多更閲醫多。"]'),
('1639eb16-e532-4ee1-b68b-c972d85c7530','病起五首  其三','劉克莊','宋','宋诗','song-poetry','','[]','小窗不復聽吾伊，時有蛩聲出吻悲。',64,'全唐诗/poet.song.202000.json','["小窗不復聽吾伊，時有蛩聲出吻悲。", "曲宴無歌賡太液，中痟止酒飲華池。", "誰將曉雪堆新鬢，自撥寒灰鍛近詩。", "未敢熱瞞同社友，草鞋尚欲遠尋師。"]'),
('f0538b5f-9d90-4349-a7fb-d18d3bb2f9f9','病起五首  其四','劉克莊','宋','宋诗','song-poetry','','[]','百歲將闌猛省驚，六根不足可憐生。',64,'全唐诗/poet.song.202000.json','["百歲將闌猛省驚，六根不足可憐生。", "古人使祝爲祈死，叔世無人弔失明。", "昔捱殘更羞渴睡，今當清晝要扶行。", "時於夢裏瞻星斗，愁絕鄰鷄腷膊聲。"]'),
('16b72618-a714-43b9-bc29-9f75fe82411d','病起五首  其五','劉克莊','宋','宋诗','song-poetry','','[]','越境迎醫伎又窮，殘骸奉施與天公。',64,'全唐诗/poet.song.202000.json','["越境迎醫伎又窮，殘骸奉施與天公。", "外庭幸際清明始，內障如囚黑暗中。", "貝葉今難開隻眼，薰絃昔忝和重瞳。", "暮年膝上惟文度，常挈書燈伴乃翁。"]'),
('fb882fff-edc9-4062-869a-a4e4101bd5f8','次韻君節祕書三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','甫登鼇頂浩然歸，豈是區區較粟薇。',64,'全唐诗/poet.song.202000.json','["甫登鼇頂浩然歸，豈是區區較粟薇。", "縱使吠聲雜堯桀，可無直筆辨聃非。", "雷音首占第一義，黛色終當四十圍。", "想見朝陽鳴未已，在岐山下莫高飛。"]'),
('20ebac1f-51cc-4219-b3f8-3742ac35adc0','次韻君節祕書三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','又從天祿閤中歸，厭太官羊憶苦薇。',64,'全唐诗/poet.song.202000.json','["又從天祿閤中歸，厭太官羊憶苦薇。", "伋瑗昌言憂國事，永欽沽直暴君非。", "貴人高爵懸金印，狎客閑情減带圍。", "獨有冥鴻惜毛羽，刺天未肯羨羣飛。"]'),
('4fd249e2-f74e-43a5-ac85-2e71f7829e91','次韻君節祕書三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','寧作青袍朝士歸，烹羔未必勝羹薇。',64,'全唐诗/poet.song.202000.json','["寧作青袍朝士歸，烹羔未必勝羹薇。", "易貪塵世好官職，難泯人心真是非。", "戰士未收青野骨，將軍誰報白登圍。", "可憐鳩鷃藩籬下，豈識垂天翼怒飛。"]'),
('e13aa785-86a6-4f12-a286-f9d8758fa707','醉筆一首','劉克莊','宋','宋诗','song-poetry','','[]','滿插花黄沃巨杯，一絲不遣掛襟懷。',64,'全唐诗/poet.song.202000.json','["滿插花黄沃巨杯，一絲不遣掛襟懷。", "若非供奉仙重謫，必是玄真子再來。", "有妓分甘徒自臭，無奴負鍤也須埋。", "平生不喜名浮實，佳傳何消上曲臺。"]'),
('6f106008-f62d-40e6-9d84-cb87ff4e5f41','次韻林太淵二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','齒宿何妨意尚新，向來誤認假爲真。',64,'全唐诗/poet.song.202000.json','["齒宿何妨意尚新，向來誤認假爲真。", "漏名左相門首客，占籍愚公谷裏人。", "上知豈無千慮失，下官惟有兩眉顰。", "史臣傳與頌臺謚，未抵盃中物切身。"]'),
('ce4e273a-a4c7-4cdc-ac32-ef3b32a23e5f','次韻林太淵二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','時賢多以刻爲明，撫字催科鮮並行。',64,'全唐诗/poet.song.202000.json','["時賢多以刻爲明，撫字催科鮮並行。", "聞舊吏民皆向化，喜新令尹不求贏。", "察簾外事非中道，立路傍碑亦近名。", "莫比尋常貴公子，長官清若一書生。"]'),
('5a2f4f46-ef80-4db3-91cd-31eb97546df1','送胡石璧帥廣西二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','制難由來在一賢，青冥鈇鉞授中權。',64,'全唐诗/poet.song.202000.json','["制難由來在一賢，青冥鈇鉞授中權。", "漢家固已收羣策，胡運何曾有百年。", "不待焦頭蒙上賞，莫云斡腹是虛傳。", "提封五筦包鯨浸，黎母山猶在次邊。"]'),
('394fd695-d72d-4027-a3cc-46055e1ee081','送胡石璧帥廣西二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','此段君王付託誰，明公身可荷安危。',64,'全唐诗/poet.song.202000.json','["此段君王付託誰，明公身可荷安危。", "常游簪带春携客，忽奪崑崙夜出奇。", "忠定罷兵纔建紹，襄公討叛止邕宜。", "腐儒雖憊如同載，堪稿平蠻第二碑。"]'),
('d8ae63bb-0644-493e-9a58-92283ed03076','迎候林德輔帥參一首','劉克莊','宋','宋诗','song-poetry','','[]','西埜約余同薦禰，六丁力盡不能留。',64,'全唐诗/poet.song.202000.json','["西埜約余同薦禰，六丁力盡不能留。", "霜蹄屢蹶追風驃，皓首還登載月舟。", "伊昔士元曾別駕，即今子美尚參謀。", "浮榮膜外何須較，且可歸來秉燭游。"]'),
('0ca5fef6-2429-4df0-bf51-e2acfedc7da7','感昔','劉克莊','宋','宋诗','song-poetry','','[]','曾見弘文館盛開，難將汗脚涴金臺。',64,'全唐诗/poet.song.202000.json','["曾見弘文館盛開，難將汗脚涴金臺。", "搜山不見之推出，入海難呼太白來。", "士各自媒誰待聘，世皆欲殺少憐才。", "空存先帝昭回筆，永閟巾箱不忍開。"]'),
('7c21abde-3afc-45bd-b0a6-b7b6073ab738','題法帖','劉克莊','宋','宋诗','song-poetry','','[]','二王萬古擅書名，聞說臨池學始成。',32,'全唐诗/poet.song.202000.json','["二王萬古擅書名，聞說臨池學始成。", "瘞鶴字猶看不見，黄庭小楷付來生。"]'),
('f42a713f-2c67-46e2-be18-c71ab9e171f2','答學者','劉克莊','宋','宋诗','song-poetry','','[]','自古名家豈偶然，雖游於藝必精專。',64,'全唐诗/poet.song.202000.json','["自古名家豈偶然，雖游於藝必精專。", "經生各守單傳舊，國弈常爭一著先。", "馬老于行知嚮導，鵠騰而上睹方圓。", "殷勤寄語同袍者，努力磨教鐵硯穿。"]'),
('4974e2e3-93dc-4c5e-8447-131e67200e6f','南唐一首','劉克莊','宋','宋诗','song-poetry','','[]','建隆事得之遺老，疇昔曾參野史看。',64,'全唐诗/poet.song.202000.json','["建隆事得之遺老，疇昔曾參野史看。", "後閣夜猶歌玉樹，陳橋日已湧金盤。", "可憐李主歸朝晚，專靠江神立國難。", "誰道齊兵當十萬，一身杌隉不能安。"]'),
('835abc1c-fb9e-4c40-ad26-d2a69c117995','古意','劉克莊','宋','宋诗','song-poetry','','[]','吾夫子喜稱遺逸，太史公亦傳滑稽。',64,'全唐诗/poet.song.202000.json','["吾夫子喜稱遺逸，太史公亦傳滑稽。", "堯帝杯曾遜巢許，武王粟不飽夷齊。", "拾來穗即萬鍾祿，採下薇堪百甕虀。", "不是狂言大無當，聞之齧缺與王倪。"]'),
('8fe46473-d9d2-4c8b-9a61-58bd2cc19415','題畫六言一首','劉克莊','宋','宋诗','song-poetry','','[]','子猷無乘興舟，越石有長嘯樓。',28,'全唐诗/poet.song.202000.json','["子猷無乘興舟，越石有長嘯樓。", "雪滅千山蹤跡，月照幾家樂愁。"]'),
('5a9aa5df-30ed-4970-9ae2-687334b6c109','理故書二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','軸猶插高架，檠已棄低牆。',48,'全唐诗/poet.song.202000.json','["軸猶插高架，檠已棄低牆。", "可惜亡三篋，安能讀一箱。", "自慙伯仁退，不及阿宜長。", "但憶初强記，誰知晚健忘。"]'),
('fcdd6e2b-f6da-46b2-a7aa-9b2447978a3a','理故書二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','難窺一字脚，空皺兩眉頭。',48,'全唐诗/poet.song.202000.json','["難窺一字脚，空皺兩眉頭。", "孤露無三樂，凄凉有四愁。", "詩疵撚鬚改，丹走出神求。", "元不離禪榻，當年遍九州。"]'),
('30fff237-78c0-4058-91d4-3b175ecbcf5d','用韻題卓刑部樂山樓','劉克莊','宋','宋诗','song-poetry','','[]','城裏惟樓盡見山，使君小築可三間。',64,'全唐诗/poet.song.202000.json','["城裏惟樓盡見山，使君小築可三間。", "弓旌招莫返長往，爐竈壞方求大還。", "及菊未荒歸栗里，有芝堪茹老商顔。", "鶴書曾賺幽人出，只恐先生又予環。"]'),
('d645c890-6aea-49fc-9895-4f6c1526ae21','銘座六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','象防弔露埋齒，麝以香聞割臍。',28,'全唐诗/poet.song.202000.json','["象防弔露埋齒，麝以香聞割臍。", "羣兒爭放紙鷂，老子寧爲木雞。"]'),
('d16693e8-08b4-433e-ad75-55767baf3971','銘座六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','數步覺蕭娘臭，三日聞荀令香。',28,'全唐诗/poet.song.202000.json','["數步覺蕭娘臭，三日聞荀令香。", "涑水公銘衾戒，乖崖老按劍防。"]'),
('244df877-4e9f-4287-82b7-0786d9891bfa','耳鼻六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','萬法與身俱幻，百骸惟耳尚聰。',28,'全唐诗/poet.song.202000.json','["萬法與身俱幻，百骸惟耳尚聰。", "文公爲補琴操，回仙邀聽松風。"]'),
('29bcb4f6-7b7d-4bdd-91d2-751907c299f8','耳鼻六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','一饑慣食腥腐，三嗅不分臭香。',28,'全唐诗/poet.song.202000.json','["一饑慣食腥腐，三嗅不分臭香。", "殘質心灰已久，末年鼻壅何傷。"]'),
('37e27b0b-0d83-4862-b40c-cabf642086ed','蝶庵一首','劉克莊','宋','宋诗','song-poetry','','[]','萬里求師脚力頑，可憐無藥駐童顔。',64,'全唐诗/poet.song.202000.json','["萬里求師脚力頑，可憐無藥駐童顔。", "遊梁曾在鄒枚右，反魯安能季孟間。", "但見堆金守郿塢，未聞全璧出函關。", "堯如天大逃焉往，莫費巢由自買山。"]'),
('3e4565f9-ec3b-4e21-9685-69dd0b262d86','即事六言四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','宦情爲虎爲鼠，世態如雲如輪。',28,'全唐诗/poet.song.202000.json','["宦情爲虎爲鼠，世態如雲如輪。", "武夫駕盲宰相，醉尉呵飛將軍。"]'),
('ce7be805-2753-4064-8200-b47b8683b8d1','即事六言四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','有時眼花落井，有時鼻孔撩天。',28,'全唐诗/poet.song.202000.json','["有時眼花落井，有時鼻孔撩天。", "工詩只是少黠，說禪莫是大顛。"]'),
('2df908ea-a54e-4d3c-b8d5-d116cbd43634','即事六言四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','骨已朽黄泉下，傳猶列青史中。',28,'全唐诗/poet.song.202000.json','["骨已朽黄泉下，傳猶列青史中。", "猛朴時來宰相，關張運去英雄。"]'),
('53cdd0e2-3cab-4bf8-abe2-81cbe953dd9c','即事六言四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','早詠白駒在谷，晚駕青牛出關。',28,'全唐诗/poet.song.202000.json','["早詠白駒在谷，晚駕青牛出關。", "寧爲魚點墨退，猶勝鶴带箭還。"]'),
('cf4b7097-36b3-47cb-80af-bc7ed38678f2','古意二十韻','劉克莊','宋','宋诗','song-poetry','','[]','自從混沌死，萬象困穿鑿。',240,'全唐诗/poet.song.202000.json','["自從混沌死，萬象困穿鑿。", "淳風誰挽還，古意日漓薄。", "余幼膽輪囷，泛濫通流略。", "短篇堪掣鯨，片文可驅鰐。", "吾嘗觀竅妙，渠敢譏雜駁。", "北未陟崧岱，南僅覽衡霍。", "菊坡評三雋，竹隠表一鶚。", "雖爲世流傳，未經聖刪削。", "晚歲歷九州，導從惟一鶴。", "飄然乘剛風，騰而上寥廓。", "金色大千界，水渦幾萬落。", "荒哉漢陵闕，蕞爾遼城郭。", "遂窺子宗廟，盡見佛樓閣。", "叫開閶闔雲，耳聞鈞天樂。", "吾持此安歸，喜極還驚愕。", "恍疑緣崖墜，又恐行路錯。", "詩魔暫辭去，來如隔日瘧。", "易展垂天翼，難踏實地脚。", "萬病皆有方，惟狂不可藥。", "拙吟示兒曹，聊記武公謔。"]'),
('c772b94c-5d1b-40f1-8ccf-8cd5bc6672d4','送王南海二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','昔作翹材客，曾談執友賢。',48,'全唐诗/poet.song.202000.json','["昔作翹材客，曾談執友賢。", "雖無金屋貯，頼有歸巢遷。", "此老飛仙去，斯文付嫡傳。", "病翁猶未聵，要聽武城絃。"]'),
('24fc90ac-a6dc-46f1-8ae0-b72f903bed10','送王南海二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','史氏循良傳，儒家果藝科。',48,'全唐诗/poet.song.202000.json','["史氏循良傳，儒家果藝科。", "土荒耕老少，海近販人多。", "古有寧馨語，今無于蒍歌。", "縣知新令尹，琴調得民和。"]'),
('14ab5a81-7764-41aa-9ae7-ed6d7df93d74','挽陳司直二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','五朝際遇諸家少，四葉封崇一品榮。',64,'全唐诗/poet.song.202000.json','["五朝際遇諸家少，四葉封崇一品榮。", "不似鶑花貴公子，宛然螢雪老書生。", "交游綠野舊賓客，濡染滄洲賢父兄。", "吾老埋辭失之約，餘哀翻入薤歌聲。"]'),
('e1e8b870-ebcb-4d1a-acc7-5458b2fee31c','挽陳司直二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','隆乾事契姑休論，歲晚相看成兩翁。',64,'全唐诗/poet.song.202000.json','["隆乾事契姑休論，歲晚相看成兩翁。", "吾女偶霑郊霈下，君兒亦脫縣灘中。", "清伊高會耆英少，碧瀨新丘伉儷同。", "我有蔡邕書欲付，未知何日兆非熊。"]'),
('0d46a720-9e28-45ee-a303-df23c7d081f6','挽葛夫人二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','銀臺曾奮塗歸筆，我亦留花批逆鱗。',64,'全唐诗/poet.song.202000.json','["銀臺曾奮塗歸筆，我亦留花批逆鱗。", "早共裂麻沮裴相，晚甘負耒作滕民。", "兒斑衣從雙旌貴，母繡簾迎萬戶春。", "方擁皇華荒大國，誤他多少借留人。"]'),
('bcdc144c-ac45-4aa7-91f8-6da8ab3bd38b','挽葛夫人二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','不惟婆嫂咸嗟惜，學語兒知此母賢。',64,'全唐诗/poet.song.202000.json','["不惟婆嫂咸嗟惜，學語兒知此母賢。", "味薄居常喜蔬食，心慈勸勿用蒲鞭。", "若非騰上天宮裏，必是迎歸海岸邊。", "九十老農來祖奠，眼枯不覺亦潸然。"]'),
('272b0767-3b07-45ec-ba39-9ee29391041b','謝景行方寺丞惠衣二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','贛州牧念予絕潔，見遺上衣并下裳。',64,'全唐诗/poet.song.202000.json','["贛州牧念予絕潔，見遺上衣并下裳。", "澤畔羊裘未韜晦，雪中鶴氅太清狂。", "笑金谷友望塵繆，經紫陽翁考古詳。", "更惠雞栖車一乘，十分結裹老文昌。"]'),
('6601b689-1b21-420f-8532-ba20720230c2','謝景行方寺丞惠衣二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','初裁隠服師楊陸，忽贈身章別一般。',64,'全唐诗/poet.song.202000.json','["初裁隠服師楊陸，忽贈身章別一般。", "似雪精絺爲表襮，比花文錦作中單。", "何妨俗笑浩然聳，不要人憐范叔寒。", "孰若子衣安且吉，絕勝劍履進賢冠。"]'),
('550114c5-850a-43f9-96f0-b905af4a31f3','抄戊辰十月近稿七首  其一','劉克莊','宋','宋诗','song-poetry','','[]','後學鮮能舍瑟作，古人未免假韶鳴。',64,'全唐诗/poet.song.202000.json','["後學鮮能舍瑟作，古人未免假韶鳴。", "不勞左轄誦新句，却愛老婆呼舊名。", "史館誰徵段公事，讎家妄作武侯評。", "人間安得忘憂物，爲窶儒生澆不平。"]'),
('9f9b0f01-8053-473e-aa2a-6ee5f8c4d354','抄戊辰十月近稿七首  其二','劉克莊','宋','宋诗','song-poetry','','[]','識之無字憶髫年，霍地紅顔變雪顛。',64,'全唐诗/poet.song.202000.json','["識之無字憶髫年，霍地紅顔變雪顛。", "求狗監人難復得，如雞林相豈非賢。", "鯉庭聞處才三百，蚓竅吟來忽五千。", "寄語毛韓并衛卜，不煩序亦不煩箋。"]'),
('6f8bbcb5-a4ae-4d5a-ae4d-f1322788a155','抄戊辰十月近稿七首  其三','劉克莊','宋','宋诗','song-poetry','','[]','頂雪無多爬欲禿，眼花亂發捏來空。',64,'全唐诗/poet.song.202000.json','["頂雪無多爬欲禿，眼花亂發捏來空。", "何如自號四休叟，不要人扶獨樂翁。", "純白固知難諱老，大丹未必可還童。", "不知後世評碑板，似李邕耶似蔡邕。"]'),
('7ded8d29-4f7f-401a-b1ae-9dee16f28296','抄戊辰十月近稿七首  其四','劉克莊','宋','宋诗','song-poetry','','[]','主公已換老龍名，部曲無知覬寵靈。',64,'全唐诗/poet.song.202000.json','["主公已換老龍名，部曲無知覬寵靈。", "執爨婢權呼小玉，拾樵童暫叚奴星。", "旋推鄰叟稱尊宿，兼命雛孫曰寧馨。", "稚子不知儂爛醉，剛來耳畔喚教醒。"]'),
('0d9f9f55-3d38-4be4-8ad9-7461c0217a13','抄戊辰十月近稿七首  其五','劉克莊','宋','宋诗','song-poetry','','[]','戶外跫然聞足音，或懷漫刺袖新吟。',64,'全唐诗/poet.song.202000.json','["戶外跫然聞足音，或懷漫刺袖新吟。", "樽空愧不能觴客，綆短如何敢汲深。", "薄俗求疵誰揜惡，先賢慮患或陽瘖。", "國人豈待儂箴儆，持在螢窗且自箴。"]'),
('86312e15-a614-4cac-ac40-67a760903160','抄戊辰十月近稿七首  其六','劉克莊','宋','宋诗','song-poetry','','[]','少狂費盡一生心，叢稿如山雪滿簪。',64,'全唐诗/poet.song.202000.json','["少狂費盡一生心，叢稿如山雪滿簪。", "楊子雕鎸誇賦麗，唐人鍛鍊說詩深。", "寒來尚可披裘釣，窮殺何妨带索吟。", "社友蕭疎吾老大，安知來者不如今。"]'),
('dfae70ca-ce06-4984-b120-77f1894d6d54','抄戊辰十月近稿七首  其七','劉克莊','宋','宋诗','song-poetry','','[]','疇昔榮途分寸躋，危機不合上雲梯。',64,'全唐诗/poet.song.202000.json','["疇昔榮途分寸躋，危機不合上雲梯。", "鳳皇池有人爭奪，鸚鵡洲無客敢題。", "早不修真壞丹竈，晚方受籙脫金閨。", "羽毛只可如鴉雀，誰遣君爲吐綬鷄。"]'),
('08b5a637-1605-4690-954f-c20f0cb15b39','又五言一首','劉克莊','宋','宋诗','song-poetry','','[]','甫白不可作，千年有廢壇。',48,'全唐诗/poet.song.202000.json','["甫白不可作，千年有廢壇。", "虛逢右文主，難獻采詩官。", "與子擘麟脯，從渠切蟣肝。", "後生多美秀，未可便麤瞞。"]'),
('254d8f2d-c3cf-42a5-bec8-99eccab0572a','絕句二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','枝上好花無十日，松梢老葉有千年。',32,'全唐诗/poet.song.202000.json','["枝上好花無十日，松梢老葉有千年。", "靜中勘破人間世，醒者常愚醉者賢。"]'),
('62a451e8-0988-4b2f-9352-31294bc75eda','絕句二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','浮榮已是卿慙長，勇退猶稱相避賢。',32,'全唐诗/poet.song.202000.json','["浮榮已是卿慙長，勇退猶稱相避賢。", "先帝賜金揮未盡，不應全仰作碑錢。"]'),
('c8c24135-4ee5-42b0-bc4b-5de8db7a2cb7','六言三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','不識平康坊裏，多在村學堂中。',28,'全唐诗/poet.song.202000.json','["不識平康坊裏，多在村學堂中。", "安得金錢買笑，只堪夏楚訓蒙。"]'),
('684ad2c1-0c19-4bd2-abf8-1bf4a75bb82c','六言三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','不入城裏市裏，常在水邊月邊。',28,'全唐诗/poet.song.202000.json','["不入城裏市裏，常在水邊月邊。", "蜀公有疏謝事，米老無書辨顛。"]'),
('90af8327-7c14-4760-8b14-a794ae180097','六言三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','溪北酒旗裊裊，溪南社鼓鼕鼕。',28,'全唐诗/poet.song.202000.json','["溪北酒旗裊裊，溪南社鼓鼕鼕。", "寧問餔糟漁父，懶求賦芧狙公。"]'),
('ff5832d4-ff34-43b7-ad0c-3b004bb07c1a','壺山一首','劉克莊','宋','宋诗','song-poetry','','[]','俯瞰二州煙晻靄，遥瞻八面壁崔嵬。',32,'全唐诗/poet.song.202000.json','["俯瞰二州煙晻靄，遥瞻八面壁崔嵬。", "廼知仙聖門庭廣，也放長房跳入來。"]'),
('52be1fc3-40ac-4909-ae2d-d27f62373c43','相法一首','劉克莊','宋','宋诗','song-poetry','','[]','姑射仙風肌似雪，盧郎鬼質面如藍。',32,'全唐诗/poet.song.202000.json','["姑射仙風肌似雪，盧郎鬼質面如藍。", "不勞鑒裁分妍醜，但覽丰標辨聖凡。"]'),
('eefcc1aa-d3ba-44ed-9092-748ac35b0643','先識一首','劉克莊','宋','宋诗','song-poetry','','[]','新戒幾曾參古德，死人不信有神仙。',32,'全唐诗/poet.song.202000.json','["新戒幾曾參古德，死人不信有神仙。", "蚊虻縱使皆成佛，雞犬何修得上天。"]'),
('cea5fffe-2096-417d-8cc5-8e347b109c86','讀阮籍傳一首','劉克莊','宋','宋诗','song-poetry','','[]','言出勿令圭有玷，舌捫不及駟難追。',32,'全唐诗/poet.song.202000.json','["言出勿令圭有玷，舌捫不及駟難追。", "阮公托醉勸進表，龐老無名受禪碑。"]'),
('10272a3e-913b-4743-8bb1-d9936ac22c97','題韓柳廟碑一首','劉克莊','宋','宋诗','song-poetry','','[]','韓柳子孫皆物故，士民尸祝尚如新。',32,'全唐诗/poet.song.202000.json','["韓柳子孫皆物故，士民尸祝尚如新。", "吾行天下已頭白，三百年唐惟二人。"]'),
('7c5a2d3f-ab0f-44e1-987c-a1dec9c12351','挽林學錄五言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','節麾三世顯，螢雪一生貧。',48,'全唐诗/poet.song.202000.json','["節麾三世顯，螢雪一生貧。", "愈積家餘慶，咸稱里善人。", "幼常推李泌，老忽哭盧綸。", "聖惡無從涕，那堪是外親。"]'),
('8919609e-1e56-473b-8957-5d5107ad140b','挽林學錄五言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','昔報尊公訃，奔喪萬里程。',48,'全唐诗/poet.song.202000.json','["昔報尊公訃，奔喪萬里程。", "生居諸子下，身代二兄行。", "負骨嘆純孝，分財見不爭。", "九原面先舅，應問白頭甥。"]'),
('456bf203-cb53-4b67-9a3b-b9ed3aa2716b','送莊糾一首','劉克莊','宋','宋诗','song-poetry','','[]','忽枉高軒訪，殷勤不忍離。',48,'全唐诗/poet.song.202000.json','["忽枉高軒訪，殷勤不忍離。", "雖書督郵考，率在過庭時。", "辯素推三語，清尤畏四知。", "歸裝無長物，一首後村詩。"]'),
('6708f418-2b4f-48d1-817c-626dbfcbbae8','雜詠一首','劉克莊','宋','宋诗','song-poetry','','[]','晴是羲和喜，陰是嫦娥妬。',48,'全唐诗/poet.song.202000.json','["晴是羲和喜，陰是嫦娥妬。", "暖是青帝來，凉是赤熛去。", "災是旄頭出，祥是奎星聚。", "雷是阿香嗔，濤是靈胥怒。"]'),
('d234b85c-4b15-4124-bbe7-9c6977812ad3','字說一首','劉克莊','宋','宋诗','song-poetry','','[]','半山字說行，精義極貫穿。',24,'全唐诗/poet.song.202000.json','["半山字說行，精義極貫穿。", "世好鴉蚓書，誰識蟲魚篆。"]'),
('716e3097-ba2d-42c5-85db-2739b84a2602','目眚六言一首','劉克莊','宋','宋诗','song-poetry','','[]','暮年因耽黄卷，雙瞳不省盲如。',28,'全唐诗/poet.song.202000.json','["暮年因耽黄卷，雙瞳不省盲如。", "來生願爲蒼頡，四目造鳥跡書。"]'),
('ef4b5b39-ace4-44aa-b3e4-2c63e027e400','夢覺一首','劉克莊','宋','宋诗','song-poetry','','[]','拋書咍㘆聲裏，轉枕屈伸肘中。',28,'全唐诗/poet.song.202000.json','["拋書咍㘆聲裏，轉枕屈伸肘中。", "盧生相黄粱舍，沈郎壻翠微宮。"]'),
('e4127603-06a0-497b-bb33-b17a9cad53b1','匡人一首','劉克莊','宋','宋诗','song-poetry','','[]','匡人不識夫子，往往發其笥中。',28,'全唐诗/poet.song.202000.json','["匡人不識夫子，往往發其笥中。", "但有深衣古履，元無寶玉大弓。"]'),
('597b2376-ef4f-43cc-9e07-00b301f5f1ce','懷真趙二公一首','劉克莊','宋','宋诗','song-poetry','','[]','南塘清談亹亹，西山至言琅琅。',28,'全唐诗/poet.song.202000.json','["南塘清談亹亹，西山至言琅琅。", "七畧通羣書博，一生短千載長。"]'),
('f893cb3b-8675-425e-81b2-3a7b7975b64f','留侯一首','劉克莊','宋','宋诗','song-poetry','','[]','一槌復九世讎，編書封萬戶侯。',28,'全唐诗/poet.song.202000.json','["一槌復九世讎，編書封萬戶侯。", "指視紫芝翁出，身從赤松子遊。"]'),
('afd0843f-a8fb-4202-9fda-f1a3252a5b80','遊仙一首','劉克莊','宋','宋诗','song-poetry','','[]','懶爲隨駕處士，寧作閉門隠君。',28,'全唐诗/poet.song.202000.json','["懶爲隨駕處士，寧作閉門隠君。", "跨青牛導紫氣，乘黄鶴上白雲。"]'),
('bfffef73-c5f1-48f4-ad1f-788f899c3811','題趙昌花一首','劉克莊','宋','宋诗','song-poetry','','[]','趙叟生長太平，以著色花擅名。',28,'全唐诗/poet.song.202000.json','["趙叟生長太平，以著色花擅名。", "自古良工獨苦，于今墨畫盛行。"]'),
('a1af318c-9a39-48c6-a75b-edeab9b4eaf1','題桃源圖一首','劉克莊','宋','宋诗','song-poetry','','[]','但記嬴二世爾，豈知晉太康耶。',28,'全唐诗/poet.song.202000.json','["但記嬴二世爾，豈知晉太康耶。", "一境渾無租稅，四時長有桃花。"]'),
('0747c670-8a30-4a9d-8a79-990107a4b109','貴公子一首','劉克莊','宋','宋诗','song-poetry','','[]','春圃鶑花圍席，秋堂風露入簾。',28,'全唐诗/poet.song.202000.json','["春圃鶑花圍席，秋堂風露入簾。", "寧以肩承蹴踘，不將手觸牙籤。"]'),
('4e764ae5-a153-4352-8b9b-9b0eb95519cc','讀開元天寶遺事一首','劉克莊','宋','宋诗','song-poetry','','[]','環子受兵火涴，梅姬如玉雪清。',28,'全唐诗/poet.song.202000.json','["環子受兵火涴，梅姬如玉雪清。", "二妃未免遺恨，三郎可煞無情。"]'),
('52d1d2e2-b1bc-41d7-a5eb-3ed09a437fe1','醉醒一首','劉克莊','宋','宋诗','song-poetry','','[]','醉夢發於真性，醒狂或者矯情。',28,'全唐诗/poet.song.202000.json','["醉夢發於真性，醒狂或者矯情。", "左相飲如川吸，龍圖笑比河清。"]'),
('f53f750b-cb72-4676-9d2c-c18880cfc48f','讀韓信馬援傳一首','劉克莊','宋','宋诗','song-poetry','','[]','伏波自托真主，淮陰願爲假王。',28,'全唐诗/poet.song.202000.json','["伏波自托真主，淮陰願爲假王。", "病厭鳶飛鼓躁，晚悲鳥盡弓藏。"]'),
('b7ffc0ba-e871-465a-955b-e6b29f8a9b80','畫贊七言一首','劉克莊','宋','宋诗','song-poetry','','[]','馿加九錫石三品，鳥覩村翁晚節榮。',32,'全唐诗/poet.song.202000.json','["馿加九錫石三品，鳥覩村翁晚節榮。", "出有小車扶有杖，前身莫是邵先生。"]'),
('a78cd4d5-174b-4cf2-b1f0-a1d481c38fb2','又六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','韶顔譬槿花爾，枵腹僅椰子如。',28,'全唐诗/poet.song.202000.json','["韶顔譬槿花爾，枵腹僅椰子如。", "不知作千年調，誰教盛萬卷書。"]'),
('b711235e-a6a0-4311-85a3-eba8c269c880','又六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','有載書盟三友，無文章送五窮。',28,'全唐诗/poet.song.202000.json','["有載書盟三友，無文章送五窮。", "怯懦寧出胯下，清狂羞入褌中。"]'),
('00ee8a19-a4af-49a6-bfcb-7b94c7198b83','五言一首','劉克莊','宋','宋诗','song-poetry','','[]','馿多爲令僕，蟻亦拜侯王。',24,'全唐诗/poet.song.202000.json','["馿多爲令僕，蟻亦拜侯王。", "恰則封萬戶，俄然夢一場。"]'),
('bd3df6a0-c243-4b76-86b8-49f022949500','雜詠六言八首  其一','劉克莊','宋','宋诗','song-poetry','','[]','退之效玉川體，子美和舂陵行。',28,'全唐诗/poet.song.202000.json','["退之效玉川體，子美和舂陵行。", "古訓後生可畏，俗語文人相輕。"]'),
('a188f649-6733-4d5d-8933-f1bac4b86815','雜詠六言八首  其二','劉克莊','宋','宋诗','song-poetry','','[]','臺卿遺令畫贊，淵明祭文挽詩。',28,'全唐诗/poet.song.202000.json','["臺卿遺令畫贊，淵明祭文挽詩。", "乍可裸尸仰藥，勿求敕葬宣醫。"]'),
('07985656-57d5-45a2-99ab-f8bcdd400740','雜詠六言八首  其三','劉克莊','宋','宋诗','song-poetry','','[]','龍章鳳姿中散，麞頭鼠目十郎。',28,'全唐诗/poet.song.202000.json','["龍章鳳姿中散，麞頭鼠目十郎。", "一遺恨悲風操，一老死偃月堂。"]'),
('a06fbfc4-326f-4723-8fb8-99560d085005','雜詠六言八首  其四','劉克莊','宋','宋诗','song-poetry','','[]','大將軍無舊客，四公子成古墳。',28,'全唐诗/poet.song.202000.json','["大將軍無舊客，四公子成古墳。", "寄語魯仲連輩，買絲繡平原君。"]'),
('762ec3ca-5be9-4e66-9569-de8ac06ad470','雜詠六言八首  其五','劉克莊','宋','宋诗','song-poetry','','[]','上壽都來百歲，厚祿不過萬鍾。',28,'全唐诗/poet.song.202000.json','["上壽都來百歲，厚祿不過萬鍾。", "陋巷儒死廿九，灌園子辭三公。"]'),
('473050c2-d282-48f0-858f-837755432618','雜詠六言八首  其六','劉克莊','宋','宋诗','song-poetry','','[]','遊俠客無珠履，故人子有練裙。',28,'全唐诗/poet.song.202000.json','["遊俠客無珠履，故人子有練裙。", "小楷臨樂毅論，太息祭田橫文。"]'),
('40759cbb-b599-4630-9a5c-a4df03bde3ba','雜詠六言八首  其七','劉克莊','宋','宋诗','song-poetry','','[]','痛駡老奴尊己，錯認厠鬼爲妻。',28,'全唐诗/poet.song.202000.json','["痛駡老奴尊己，錯認厠鬼爲妻。", "先儒重鄭玄易，三孤喜李赤詩。"]'),
('44754745-0e7f-4091-b249-e36d6842ef8b','雜詠六言八首  其八','劉克莊','宋','宋诗','song-poetry','','[]','盧老數間破屋，張公九尺長身。',28,'全唐诗/poet.song.202000.json','["盧老數間破屋，張公九尺長身。", "容膝何妨嘯傲，打頭不敢欠伸。"]'),
('f673c083-b356-4f13-b18a-a02335151c91','雜詠五言五首  其一','劉克莊','宋','宋诗','song-poetry','','[]','傳呼尤赫赫，變滅忽休休。',24,'全唐诗/poet.song.202000.json','["傳呼尤赫赫，變滅忽休休。", "鴻筆銘勳績，蟬冠歛髑髏。"]'),
('18f4b178-5b2b-4d00-ba56-c7a9c7a85bee','雜詠五言五首  其二','劉克莊','宋','宋诗','song-poetry','','[]','奴視中人少，庭機左戚難。',24,'全唐诗/poet.song.202000.json','["奴視中人少，庭機左戚難。", "高爹嗔李白，新莽弔師丹。"]'),
('a6ad0d9c-b388-442b-8481-8ed55bdcdcab','雜詠五言五首  其三','劉克莊','宋','宋诗','song-poetry','','[]','親朋存者少，歲月去如馳。',24,'全唐诗/poet.song.202000.json','["親朋存者少，歲月去如馳。", "不記桃三竊，猶疑黍一炊。"]'),
('9462045d-588f-495c-9a56-4ac8ed7f4f31','雜詠五言五首  其四','劉克莊','宋','宋诗','song-poetry','','[]','乾鵲噪送喜，訓狐鳴主災。',24,'全唐诗/poet.song.202000.json','["乾鵲噪送喜，訓狐鳴主災。", "龍隨黄帝去，麟爲素王來。"]'),
('664bfe67-acb5-44a5-b5a8-ed587d686f8d','雜詠五言五首  其五','劉克莊','宋','宋诗','song-poetry','','[]','敝廬吾亦愛，陋巷人不堪。',24,'全唐诗/poet.song.202000.json','["敝廬吾亦愛，陋巷人不堪。", "癡兒蝸带屋，老子繭名庵。"]'),
('3b0c3af0-f3e3-42fb-9361-7d2916326a3b','雜詠七言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','夷齊甘受周家餓，申白曾遭漢法髠。',32,'全唐诗/poet.song.202000.json','["夷齊甘受周家餓，申白曾遭漢法髠。", "全活老臣殘齒髮，來生尚欲報君恩。"]'),
('7c04fdec-72bc-4ac9-b81a-60cbf039f2ab','雜詠七言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','清禁已無蓮炬分，名山尚欠草鞋緣。',32,'全唐诗/poet.song.202000.json','["清禁已無蓮炬分，名山尚欠草鞋緣。", "賀公未是真知己，却喚詩仙作謫仙。"]'),
('0fa9d8d3-2d7f-4b97-abd7-ced3cfbaa74d','跋潘岳悼亡一首','劉克莊','宋','宋诗','song-poetry','','[]','長恨齊眉人已往，可憐尊足者猶存。',32,'全唐诗/poet.song.202000.json','["長恨齊眉人已往，可憐尊足者猶存。", "乃知劍履圖麟閣，不似琴書隠鹿門。"]'),
('77351ceb-1c92-41e1-b999-ec5572bee812','題佛書六言一首','劉克莊','宋','宋诗','song-poetry','','[]','圓隨如一百八，大知識五十三。',28,'全唐诗/poet.song.202000.json','["圓隨如一百八，大知識五十三。", "旋學梵音朗誦，老無脚力遍參。"]'),
('cee94eb7-2d34-4d64-845b-e4130594425c','凡聖一首','劉克莊','宋','宋诗','song-poetry','','[]','死生非有二致，聖凡於此一般。',28,'全唐诗/poet.song.202000.json','["死生非有二致，聖凡於此一般。", "桓魋預爲石槨，王喬尚欲玉棺。"]'),
('565fbca4-14da-40a4-81ca-e35df85be8e5','梅開五言一首','劉克莊','宋','宋诗','song-poetry','','[]','陶翁書甲子，楚客紀庚寅。',24,'全唐诗/poet.song.202000.json','["陶翁書甲子，楚客紀庚寅。", "村叟無臺歷，梅開認小春。"]'),
('1f1c88f2-ddb6-43be-bac3-fcaddebbc409','記方尊師事一首','劉克莊','宋','宋诗','song-poetry','','[]','坱圠司元化，回環列衆真。',24,'全唐诗/poet.song.202000.json','["坱圠司元化，回環列衆真。", "有稱金闕令，無記玉樓人。"]'),
('9df2cfc0-e892-4183-a830-c4671d377b8f','居厚弟乞以礙止法官回授公朝特俞所請族子有詩志喜居厚次韻邀某同作效顰一首既拙且鈍錄獻家廟','劉克莊','宋','宋诗','song-poetry','','[]','回貤異渥未之聞，凜凜乾淳生氣存。',64,'全唐诗/poet.song.202000.json','["回貤異渥未之聞，凜凜乾淳生氣存。", "頻對青藜真濟美，雖埋玉樹尚追尊。", "奉新鸞誥陳幽壤，距小麟臺只近村。", "太息琰玄皆耄矣，誄成姑以寢爲園。"]'),
('581430a3-c165-4e61-bc5a-8cb51195a089','晚意','劉克莊','宋','宋诗','song-poetry','','[]','鷄報東方欲白時，林林羣動起飛馳。',64,'全唐诗/poet.song.202000.json','["鷄報東方欲白時，林林羣動起飛馳。", "匹居峴上入城少，頗怪淮南拔宅遲。", "驚餌何妨潜密藻，安巢謹勿托危枝。", "末年慕用寒山子，不是行家本色詩。"]'),
('1a0406ea-578e-4f42-ab3f-9aa6dd536c7d','道房六言一首','劉克莊','宋','宋诗','song-poetry','','[]','懶白衣作宰相，寧黄冠事老君。',28,'全唐诗/poet.song.202000.json','["懶白衣作宰相，寧黄冠事老君。", "試問讀三萬軸，何如誦五千文。"]'),
('0392e96f-9be8-4164-b07d-e472cbe92657','謝諸寓貴載酒  其一','劉克莊','宋','宋诗','song-poetry','','[]','樗翁九袠逢初度，洛社耆英共舉杯。',64,'全唐诗/poet.song.202000.json','["樗翁九袠逢初度，洛社耆英共舉杯。", "富相苦邀康節入，溫公亦喜小程來。", "每慚席上陪真率，誰道窩中愛打乖。", "不怕醉歸盧老攧，芙蓉月恰照人懷。"]'),
('0b95330e-744c-40a9-a1fd-920b715ecb7c','謝諸寓貴載酒  其二','劉克莊','宋','宋诗','song-poetry','','[]','洛中舊話誰拈出，幾載寥寥有此杯。',64,'全唐诗/poet.song.202000.json','["洛中舊話誰拈出，幾載寥寥有此杯。", "迂叟力辭年高晚，先賢羞與尹俱來。", "寧陪邵子稱安樂，免使歐公笑僻乖。", "况值霜天好風月，皺眉不若且舒懷。"]'),
('25f749b9-fbf9-4bfc-99b3-dfa02cc7bfd0','謝諸寓貴載酒  其三','劉克莊','宋','宋诗','song-poetry','','[]','景迫桑榆歡意少，相依藥椀與茶杯。',64,'全唐诗/poet.song.202000.json','["景迫桑榆歡意少，相依藥椀與茶杯。", "忽聞有客載醪過，誰道無人裹飯來。", "家在恍驚如鶴化，歲豐未可罪龍乖。", "閑吟不與君爭巧，自作村田樂散懷。"]'),
('05a768ae-2f12-4468-88cb-00dee0d3525d','老嘆一首','劉克莊','宋','宋诗','song-poetry','','[]','少豪扛鼎復搴旗，倏忽才情已竭衰。',64,'全唐诗/poet.song.202000.json','["少豪扛鼎復搴旗，倏忽才情已竭衰。", "今無百斤金買賦，古有九千縑作碑。", "毛錐盡禿難藏老，麈尾高懸合授誰。", "他日學人求肘後，不消挽些與哀詞。"]'),
('cfc50ebc-77df-4a55-a395-635c28cf0100','題達卿姪別墅','劉克莊','宋','宋诗','song-poetry','','[]','吾門不幸去華亡，頼有高才出鴈行。',64,'全唐诗/poet.song.202000.json','["吾門不幸去華亡，頼有高才出鴈行。", "自擬退之稱稍黠，孰云白也是陽狂。", "表阡鶴許儂歸老，飲硯虹爲汝發祥。", "它日雛鶑燎黄誥，分墦應許及聯牆。"]'),
('86b20310-b6ed-40dc-8b53-246b34e22ad1','示强甫','劉克莊','宋','宋诗','song-poetry','','[]','昔受浮丘伯密傳，駸駸轅固伏生年。',64,'全唐诗/poet.song.202000.json','["昔受浮丘伯密傳，駸駸轅固伏生年。", "試橫牧笛花間飲，勝著朝冠柏下眠。", "天上錦袍曾奪得，山中石硯又磨穿。", "生來羞舐淮南鼎，且戲塵寰作地仙。"]'),
('af65f738-8013-41bb-9108-1cf936fedd21','示沂孫','劉克莊','宋','宋诗','song-poetry','','[]','過去光陰電莫追，鏡中非復舊鬚眉。',64,'全唐诗/poet.song.202000.json','["過去光陰電莫追，鏡中非復舊鬚眉。", "已拚眸子難重朗，猶幸心官可苦思。", "太極旋闓無極義，極玄更有又玄詩。", "此篇若問何人作，向道山中老古錐。"]'),
('d4efbd79-60c3-436f-9047-98f2614926a8','師友六言一首','劉克莊','宋','宋诗','song-poetry','','[]','聞諸師者本同，取之友者亦公。',42,'全唐诗/poet.song.202000.json','["聞諸師者本同，取之友者亦公。", "高才有出象外，精義不離箇中。", "南渡大儒管見，西山先生正宗。"]'),
('cdfcfe7b-2880-496d-99d4-5753e5f69350','記箕山商野事一首','劉克莊','宋','宋诗','song-poetry','','[]','放勛禪飲牛父，軒皇問牧馬童。',28,'全唐诗/poet.song.202000.json','["放勛禪飲牛父，軒皇問牧馬童。", "曰夫子致南面，稱天師拜下風。"]'),
('438e0007-ff79-472f-9390-44a0bc73ef04','赤姪孫改名圭行冠禮一首','劉克莊','宋','宋诗','song-poetry','','[]','冠非責童子禮，兒必讀手澤書。',28,'全唐诗/poet.song.202000.json','["冠非責童子禮，兒必讀手澤書。", "簞瓢回也不改，宗廟赤爾何如。"]'),
('8caa9331-e730-4042-81d0-ef5316bcfeb6','霜菊','劉克莊','宋','宋诗','song-poetry','','[]','霜菊尤宜晚，纔開一兩葩。',24,'全唐诗/poet.song.202000.json','["霜菊尤宜晚，纔開一兩葩。", "不隨蒲柳變，索性待梅花。"]'),
('8550921d-fbe0-4279-99ca-7565fb3dc2a4','蘇柑','劉克莊','宋','宋诗','song-poetry','','[]','橘裏爭棋叟，壺中賣藥公。',24,'全唐诗/poet.song.202000.json','["橘裏爭棋叟，壺中賣藥公。", "蘇柑肥似瓠，盛不得樗翁。"]'),
('2edc6f31-20a5-4573-8c8a-7feaeb9161b2','小勞','劉克莊','宋','宋诗','song-poetry','','[]','性不耐閑懶，小勞方小佳。',24,'全唐诗/poet.song.202000.json','["性不耐閑懶，小勞方小佳。", "鋸沉成薄片，末麝入新芽。"]'),
('9cb9bcc5-72b2-48f1-8def-2422e7ee7c22','病起','劉克莊','宋','宋诗','song-poetry','','[]','不求玉杵杵，不要水銀銀。',24,'全唐诗/poet.song.202000.json','["不求玉杵杵，不要水銀銀。", "但祝未來世，長爲無病人。"]'),
('accaa6f0-9af8-4226-b5f3-8f0f16ec01ce','物化','劉克莊','宋','宋诗','song-poetry','','[]','今朝風物甚美，明日陰晴未知。',28,'全唐诗/poet.song.202000.json','["今朝風物甚美，明日陰晴未知。", "夕陽無回照理，落花有上天時。"]'),
('075c1bae-8ad0-4f05-aa3f-fe8e78af5cc0','蚋','劉克莊','宋','宋诗','song-poetry','','[]','蚓穿槁壤及黄泉，蜂採花房與柳綿。',32,'全唐诗/poet.song.202000.json','["蚓穿槁壤及黄泉，蜂採花房與柳綿。", "微蚋么麽殊嗜好，以醯爲蜜甕爲天。"]'),
('98619826-4758-48c0-93da-557e35c7f761','雀','劉克莊','宋','宋诗','song-poetry','','[]','恰見趨燕市，俄聞集兔園。',24,'全唐诗/poet.song.202000.json','["恰見趨燕市，俄聞集兔園。", "雕籠馴養者，誰到翟公門。"]'),
('98f3bbb8-5dbc-46df-8584-69d780d256eb','惜春','劉克莊','宋','宋诗','song-poetry','','[]','亂漂源裏紅雨，凈洗枝頭雪綿。',28,'全唐诗/poet.song.202000.json','["亂漂源裏紅雨，凈洗枝頭雪綿。", "只訝歡非前日，安知春是去年。"]'),
('5580a76b-e84e-43b6-bb5f-8b12077fed1a','予點','劉克莊','宋','宋诗','song-poetry','','[]','聲音笑貌可爲，顔色哭泣難揜。',28,'全唐诗/poet.song.202000.json','["聲音笑貌可爲，顔色哭泣難揜。", "聖人無私喜怒，見於誅予與點。"]'),
('d1f546aa-f262-4687-991f-a924d2f92a9d','客問宗旨一首','劉克莊','宋','宋诗','song-poetry','','[]','萬物泛觀皆我闥，諸君何事入吾褌。',32,'全唐诗/poet.song.202000.json','["萬物泛觀皆我闥，諸君何事入吾褌。", "不須苦問儂宗旨，醉裏聞之洛誦孫。"]'),
('53598f2e-76f4-4f19-b809-cfbe0e372b1d','咸淳龍飛大魁之歸卿大夫以某兄弟有一日之長俾主其事水村農卿謂某當爲詩爲壺山喚回百年英靈之氣客散詩成翌早錄呈且約同社屬和  其一','劉克莊','宋','宋诗','song-poetry','','[]','傾城迎侯錦歸忙，兒女鮮衣妓曉粧。',64,'全唐诗/poet.song.202000.json','["傾城迎侯錦歸忙，兒女鮮衣妓曉粧。", "龍首榜來春滿郡，鷄栖車已夕還鄉。", "團司局結慈恩寺，一炬燈傳舊弼坊。", "莫作尋常先輩看，淳熙相府甲科郎。"]'),
('a65868c8-7c4e-4fe1-843f-6146f2d1db0a','咸淳龍飛大魁之歸卿大夫以某兄弟有一日之長俾主其事水村農卿謂某當爲詩爲壺山喚回百年英靈之氣客散詩成翌早錄呈且約同社屬和  其二','劉克莊','宋','宋诗','song-poetry','','[]','射策人如射利忙，豈知世有古來粧。',64,'全唐诗/poet.song.202000.json','["射策人如射利忙，豈知世有古來粧。", "漢庭儒半壞科舉，天下士寧論國鄉。", "但詫高標廣寒殿，誰能更讀善和坊。", "觀君毛羽真鸞鳳，羞殺麤豪白面郎。"]'),
('52204673-3dff-49b1-b089-33472c9d5a4a','次江權軍宴新進士韻','劉克莊','宋','宋诗','song-poetry','','[]','病翁無計出愁城，喜甲科郎競拾青。',64,'全唐诗/poet.song.202000.json','["病翁無計出愁城，喜甲科郎競拾青。", "主禮尤隆真刺史，華宗相望兩魁星。", "董生至論惟三策，韋氏單傳只一經。", "舉首愛身如拱璧，修於家肯獻於廷。"]'),
('f4620fa8-9229-4dea-aaf8-b2ad6f0b1be9','聞喜宴李教君瑞不赴小詩贊美','劉克莊','宋','宋诗','song-poetry','','[]','膾人肝與採山薇，舉世營營爲飽饑。',64,'全唐诗/poet.song.202000.json','["膾人肝與採山薇，舉世營營爲飽饑。", "始信洋洋而逝矣，已烹鶂鶂復哇之。", "伏雌雉亦防身害，疇昔羊能兆禍基。", "獨有廣文君卓識，殘盃冷炙也牢辭。"]'),
('0628fe76-87fb-4774-b4a9-bc7235a53cc1','始冰','劉克莊','宋','宋诗','song-poetry','','[]','始猶飄灑忽嚴凝，村獠初看盡失驚。',32,'全唐诗/poet.song.202000.json','["始猶飄灑忽嚴凝，村獠初看盡失驚。", "包裹入城問蓍舊，一名木稼一名冰。"]'),
('d6de8fe2-d193-482f-82e8-ad0b078835f5','有客','劉克莊','宋','宋诗','song-poetry','','[]','幾載庭空雀可羅，朝來忽有客相過。',32,'全唐诗/poet.song.202000.json','["幾載庭空雀可羅，朝來忽有客相過。", "似知老子條冰進，不道先生鬢雪多。"]'),
('a5d983bf-de95-452e-a1cd-2c51d188c132','柬春谷工部','劉克莊','宋','宋诗','song-poetry','','[]','假使富埒國，何如貧在家。',24,'全唐诗/poet.song.202000.json','["假使富埒國，何如貧在家。", "尚存儂漢札，寧奪我齊瓜。"]'),
('beed3f46-939a-44ee-b635-587617a30182','七竅鑿','劉克莊','宋','宋诗','song-poetry','','[]','自從七竅鑿，無復六根全。',24,'全唐诗/poet.song.202000.json','["自從七竅鑿，無復六根全。", "鯨死彗星出，蟇枯月魄圓。"]'),
('f21ac70a-739c-4761-a5aa-9a85721a81ef','遷客黨碑','劉克莊','宋','宋诗','song-poetry','','[]','人無公議論，天有真是非。',24,'全唐诗/poet.song.202000.json','["人無公議論，天有真是非。", "佛肯護遷客，雷能碎黨碑。"]'),
('7443df1d-6d0a-4623-944e-9cf40f6c8504','奎宿奏事','劉克莊','宋','宋诗','song-poetry','','[]','過客危於惠，移儋遠似瓊。',24,'全唐诗/poet.song.202000.json','["過客危於惠，移儋遠似瓊。", "末年蘂珠殿，奏事獨奎星。"]'),
('3bf54554-0d9d-44cd-9da1-f29f9e3ba201','飲者','劉克莊','宋','宋诗','song-poetry','','[]','大醉害心風，小醉卧咽嘔。',24,'全唐诗/poet.song.202000.json','["大醉害心風，小醉卧咽嘔。", "世有大先生，一飲石五斗。"]'),
('985ef74a-ac08-4b50-837f-e1aa147a14ad','怕愛','劉克莊','宋','宋诗','song-poetry','','[]','月中玉女雖嚴冷，雪裏瑶姬轉麗華。',32,'全唐诗/poet.song.202000.json','["月中玉女雖嚴冷，雪裏瑶姬轉麗華。", "不管達官怕木稼，且留處士愛梅花。"]'),
('098c499e-9f15-4483-85a5-f63847f0abf6','餘寒','劉克莊','宋','宋诗','song-poetry','','[]','老子今年八十三，怕寒渾未試春衫。',32,'全唐诗/poet.song.202000.json','["老子今年八十三，怕寒渾未試春衫。", "尚存晉宋間人意，折得南枝带雪簪。"]'),
('4aa95aa2-39cb-496f-a85d-d324adf306cc','趙昌花','劉克莊','宋','宋诗','song-poetry','','[]','要識洛陽姚魏面，趙昌著色亦名家。',32,'全唐诗/poet.song.202000.json','["要識洛陽姚魏面，趙昌著色亦名家。", "可憐俗眼無真賞，不寶丹青寶墨花。"]'),
('231b6b76-f4af-47a6-ab3a-e19344845c3d','天奪','劉克莊','宋','宋诗','song-poetry','','[]','曩造河沙業，今災夢幻身。',24,'全唐诗/poet.song.202000.json','["曩造河沙業，今災夢幻身。", "不知岩下電，天奪與何人。"]'),
('c5e8252c-c6c4-4eb9-80ff-76c69a858741','逃禪便面','劉克莊','宋','宋诗','song-poetry','','[]','姑射吸風仍飲露，洛妃習禮更明詩。',32,'全唐诗/poet.song.202000.json','["姑射吸風仍飲露，洛妃習禮更明詩。", "梅花渾不施朱粉，直以天香與雪肌。"]'),
('370f31d1-7569-4017-89c7-f3b227e3882a','聞東軒訃  其一','劉克莊','宋','宋诗','song-poetry','','[]','君給相如札，吾方長道山。',24,'全唐诗/poet.song.202000.json','["君給相如札，吾方長道山。", "燕猶棲舊壘，駒已養天閑。"]'),
('b44202a6-5429-4d2b-add8-c387cb8b0d71','聞東軒訃  其二','劉克莊','宋','宋诗','song-poetry','','[]','位逼將求說，書來欲鑄顔。',24,'全唐诗/poet.song.202000.json','["位逼將求說，書來欲鑄顔。", "柰何化鶴去，不見珥貂還。"]'),
('afb338ab-6605-46cf-ba41-47de98b45c05','惜舟','劉克莊','宋','宋诗','song-poetry','','[]','生世誰令抱百憂，點黄不肯上眉頭。',32,'全唐诗/poet.song.202000.json','["生世誰令抱百憂，點黄不肯上眉頭。", "江邊風雨飄蓬箬，愛惜扁舟一夜愁。"]'),
('4ee4fbe9-c078-4b4d-b170-82b1b46af143','天塹','劉克莊','宋','宋诗','song-poetry','','[]','興亡天數亦人謀，戰艦蒙衝一炬休。',32,'全唐诗/poet.song.202000.json','["興亡天數亦人謀，戰艦蒙衝一炬休。", "雪浪如山限南北，不湔江令沈侯羞。"]'),
('1ac0fc07-fe43-40d9-a078-4682a10e1404','送客','劉克莊','宋','宋诗','song-poetry','','[]','夸毗子有誰存者，恩澤侯何足道哉。',32,'全唐诗/poet.song.202000.json','["夸毗子有誰存者，恩澤侯何足道哉。", "一葉絕江載愁去，萬花環席突圍來。"]'),
('15032d7c-6571-44d0-878a-6a42f620c0d7','固窮','劉克莊','宋','宋诗','song-poetry','','[]','狎邪早不由三閣，崛强今難事五樓。',32,'全唐诗/poet.song.202000.json','["狎邪早不由三閣，崛强今難事五樓。", "寧伴伯夷山下餓，豈隨徐福海中求。"]'),
('d4e30e25-c9bb-4c2a-b74f-b8ebb36f4d31','顛危','劉克莊','宋','宋诗','song-poetry','','[]','老梢慮航危，隆棟憂厦顛。',24,'全唐诗/poet.song.202000.json','["老梢慮航危，隆棟憂厦顛。", "危欠維楫爾，顛將覆壓焉。"]'),
('3d2f4d89-1b2f-456b-9a4b-e9bf56e13ebe','節惠','劉克莊','宋','宋诗','song-poetry','','[]','醉似東臯子，愚於北谷公。',24,'全唐诗/poet.song.202000.json','["醉似東臯子，愚於北谷公。", "何當節一惠，單謚作愚翁。"]'),
('6191dd8a-91d4-4f79-a76f-51bfce8e0fc1','化蝶','劉克莊','宋','宋诗','song-poetry','','[]','鶴肯從坡老，鳩能感醉翁。',24,'全唐诗/poet.song.202000.json','["鶴肯從坡老，鳩能感醉翁。", "老夫曾化蝶，飛入百花中。"]'),
('d26f117d-c04e-40f4-8064-a6ac1710b32a','封邑','劉克莊','宋','宋诗','song-poetry','','[]','髮似蘆花面削瓜，躬圭錦襖忽高華。',32,'全唐诗/poet.song.202000.json','["髮似蘆花面削瓜，躬圭錦襖忽高華。", "願還封邑九百戶，小築茆茨三兩家。"]'),
('ef1505e6-654f-4592-b805-a004f86b0b7c','菜地','劉克莊','宋','宋诗','song-poetry','','[]','依然山澤一臞儒，幸有先疇與敝廬。',32,'全唐诗/poet.song.202000.json','["依然山澤一臞儒，幸有先疇與敝廬。", "聞說醉鄉方弄印，不知堪拜小侯無。"]'),
('85372117-b575-408e-a3d3-911291dcbccc','逃愁','劉克莊','宋','宋诗','song-poetry','','[]','年饑未可傾家釀，晝短真當秉燭游。',32,'全唐诗/poet.song.202000.json','["年饑未可傾家釀，晝短真當秉燭游。", "中國醉鄉隔萬里，豈無寸地可逃愁。"]'),
('def0731b-8258-4c32-a154-331c87de26a4','溫故','劉克莊','宋','宋诗','song-poetry','','[]','號寒博士燈檠作，凍死秀才衣带詩。',44,'全唐诗/poet.song.202000.json','["號寒博士燈檠作，凍死秀才衣带詩。", "鯨吸偶陶陶兀兀，蟬嘶尚怪怪奇奇。", "曩時小家數，歲晚大宗師。"]'),
('7b903525-fbc1-480f-8530-670d57f1ea4f','受用','劉克莊','宋','宋诗','song-poetry','','[]','阮遥集平生幾屐，晏平仲半世一裘。',32,'全唐诗/poet.song.202000.json','["阮遥集平生幾屐，晏平仲半世一裘。", "禿翁受用能多少，槲葉爲衣荷蓋頭。"]'),
('62a72a4f-6f64-407f-8991-01b1ab5d63f6','自箴','劉克莊','宋','宋诗','song-poetry','','[]','夢亦齊莊非矯戾，病猶溫習見操存。',32,'全唐诗/poet.song.202000.json','["夢亦齊莊非矯戾，病猶溫習見操存。", "生柴參後千餘載，恍似同時及聖門。"]'),
('3fe42ce6-cb41-4cc0-a17e-c1b37ca8b6c8','飛將','劉克莊','宋','宋诗','song-poetry','','[]','沙漠有烽起，上林無鴈來。',24,'全唐诗/poet.song.202000.json','["沙漠有烽起，上林無鴈來。", "可憐漢飛將，虛築望鄉臺。"]'),
('493fff01-7594-4adc-ac6d-67b8e2d68f5c','退之','劉克莊','宋','宋诗','song-poetry','','[]','向來諛墓人，其報在身後。',48,'全唐诗/poet.song.202000.json','["向來諛墓人，其報在身後。", "柳車不免埋，硫黄安能壽。", "流傳碑板多，篇篇說不朽。", "溘先同露電，沙魘曰山斗。"]'),
('1680abc5-a733-4792-a818-21753e2e7876','李杜','劉克莊','宋','宋诗','song-poetry','','[]','李杜文章宗，繼者宜重黎。',108,'全唐诗/poet.song.202000.json','["李杜文章宗，繼者宜重黎。", "伯禽視熊驥，未易分高低。", "小者善鈎魚，大者能柵雞。", "世無託孤者，練葛誰提携。", "謫仙葬青山，女嫁爲農妻。", "州牧選高援，使嬪於中閨。", "曰禽鳥有匹，寧合不願睽。", "生於隋唐後，名與姬姜齊。", "吾家中壘公，惜不經品題。"]'),
('4c85e44b-49b6-4815-8d9d-e8d1e6dca970','昌谷','劉克莊','宋','宋诗','song-poetry','','[]','王孫乘顥氣，九萬里空洞。',48,'全唐诗/poet.song.202000.json','["王孫乘顥氣，九萬里空洞。", "春風吹玉唾，點點成綵鳳。", "不惟僕命騷，直恐無雅頌。", "暮歸阿㜷嗔，奴輩錦囊重。"]'),
('c12bc649-9f69-4b19-95e2-14579d8428dd','商翁','劉克莊','宋','宋诗','song-poetry','','[]','初隠靈芝處，終逃小橘中。',24,'全唐诗/poet.song.202000.json','["初隠靈芝處，終逃小橘中。", "誰言秦法密，網不得商翁。"]'),
('cc5378d0-22d8-4459-b547-d0d1aca02ca7','樂天','劉克莊','宋','宋诗','song-poetry','','[]','衆評白傅謚，誰得樂天心。',24,'全唐诗/poet.song.202000.json','["衆評白傅謚，誰得樂天心。", "小太宗英主，臨朝謚醉吟。"]'),
('1e965914-71c9-4376-8af7-5dd40405c093','涑水','劉克莊','宋','宋诗','song-poetry','','[]','洛下人呼爲迂叟，非惟語簡意無窮。',32,'全唐诗/poet.song.202000.json','["洛下人呼爲迂叟，非惟語簡意無窮。", "曲臺不合加美謚，俗了深衣大带翁。"]'),
('913ad39d-35a7-4ffb-9c7b-0320dfd30b1c','高光','劉克莊','宋','宋诗','song-poetry','','[]','發兵坑黥布豎子，踞洗駡隋何腐儒。',32,'全唐诗/poet.song.202000.json','["發兵坑黥布豎子，踞洗駡隋何腐儒。", "誰道東都重名節，故人只喚作狂奴。"]'),
('c8b5ed2e-2a42-4d4b-8fca-e043b3bb84c5','蹙操','劉克莊','宋','宋诗','song-poetry','','[]','老賊所憂惟備權，豈知中憤氣同然。',32,'全唐诗/poet.song.202000.json','["老賊所憂惟備權，豈知中憤氣同然。", "諸賢莫道江東小，蹙操惟消兩少年。"]'),
('a6525e10-0ed3-445a-a11b-3451b8fc785f','琨逖','劉克莊','宋','宋诗','song-poetry','','[]','遷喬不與鶑爭出，殿後猶云馬不前。',32,'全唐诗/poet.song.202000.json','["遷喬不與鶑爭出，殿後猶云馬不前。", "越石早知無合殺，不如且讓祖生鞭。"]'),
('6765818f-5310-48db-9b7a-a57d287bdaa0','曹孟德','劉克莊','宋','宋诗','song-poetry','','[]','精舍觀書二十年，偶窺沸鼎出饞涎。',64,'全唐诗/poet.song.202000.json','["精舍觀書二十年，偶窺沸鼎出饞涎。", "小豪已草黄巾檄，老大遭燒赤壁船。", "半夜宮嬪和淚訣，當時漢禪只心傳。", "後來仍有朱三輩，欲比英雄恐未然。"]'),
('a385576b-39cd-4191-bf78-7e581707ab21','孫伯符','劉克莊','宋','宋诗','song-poetry','','[]','霸略誰堪敵伯符，每開史冊想規模。',64,'全唐诗/poet.song.202000.json','["霸略誰堪敵伯符，每開史冊想規模。", "一千掃衆橫江去，十七成功自古無。", "不分老瞞稱猘子，便呼公瑾作姨夫。", "君看末命尤奇特，指顧張昭爲托孤。"]'),
('cf2b07fd-cbbe-4320-87bf-165262467f7c','劉玄德','劉克莊','宋','宋诗','song-poetry','','[]','老瞞虐焰市朝空，宗室惟餘大耳翁。',64,'全唐诗/poet.song.202000.json','["老瞞虐焰市朝空，宗室惟餘大耳翁。", "漢賊有誰分逆順，關河無地著英雄。", "紫髯久矣營江表，黄屋蕭然寄峽中。", "可惜姜維膽如斗，功雖不就有餘忠。"]'),
('f7edd68d-d596-40b8-9179-20ab3989d511','魏志','劉克莊','宋','宋诗','song-poetry','','[]','稱帝稱王非一个，國家不可便無孤。',32,'全唐诗/poet.song.202000.json','["稱帝稱王非一个，國家不可便無孤。", "此言只是瞞孀幼，豈有英雄也恁愚。"]'),
('447816a9-bbec-4c40-a943-5e5a062c7fb6','二世','劉克莊','宋','宋诗','song-poetry','','[]','失國之君多咎政，興王者作著休符。',32,'全唐诗/poet.song.202000.json','["失國之君多咎政，興王者作著休符。", "亡秦天告由胡亥，非謂長城外有胡。"]'),
('9e7586e5-845d-40dd-939f-71fd8d648d89','質子','劉克莊','宋','宋诗','song-poetry','','[]','七雄側目虎狼都，仁暴端由取舍殊。',32,'全唐诗/poet.song.202000.json','["七雄側目虎狼都，仁暴端由取舍殊。", "燕太子留生馬角，楚王心作牧羊奴。"]'),
('0b22b139-b425-4aa4-bcca-e1f64d56d6d6','郡宴','劉克莊','宋','宋诗','song-poetry','','[]','瑶琴能挑文君意，玉笛安知虢國心。',32,'全唐诗/poet.song.202000.json','["瑶琴能挑文君意，玉笛安知虢國心。", "但是有情俱感動，惟村夫子不知音。"]'),
('29a50145-e138-4d7b-9093-5be7587d8b2f','冬蚊','劉克莊','宋','宋诗','song-poetry','','[]','南州時令舛，冬月有蚊飛。',48,'全唐诗/poet.song.202000.json','["南州時令舛，冬月有蚊飛。", "豈是爲饑祟，因而觸禍機。", "照尤嫌畫燭，驅尚入羅幃。", "吾母音容遠，何妨用扇揮。"]'),
('2771b4fb-e603-4b21-a545-c9fd3287d9bd','冬蠅','劉克莊','宋','宋诗','song-poetry','','[]','百蟲已藏蟄，此物出何哉。',48,'全唐诗/poet.song.202000.json','["百蟲已藏蟄，此物出何哉。", "甚矣綠衣僣，公然赤幘來。", "居嘗污脯醢，尤喜敗樽罍。", "刑故寧論小，無分卵與胎。"]'),
('4f3b53b5-07a9-4694-be92-a45bb45e8327','隠者','劉克莊','宋','宋诗','song-poetry','','[]','寧採箕山釣潁濱，放勛天大不能臣。',32,'全唐诗/poet.song.202000.json','["寧採箕山釣潁濱，放勛天大不能臣。", "漁郎未必知年代，先有逃堯次避秦。"]'),
('75a16dbe-a227-40e2-8e47-705fdeed061a','偈','劉克莊','宋','宋诗','song-poetry','','[]','遠希大慧無，近笑孤峯絮。',24,'全唐诗/poet.song.202000.json','["遠希大慧無，近笑孤峯絮。", "多少初地人，爭問末後句。"]'),
('e3a135e5-4f4b-4e33-a71d-529103bd3071','秦紀','劉克莊','宋','宋诗','song-poetry','','[]','土廣曾吞九雲夢，民勞因起一阿房。',32,'全唐诗/poet.song.202000.json','["土廣曾吞九雲夢，民勞因起一阿房。", "人皆憐楚三戶在，天獨知秦二世亡。"]'),
('a4c56492-6c76-452d-a8bf-2814cc14df3d','自警','劉克莊','宋','宋诗','song-poetry','','[]','司馬賦中聊諷一，伯魚詩外又聞三。',32,'全唐诗/poet.song.202000.json','["司馬賦中聊諷一，伯魚詩外又聞三。", "空餘物表陵雲氣，不向師前立雪參。"]'),
('718f48b0-fa65-4810-9ac5-6e64b8d6e37d','齊俗','劉克莊','宋','宋诗','song-poetry','','[]','柏寢纔休又雪宮，殺麋罪與殺人同。',32,'全唐诗/poet.song.202000.json','["柏寢纔休又雪宮，殺麋罪與殺人同。", "徂丘稷下人多詐，誰肯投身入穽中。"]'),
('f756fcd8-cbf4-4229-ab2f-80bc976198fa','源裏','劉克莊','宋','宋诗','song-poetry','','[]','一洞沾秦俗，疑非太古民。',24,'全唐诗/poet.song.202000.json','["一洞沾秦俗，疑非太古民。", "盡將源裏事，報與世間人。"]'),
('dfb9d434-4b30-4867-a0ba-05804a9ad290','中說','劉克莊','宋','宋诗','song-poetry','','[]','先業歸猶在，遺經讀未終。',24,'全唐诗/poet.song.202000.json','["先業歸猶在，遺經讀未終。", "豈無門弟子，私謚作文中。"]'),
('f58ad943-d531-427a-9530-c1ece12a6098','軹道','劉克莊','宋','宋诗','song-poetry','','[]','秦暴渾如狼牧羊，築臨洮郡至咸陽。',32,'全唐诗/poet.song.202000.json','["秦暴渾如狼牧羊，築臨洮郡至咸陽。", "苦防齊客出關外，豈料子嬰降道傍。"]'),
('2c4e912a-7e98-4402-9422-6ecd8121aa09','求鳳曲','劉克莊','宋','宋诗','song-poetry','','[]','古有輕生士，今無起死醫。',24,'全唐诗/poet.song.202000.json','["古有輕生士，今無起死醫。", "可憐茂陵渴，猶畫遠山眉。"]'),
('fff41c35-62b2-4920-b38b-5134d5894ebc','刺客','劉克莊','宋','宋诗','song-poetry','','[]','不了一毫事，空捐七尺軀。',24,'全唐诗/poet.song.202000.json','["不了一毫事，空捐七尺軀。", "陶惜其人沒，雄纔以盜書。"]'),
('35c59849-923f-4342-9aa2-f4f12279258b','古墓','劉克莊','宋','宋诗','song-poetry','','[]','龜趺但見碑訛缺，馬鬣安知葬舊新。',32,'全唐诗/poet.song.202000.json','["龜趺但見碑訛缺，馬鬣安知葬舊新。", "想見若敖求食鬼，亦羞東郭乞墦人。"]'),
('f19e767c-e87d-4ef5-be06-1996dd3e235c','舊遊','劉克莊','宋','宋诗','song-poetry','','[]','扶胥黄木水連空，曾讀韓碑訪祝融。',32,'全唐诗/poet.song.202000.json','["扶胥黄木水連空，曾讀韓碑訪祝融。", "安得六丁機萬弩，岷江西去海潮東。"]'),
('4601a98b-e29f-49e5-be23-105993588033','歲除即事十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','聽得先生去，拋書喜欲顛。',24,'全唐诗/poet.song.202000.json','["聽得先生去，拋書喜欲顛。", "吾聞渥洼種，墮地不須鞭。"]'),
('f4ced69e-7709-45a0-b8c3-4d184703b2d1','歲除即事十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','門外呵寒客，鶉衣百結懸。',24,'全唐诗/poet.song.202000.json','["門外呵寒客，鶉衣百結懸。", "藏瓶猶可撲，莫費水衡錢。"]'),
('490a106b-09ff-487b-83de-5a07dad344a7','歲除即事十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','甚惜光陰去，其如耄老何。',24,'全唐诗/poet.song.202000.json','["甚惜光陰去，其如耄老何。", "丁寧小兒女，不必看鄉儺。"]'),
('d0ad05b2-08f5-424f-a001-995ad6ca909d','歲除即事十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','歲晚傭耕者，人人訴澇乾。',24,'全唐诗/poet.song.202000.json','["歲晚傭耕者，人人訴澇乾。", "吾寧減私量，汝莫待租瘢。"]'),
('88051780-0a7d-4fce-a985-9f76052877a5','歲除即事十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','賣菜猶求益，栽桃不厭多。',24,'全唐诗/poet.song.202000.json','["賣菜猶求益，栽桃不厭多。", "小園兩三樹，冷淡柰春何。"]'),
('de3e816a-26b7-4657-8de0-6fde6268ae06','歲除即事十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','想見朱衣吏，催排玉筍班。',24,'全唐诗/poet.song.202000.json','["想見朱衣吏，催排玉筍班。", "老臣絕朝謁，北望祝南山。"]'),
('ac7a35a0-fadb-48a9-91f1-fb7257fafc88','歲除即事十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','細切如絲菜，添斟獻頌椒。',24,'全唐诗/poet.song.202000.json','["細切如絲菜，添斟獻頌椒。", "未曾守除夜，早已問元宵。"]'),
('d582d8e1-ebaa-4fd6-816b-4592225e3d2f','歲除即事十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','聞說醉鄉裏，家家設酒壚。',24,'全唐诗/poet.song.202000.json','["聞說醉鄉裏，家家設酒壚。", "有劉伶肯飲，無李白誰沽。"]'),
('1bd6f263-a3f7-4164-b1f5-5aaacc437626','歲除即事十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','草市芳菲節，柴門寂寞濱。',24,'全唐诗/poet.song.202000.json','["草市芳菲節，柴門寂寞濱。", "桃符聊塞白，免謗作詩人。"]'),
('5ea29b9a-9562-499c-9f52-9ec1eb51c625','歲除即事十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','瘦骨春衫薄，華顛綵勝垂。',24,'全唐诗/poet.song.202000.json','["瘦骨春衫薄，華顛綵勝垂。", "菱花應竊笑，粧束不相宜。"]'),
('0df94462-082d-4b98-bf1c-3e462cab884e','錦孫','劉克莊','宋','宋诗','song-poetry','','[]','胎髮落居後，屠蘇飲最先。',24,'全唐诗/poet.song.202000.json','["胎髮落居後，屠蘇飲最先。", "眉間八十字，願汝過翁年。"]'),
('61e23989-60d0-41e7-a39b-9d4e59fc6278','葵女','劉克莊','宋','宋诗','song-poetry','','[]','早惠能言者，前生結習餘。',24,'全唐诗/poet.song.202000.json','["早惠能言者，前生結習餘。", "吾聞伏生女，口授古尚書。"]'),
('0487a63d-3be4-4a88-b6d3-71d2c6d67ec2','短章二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','少日喜累句，暮年多短章。',24,'全唐诗/poet.song.202000.json','["少日喜累句，暮年多短章。", "假令重盛壯，展拓不能長。"]'),
('f2b3fce7-8a61-41e1-a945-092351546e6d','短章二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','衰殘齒易宿，陳腐意難新。',24,'全唐诗/poet.song.202000.json','["衰殘齒易宿，陳腐意難新。", "安知癡老子，非復舊詞臣。"]'),
('fa32be26-d6db-4254-aa53-bad35e50932d','新春二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','聞禽啄木心猶喜，躍馬追花事已非。',32,'全唐诗/poet.song.202000.json','["聞禽啄木心猶喜，躍馬追花事已非。", "今與東皇盟歃了，留春死不放春歸。"]'),
('1932c9b1-3b88-4557-8b6b-a06796512405','新春二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','春說吾去留靡定，又云君醉醒難知。',32,'全唐诗/poet.song.202000.json','["春說吾去留靡定，又云君醉醒難知。", "即愁醉裏逃而去，不道先生有醒時。"]'),
('61d981b5-bfef-49d2-9a28-6ef64d3d8474','畫贊','劉克莊','宋','宋诗','song-poetry','','[]','雖則丹青妙，其如齒髮衰。',24,'全唐诗/poet.song.202000.json','["雖則丹青妙，其如齒髮衰。", "遠孫元未識，認作古鍾馗。"]'),
('245236b7-4c29-417a-b368-2a3ed26d667b','時事','劉克莊','宋','宋诗','song-poetry','','[]','問訊班春守，牢辭餽歲人。',24,'全唐诗/poet.song.202000.json','["問訊班春守，牢辭餽歲人。", "翁年十分老，時事一番新。"]'),
('2aaa487c-4f4e-43b9-a927-a96e0ff61c74','二呂','劉克莊','宋','宋诗','song-poetry','','[]','韓呂真喬木，蟠根與國同。',24,'全唐诗/poet.song.202000.json','["韓呂真喬木，蟠根與國同。", "伯泰太史氏，子約大愚公。"]'),
('61340763-ba5f-4ac1-93b3-f319cfd7927f','立春十四韻','劉克莊','宋','宋诗','song-poetry','','[]','嘉平至孟陬，麗譙春再頒。',168,'全唐诗/poet.song.202000.json','["嘉平至孟陬，麗譙春再頒。", "齊民撥不開，雜遝來如山。", "農家卜休咎，多以觳觫觀。", "頗聞舉體赤，其咎爲燥乾。", "又云尾角白，亦慮冬祁寒。", "吾憊不能耕，對之發長歎。", "平生願豐心，雖老猶如丹。", "方興西疇務，稍覺南船慳。", "展轉夜少眠，嘔噎晨廢餐。", "敢望餘糧栖，漸恐拾穗難。", "陛下仁如天，役簡稅賦寬。", "臨遣皆循良，黜削先饕殘。", "一麗丹書內，孰若青史間。", "僕方儕民伍，誰爲語縣官。"]'),
('24bff9d2-a1bc-4fbc-9e32-4328aeddea2d','老少','劉克莊','宋','宋诗','song-poetry','','[]','上樹千回時已過，遶枝三匝老安歸。',32,'全唐诗/poet.song.202000.json','["上樹千回時已過，遶枝三匝老安歸。", "向來誤立紅雲畔，逃入青山計未非。"]'),
('2ec1e2bd-c2d2-4b0f-bc72-bac01fa2c0f1','倚伏','劉克莊','宋','宋诗','song-poetry','','[]','且可飲杯中物，誰能管身外愁。',28,'全唐诗/poet.song.202000.json','["且可飲杯中物，誰能管身外愁。", "穢襪奄終元載，短衾可斂黔婁。"]'),
('daadde0a-d17a-4da1-9825-4f8391d6b2c0','螢蟻','劉克莊','宋','宋诗','song-poetry','','[]','螢微化因草，蟻聚國於槐。',48,'全唐诗/poet.song.202000.json','["螢微化因草，蟻聚國於槐。", "繆析封侯爵，僭爲思子臺。", "九泉謀蟄處，十月有霜來。", "穹壤大如許，爾曹小矣哉。"]'),
('edf9d5b8-0a11-47a3-b4f0-8c2b6ffb82b2','范雎魏齊','劉克莊','宋','宋诗','song-poetry','','[]','士固不可辱，人殊未易知。',24,'全唐诗/poet.song.202000.json','["士固不可辱，人殊未易知。", "元來座上客，不及簀中尸。"]'),
('e72c341b-5f54-49cd-992d-51c94cf85e19','瓜李','劉克莊','宋','宋诗','song-poetry','','[]','蠅及瓜勿啖，螬食李何妨。',24,'全唐诗/poet.song.202000.json','["蠅及瓜勿啖，螬食李何妨。", "苦淡誰知味，甘鮮或腐腸。"]'),
('78a3d4da-22d9-4eb9-8b46-0edd52dffaae','盤龍欒大','劉克莊','宋','宋诗','song-poetry','','[]','豪傑爭鵝炙，神仙食馬肝。',24,'全唐诗/poet.song.202000.json','["豪傑爭鵝炙，神仙食馬肝。", "豈知有薇蕨，布滿首陽山。"]'),
('abf12f6d-48c2-4892-a952-6fd9992627af','達生','劉克莊','宋','宋诗','song-poetry','','[]','無二客穿冢殉，有一奴荷鍤從。',28,'全唐诗/poet.song.202000.json','["無二客穿冢殉，有一奴荷鍤從。", "勿煩作者諛墓，莫管鄰人相舂。"]'),
('11fbbb6a-5b6c-4531-9a9d-b74c39ae30e7','儒釋','劉克莊','宋','宋诗','song-poetry','','[]','鵝湖始若小異，虎溪豈必皆同。',28,'全唐诗/poet.song.202000.json','["鵝湖始若小異，虎溪豈必皆同。", "平亭晦庵子靜，揑合淵明遠公。"]'),
('ef992598-edb4-4ae0-bf06-f47dca4b3853','閑情','劉克莊','宋','宋诗','song-poetry','','[]','宴坐僅留半窗月，歸裝只載一船愁。',32,'全唐诗/poet.song.202000.json','["宴坐僅留半窗月，歸裝只載一船愁。", "可憐潘令無標致，却爲閑情白了頭。"]'),
('43d5f576-acd6-4eb2-a7e0-1eb9f363387e','諸侯客','劉克莊','宋','宋诗','song-poetry','','[]','犬吠雞鳴者，皆爲席上珍。',24,'全唐诗/poet.song.202000.json','["犬吠雞鳴者，皆爲席上珍。", "如何彈鋏客，亦有竊弓人。"]'),
('5cc369dd-898a-4401-a80c-7648a49ad922','三和粧字韻陳魁載酒','劉克莊','宋','宋诗','song-poetry','','[]','榮途素定不須忙，羞作春妍愛古粧。',64,'全唐诗/poet.song.202000.json','["榮途素定不須忙，羞作春妍愛古粧。", "衆促奪袍詩進御，君寧微服夜歸鄉。", "怪來尊老升歌席，移就菩提養病坊。", "聞說重題新鶴表，分留印綬與諸郎。"]'),
('93e01d3b-497e-4365-adcf-5d9927437292','孚應祠十二韻','劉克莊','宋','宋诗','song-poetry','','[]','吾翁宰木下，有蛟穴而居。',144,'全唐诗/poet.song.202000.json','["吾翁宰木下，有蛟穴而居。", "一旦忽死去，靈物不待驅。", "秦時灌口君，髣佛其人歟。", "但當詠雩風，不必焚尪巫。", "三農相勞苦，萬頃皆上腴。", "其功及百世，否則吾其魚。", "沈沈孚應祠，輪奐粲碧朱。", "何當春服成，童冠相携扶。", "牢醴薦閟宮，風謠采康衢。", "它日送迎神，詩亦不可無。", "吾筆雖卑弱，實錄非敢誣。", "斐然勒碑陰，竊比韓與蘇。"]'),
('9274ffe2-895c-4b90-b26b-128630287dcf','歲除前一日','劉克莊','宋','宋诗','song-poetry','','[]','暮年心膽怯，臨履極兢兢。',24,'全唐诗/poet.song.202000.json','["暮年心膽怯，臨履極兢兢。", "已被梅花惱，時爲爆竹驚。"]'),
('d1d0f3f2-5dc5-4325-925c-2312e4d0c421','演雅二十韻','劉克莊','宋','宋诗','song-poetry','','[]','學道無所得，惟於鄙事能。',240,'全唐诗/poet.song.202000.json','["學道無所得，惟於鄙事能。", "九袠後篇什，來世有公評。", "豈未登社壇，直欲破劉城。", "六言與七字，如九轉煉成。", "宇宙中間物，瑣屑不記名。", "孰能通倫類，挑抉其微情。", "蛾以燈爲光，蚊衆成雷聲。", "桑老蠶繭白，草腐螢爝明。", "幽谷聞綿蠻，知有遷喬鶑。", "落日見科斗，深夜有蟈鳴。", "蚋嗜醯雜襲，蚓飲泉亦清。", "蠅吮血美炙，犬以穢爲鯖。", "蛇非性好曲，蠖負屈求伸。", "蚤懼鵂鶹撮，自匿於衣巾。", "虱愁犢鼻破，不免景略捫。", "狐依冢作祟，鼠謂社可憑。", "痛摑一掌血，飽食五鼎烹。", "疇昔同袍子，來問儂師承。", "前柴桑處士，後半山老人。", "詎能追高雅，或可洗腐陳。"]'),
('f71a4549-ce5c-42cb-9093-a7b75a53b86b','郄謝','劉克莊','宋','宋诗','song-poetry','','[]','蒙叟云大儒倡，晉人以小字呼。',28,'全唐诗/poet.song.202000.json','["蒙叟云大儒倡，晉人以小字呼。", "謝琰僅呼未婢，方回故是傖奴。"]'),
('56641c16-e2fa-47d2-9904-ddeca34709d3','梅妃','劉克莊','宋','宋诗','song-poetry','','[]','簫能妻弄玉，琴可挑文君。',24,'全唐诗/poet.song.202000.json','["簫能妻弄玉，琴可挑文君。", "吹徹寧哥笛，梅妃未必聞。"]'),
('46e854e0-da0c-4b21-924b-4243aea8b853','寄强甫','劉克莊','宋','宋诗','song-poetry','','[]','囝罷相依螢雪邊，安知今汝亦華顛。',64,'全唐诗/poet.song.202000.json','["囝罷相依螢雪邊，安知今汝亦華顛。", "寧從欵乃翁孤釣，肯要原夫輩一聯。", "兒向詩中得三昧，吏鉗紙尾怕分權。", "客言大尹尤謙挹，每見屏星榻必懸。"]'),
('494b097d-3525-4cb5-b6f2-c58c39d4e71e','寄沂孫','劉克莊','宋','宋诗','song-poetry','','[]','帝失遺珠不知處，離朱象罔遍咨詢。',64,'全唐诗/poet.song.202000.json','["帝失遺珠不知處，離朱象罔遍咨詢。", "彼皆宗此於方外，汝獨問之於水濱。", "求我聲音難見佛，得吾骨髓別無人。", "即今牛驥嗟同皁，天網何時罩鳳麟。"]'),
('38abf14b-3efe-4a71-83c4-09c2432771ad','白湖廟二十韻','劉克莊','宋','宋诗','song-poetry','','[]','靈妃一女子，瓣香起湄洲。',240,'全唐诗/poet.song.202000.json','["靈妃一女子，瓣香起湄洲。", "巨浸雖稽天，旗蓋儼中流。", "駕風檣浪舶，翻筋斗韆鞦。", "既而大神通，血食羊萬頭。", "封爵遂綦貴，青圭蔽珠旒。", "輪奐擬宮省，盥薦皆公侯。", "始盛自全閩，俄遍於齊州。", "靜如海不波，幽與神爲謀。", "營卒嘗密禱，山越立獻囚。", "豈必如麻姑，撒米人間游。", "亦竊笑阿環，種桃兒童偷。", "獨於民錫福，能使歲有秋。", "每至割穫時，稚耄爭勸酬。", "坎坎擊社鼓，嗚嗚纏蠻謳。", "常恨孔子沒，豳風不見收。", "君謨與漁仲，亦未嘗旁搜。", "束晳何人哉，愚欲補前脩。", "緬懷荔臺叟，紀述惜未周。", "他山豈無石，可以礱且鎪。", "吾老毛穎禿，安能斡萬年。"]'),
('947dcd8c-2ac8-4978-83aa-3e486826612d','賀歲','劉克莊','宋','宋诗','song-poetry','','[]','遍行海角與天涯，煙閣雲臺不似家。',64,'全唐诗/poet.song.202000.json','["遍行海角與天涯，煙閣雲臺不似家。", "無肉併無子猷竹，失侯不失邵平瓜。", "難藏白髮惟菱照，晚悟朱榮若槿花。", "慙愧孫曾來賀歲，勸翁椒酒各斟些。"]'),
('11869249-831c-4c66-bc62-971547c4b7b7','廣列女四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','前有條桑女子，後有花蘂夫人。',28,'全唐诗/poet.song.202000.json','["前有條桑女子，後有花蘂夫人。", "潔以自媒爲婦，賢於奉表稱臣。"]'),
('c5b16aa7-126d-4cfc-9f3e-0b56b9dfe263','廣列女四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','不肯一錢分，賢哉父誨言。',24,'全唐诗/poet.song.202000.json','["不肯一錢分，賢哉父誨言。", "奈何伯喈女，有媿卓王孫。"]'),
('d278b89c-61f5-4db9-b4fe-b511ec41476b','廣列女四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','空有難深作，殊無貞烈姿。',24,'全唐诗/poet.song.202000.json','["空有難深作，殊無貞烈姿。", "試評阿嬌賦，有愧孝娥碑。"]'),
('03e3f2ea-ff4b-40b5-b0e5-39a3d41e7461','廣列女四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','骨永埋胡地，魂終戀漢廷。',24,'全唐诗/poet.song.202000.json','["骨永埋胡地，魂終戀漢廷。", "誰令妃遠嫁，千載塚猶青。"]'),
('0efb1c36-ebd5-4df5-a655-6f621e794316','錄姜伯約遺言','劉克莊','宋','宋诗','song-poetry','','[]','事或難遥度，人殊未易知。',24,'全唐诗/poet.song.202000.json','["事或難遥度，人殊未易知。", "誰云卧龍死，復有一姜維。"]'),
('443f9b7b-8fcf-4a07-84a9-17afd5535d93','左史倚相','劉克莊','宋','宋诗','song-poetry','','[]','善謔非爲謔，微言可解紛。',24,'全唐诗/poet.song.202000.json','["善謔非爲謔，微言可解紛。", "祈招忘出處，也道讀三墳。"]'),
('7e50484c-eb69-42df-a6a8-11061628cc4c','廣游女  其一','劉克莊','宋','宋诗','song-poetry','','[]','男女不親授，寧親筆父書。',24,'全唐诗/poet.song.202000.json','["男女不親授，寧親筆父書。", "如何出腹子，兩箇是胡雛。"]'),
('946eacf4-7626-4671-8d22-c59f9b571134','廣游女  其二','劉克莊','宋','宋诗','song-poetry','','[]','昔有吹笙侶，驂鸞上玉宸。',24,'全唐诗/poet.song.202000.json','["昔有吹笙侶，驂鸞上玉宸。", "奈何無欲地，著得有情人。"]'),
('d82a3da4-54b3-4222-b1f9-6f8fd2c844d7','廣游女  其三','劉克莊','宋','宋诗','song-poetry','','[]','振笛深宮側，夫人若罔知。',24,'全唐诗/poet.song.202000.json','["振笛深宮側，夫人若罔知。", "可憐東鄰女，三載隔牆窺。"]'),
('781eba39-b374-4614-b44a-d532d52387d8','又六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','昏主非姬不飽，內嬖廢嫡可悲。',28,'全唐诗/poet.song.202000.json','["昏主非姬不飽，內嬖廢嫡可悲。", "驪女逐金玦子，玉環養錦䙀兒。"]'),
('bfd07fb6-0550-49e6-bdbd-b592b7cd2a75','又六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','寡女畫眉通好，鄰姬捧心效顰。',28,'全唐诗/poet.song.202000.json','["寡女畫眉通好，鄰姬捧心效顰。", "况有黄金買賦，不羨碧玉嫁人。"]'),
('1963a5d6-6733-4ccf-9430-74893c422431','明暗','劉克莊','宋','宋诗','song-poetry','','[]','大士千眼而明，老子一隻而盲。',28,'全唐诗/poet.song.202000.json','["大士千眼而明，老子一隻而盲。", "或不夜能久照，誰籲天鳴不平。"]'),
('624920a1-dd0f-4f6b-90db-fb826dcf3cec','春詞','劉克莊','宋','宋诗','song-poetry','','[]','人競迎新歲，儂方餞舊年。',24,'全唐诗/poet.song.202000.json','["人競迎新歲，儂方餞舊年。", "雛鶑又百囀，高柳忽三眠。"]'),
('73423505-28e9-4fe6-a46f-a8a40a068ee2','題海陵徐神翁墓','劉克莊','宋','宋诗','song-poetry','','[]','忽被黄符迫下山，許携苕帚面天顔。',64,'全唐诗/poet.song.202000.json','["忽被黄符迫下山，許携苕帚面天顔。", "早知錦纜盛宮女，因舍紅巾問阿環。", "空有蚋蠅侵玉骨，斷無龍虎守金丹。", "秋墳翁仲相酬答，日落僧歸家閉關。"]'),
('28253e62-e641-4f9b-9cda-155bc13cfcd3','寓言','劉克莊','宋','宋诗','song-poetry','','[]','赤肉團終當敗壞，臭皮袋死尚貪癡。',64,'全唐诗/poet.song.202000.json','["赤肉團終當敗壞，臭皮袋死尚貪癡。", "生憎銅鏡催白髮，殘著珠襦待赤眉。", "高築迷樓愁鬼瞰，多爲疑冢怕人知。", "吾評裸葬尤堅久，來往何曾挂一絲。"]'),
('9be36fb8-6ff8-4074-aa67-26f1e024702d','芳臭','劉克莊','宋','宋诗','song-poetry','','[]','流芳斜谷出師表，遺臭樊城受禪碑。',32,'全唐诗/poet.song.202000.json','["流芳斜谷出師表，遺臭樊城受禪碑。", "芳臭即今皆判矣，鮑魚難揜祖龍尸。"]'),
('30f5c0bb-bcb0-4458-b233-8133270a6f64','寒','劉克莊','宋','宋诗','song-poetry','','[]','趁得清明幾日閑，不禁連雨作春寒。',32,'全唐诗/poet.song.202000.json','["趁得清明幾日閑，不禁連雨作春寒。", "小窗對客開新煮，爇罷沈香看牡丹。"]'),
('abe316ff-b06d-4630-8788-9738dddf1e19','乍晴','劉克莊','宋','宋诗','song-poetry','','[]','天更商量雨，人都領略晴。',48,'全唐诗/poet.song.202000.json','["天更商量雨，人都領略晴。", "晚山青妥貼，野水白縱橫。", "鷺立沙頭影，蜂喧樹底聲。", "笋輿扶病出，邂逅亦詩成。"]'),
('38a6d53b-d7d0-4781-bbdc-d0468bc49d64','晝','劉克莊','宋','宋诗','song-poetry','','[]','散懷輕病骨，汲古活心源。',48,'全唐诗/poet.song.202000.json','["散懷輕病骨，汲古活心源。", "日炙桐陰晚，烟蒸豆穗繁。", "密紅雙鷺迹，深綠一鷗喧。", "未晝聊舒偃，茶香起小烟。"]'),
('c015c29c-b9e3-4cb6-9e46-fd1519453e6f','未開梅','劉克莊','宋','宋诗','song-poetry','','[]','老樹天機早，潛回一點春。',48,'全唐诗/poet.song.202000.json','["老樹天機早，潛回一點春。", "寒梢方蓓蕾，玉骨已精神。", "冷淡看前輩，芳菲總後塵。", "更須香共色，未是覽花人。"]'),
('e3e80d0a-8cc2-46c8-8015-e572f703fc19','桂花','劉克莊','宋','宋诗','song-poetry','','[]','生得粟來大，妝成蠟樣黄。',48,'全唐诗/poet.song.202000.json','["生得粟來大，妝成蠟樣黄。", "落金遮蟻穴，釀蜜滿蜂房。", "月下高低影，風前遠近香。", "夜深清到骨，幽夢繞胡床。"]'),
('937ab9fa-4b60-4adf-9cfe-c66e6255594a','柳','劉克莊','宋','宋诗','song-poetry','','[]','靜是無憀動是狂，秋蟬兩兩抱斜陽。',32,'全唐诗/poet.song.202000.json','["靜是無憀動是狂，秋蟬兩兩抱斜陽。", "不知才思能多少，瘦得腰肢似沈郎。"]'),
('a7265d5d-df1a-4730-9829-99d267fad920','種柳','劉克莊','宋','宋诗','song-poetry','','[]','少少旗亭夾道邊，小橋終日水潺湲。',32,'全唐诗/poet.song.202000.json','["少少旗亭夾道邊，小橋終日水潺湲。", "垂楊種後方二尺，惆悵成陰是幾年。"]'),
('c06a8906-036c-4b64-bc7b-0c66339af01e','雪','劉克莊','宋','宋诗','song-poetry','','[]','衰桐無葉報蕭颼，卧聽窗聲作許愁。',64,'全唐诗/poet.song.202000.json','["衰桐無葉報蕭颼，卧聽窗聲作許愁。", "檠暗冷光侵硯几，瓦疏飛片落香篝。", "病思結客遊梁苑，狂愛提軍入蔡州。", "也欲訪梅湖畔去，黄塵滿袖欲盟鷗。"]'),
('71cfb08a-557e-4e92-ba0e-dab4c5bffd0f','寺','劉克莊','宋','宋诗','song-poetry','','[]','人烟疏處老僧家，石路榕陰噪晚鴉。',32,'全唐诗/poet.song.202000.json','["人烟疏處老僧家，石路榕陰噪晚鴉。", "欲挈龐公妻子去，幅巾閣上讀楞伽。"]'),
('59e95e1d-132d-4e4d-9aa3-eb4e325dffbc','書','劉克莊','宋','宋诗','song-poetry','','[]','兩帖走蛟虬，堂堂腕力遒。',48,'全唐诗/poet.song.202000.json','["兩帖走蛟虬，堂堂腕力遒。", "太師唐死節，大令晉風流。", "要續麻姑刻，那容扇媼求。", "教兒勤護惜，恐被六丁偷。"]'),
('1d5c29ff-fdce-40a1-9cbb-314f80ec4fdd','雁陣','劉克莊','宋','宋诗','song-poetry','','[]','出塞行行如出戰，銜蘆寂寂類銜枚。',32,'全唐诗/poet.song.202000.json','["出塞行行如出戰，銜蘆寂寂類銜枚。", "平沙夜宿排形勢，誰爲王師破得來。"]'),
('a2adcdff-7bf7-445e-aa6d-8039d3a06767','子規','劉克莊','宋','宋诗','song-poetry','','[]','一聲聲勸人歸去，啼血江南幾樹花。',32,'全唐诗/poet.song.202000.json','["一聲聲勸人歸去，啼血江南幾樹花。", "我被微官拘束在，汝緣何事不歸家。"]'),
('1e341c26-2385-498e-8f06-b79436970985','蝶','劉克莊','宋','宋诗','song-poetry','','[]','東皇頒節下天階，那得香魂入夢來。',32,'全唐诗/poet.song.202000.json','["東皇頒節下天階，那得香魂入夢來。", "十道風光都采訪，相逢只欠驛邊梅。"]'),
('1ff800af-1940-46fc-bd88-3661bb6adb1e','李術士善醫卜','劉克莊','宋','宋诗','song-poetry','','[]','西漢君平莫是渠，蕭然閉肆或旬餘。',64,'全唐诗/poet.song.202000.json','["西漢君平莫是渠，蕭然閉肆或旬餘。", "青囊系肘藏仙訣，黑子如毛錄讖書。", "屢倩揲蓍爻每驗，近聞咒棗病皆除。", "閑時更取離騷看，怕有靈均猶卜居。"]'),
('2b1ca27f-57ba-43ca-9ef3-219f95b1401f','道士','劉克莊','宋','宋诗','song-poetry','','[]','丫髻唐衣八尺長，試看風骨已昂藏。',64,'全唐诗/poet.song.202000.json','["丫髻唐衣八尺長，試看風骨已昂藏。", "丹成屢詫飛昇去，客至多稱吐納忙。", "近習星文兼賣卜，每尋洞穴不賫糧。", "或云曾與陣摶遇，擬問先生乞睡方。"]'),
('e326a865-c6bc-4305-b039-601cac67a851','初冬','劉克莊','宋','宋诗','song-poetry','','[]','晴窗蚤覺愛朝曦，竹外秋聲漸作威。',64,'全唐诗/poet.song.202000.json','["晴窗蚤覺愛朝曦，竹外秋聲漸作威。", "命僕安排新暖閣，呼童熨貼舊寒衣。", "葉浮嫩綠酒初熟，橙切香黄蟹正肥。", "蓉菊滿園皆可羨，賞心從此莫相違。"]'),
('c7025d22-c255-453b-81c9-cd102516b297','東阿王紀夢行','劉克莊','宋','宋诗','song-poetry','','[]','月青露紫翠衾白，相思一夜貫地脈。',104,'全唐诗/poet.song.202000.json','["月青露紫翠衾白，相思一夜貫地脈。", "帝遣纖阿控綠鸞，崑崙低小海如席。", "曲房小幄雙杏坡，玉鳬吐麝熏錦窠。", "軟香蕙雨裙衩濕，紫雲三尺生紅靴。", "金蟾吞漏不入咽，柔情一點薔薇血。", "海山重結千年期，碧桃小核生孫枝，陳王此恨屏山知。"]'),
('68fca419-8dd0-4f57-a367-610e991929cd','齊人少翁招魂歌','劉克莊','宋','宋诗','song-poetry','','[]','夜月抱秋衾，支枕玉鸞小。',90,'全唐诗/poet.song.202000.json','["夜月抱秋衾，支枕玉鸞小。", "艷骨泣紅蕪，茂陵三十老。", "卧聞秦王女兒吹鳳簫，淚入星河翻鵲橋。", "素娥剗襪跨玉兔，回望桂宮一點霧。", "紛紅小蝶沒柳煙，白茅老仙方瞳圓。", "尋愁不見入香髓，露花點衣碧成水。"]'),
('7ae891b8-786e-4759-b724-cf4308f520ce','趙昭儀春浴行','劉克莊','宋','宋诗','song-poetry','','[]','花奴一雙鬢垂耳，綠繩夜汲露桃蘂。',96,'全唐诗/poet.song.202000.json','["花奴一雙鬢垂耳，綠繩夜汲露桃蘂。", "青桂寒烟濕不飛，玉龍呵暖紅薇水。", "翠靴踏雲雲帖妥，燕釵微卸香絲鬌。", "小蓮夾擁真天人，紅梅犯雪欹一朵。", "鸞錦屏風畫水月，鵁鶄抱頸唼蘭葉。", "劉郎散盡金餠歸，笑引香綃護癡蝶。"]'),
('1ba5d39b-3dc5-4e2e-b39b-c24ce659188c','梅花  其一','劉克莊','宋','宋诗','song-poetry','','[]','小園風月不多寬，一樹梅花開未殘。',32,'全唐诗/poet.song.202000.json','["小園風月不多寬，一樹梅花開未殘。", "剝啄敲門嫌特地，緩拖藤杖隔籬看。"]'),
('92e0681b-a044-43c2-88db-96f221e08485','梅花  其二','劉克莊','宋','宋诗','song-poetry','','[]','一點不雜桃李春，一水隔斷車馬塵。',32,'全唐诗/poet.song.202000.json','["一點不雜桃李春，一水隔斷車馬塵。", "恨不來爲清夜飲，月中香露濕烏巾。"]'),
('eb2118bc-8fe7-44cd-903d-5f29db2eb648','梅花  其三','劉克莊','宋','宋诗','song-poetry','','[]','江都車馬滿斜暉，爭赴城南未掩扉。',32,'全唐诗/poet.song.202000.json','["江都車馬滿斜暉，爭赴城南未掩扉。", "要識梅花無盡藏，人人襟袖带香歸。"]'),
('b7406c82-390f-4c44-bc1f-b2577aa9f7a3','蓼花','劉克莊','宋','宋诗','song-poetry','','[]','分紅間白汀洲晚，拜雨揖風江漢秋。',32,'全唐诗/poet.song.202000.json','["分紅間白汀洲晚，拜雨揖風江漢秋。", "看渠耐得清霜去，却恐蘆花先白頭。"]'),
('6f742b8e-832b-4a69-b144-54c50a472f22','壽建寧太守  其一','劉克莊','宋','宋诗','song-poetry','','[]','珥貂不愛愛憑熊，似喜閩山入眼濃。',64,'全唐诗/poet.song.202000.json','["珥貂不愛愛憑熊，似喜閩山入眼濃。", "燕寢香漬公事簡，圍腰金重宦情慵。", "頗聞昭代洵黄髮，未許先期訪赤松。", "十萬人家同祝頌，衮衣從此入登庸。"]'),
('95316a37-a9da-42e3-bb35-401713b1f356','壽建寧太守  其二','劉克莊','宋','宋诗','song-poetry','','[]','官府升平戟衛嚴，退衙惟與客清談。',64,'全唐诗/poet.song.202000.json','["官府升平戟衛嚴，退衙惟與客清談。", "寬和却笑閩溪急，苦硬翻嫌建茗甘。", "南國只今歌召伯，漢庭早晚相曹參。", "情知金鼎催調燮，驛路梅開雪意酣。"]'),
('3720b5b2-50b6-4674-be84-a183484e53c1','慶建州葉守  其一','劉克莊','宋','宋诗','song-poetry','','[]','不比群花取次開，晚香高節匹寒旃。',32,'全唐诗/poet.song.202000.json','["不比群花取次開，晚香高節匹寒旃。", "分明带得清癯相，故傍層冰積雪來。"]'),
('fca74bad-0952-4176-bc66-7f40ffa59e20','慶建州葉守  其二','劉克莊','宋','宋诗','song-poetry','','[]','新貴紛紛競著鞭，明公於此獨恬然。',32,'全唐诗/poet.song.202000.json','["新貴紛紛競著鞭，明公於此獨恬然。", "未曾批敕中書考，先判天官二十年。"]'),
('85402969-bd82-42c0-b90b-26792e7d7ff5','慶建州葉守  其三','劉克莊','宋','宋诗','song-poetry','','[]','鬢猶點漆面桃紅，乾道淳熙輩行空。',32,'全唐诗/poet.song.202000.json','["鬢猶點漆面桃紅，乾道淳熙輩行空。", "不是修身存養力，自緣方寸與天通。"]'),
('d39904de-5260-4094-bc6a-9ddd394c82bf','慶建州葉守  其四','劉克莊','宋','宋诗','song-poetry','','[]','久立紅雲一朵邊，合於仙裏珥貂蟬。',32,'全唐诗/poet.song.202000.json','["久立紅雲一朵邊，合於仙裏珥貂蟬。", "偶然夢到人間世，猶擁旌旗管洞天。"]'),
('9923d0ef-c2cc-4d67-905d-d3c40c3d2409','慶建州葉守  其五','劉克莊','宋','宋诗','song-poetry','','[]','曾遊楚澤詠江蘺，亦向閩山品荔枝。',32,'全唐诗/poet.song.202000.json','["曾遊楚澤詠江蘺，亦向閩山品荔枝。", "猶幸早春茶未試，故應先取建州麾。"]'),
('aa169084-331e-424a-9a01-643ae0f6c3ef','慶建州葉守  其六','劉克莊','宋','宋诗','song-poetry','','[]','處處鷄豚競賽冬，皆言太守致年豐。',32,'全唐诗/poet.song.202000.json','["處處鷄豚競賽冬，皆言太守致年豐。", "老農記得莊生說，姑射仙人恐是公。"]'),
('71895544-857b-4ba9-8b04-77bd8eae70b0','慶建州葉守  其七','劉克莊','宋','宋诗','song-poetry','','[]','貴人列屋貯傾城，公獨齋居徹骨清。',32,'全唐诗/poet.song.202000.json','["貴人列屋貯傾城，公獨齋居徹骨清。", "七袠高年高上品，夜窗相伴一寒檠。"]'),
('c6a4ade4-21a4-4cb1-afb7-22ad3caebcb1','慶建州葉守  其八','劉克莊','宋','宋诗','song-poetry','','[]','袖中凝香未必非，建人惟恐我公歸。',32,'全唐诗/poet.song.202000.json','["袖中凝香未必非，建人惟恐我公歸。", "安知世有孤寒士，側聽黄麻侍衮衣。"]'),
('110f5da6-3553-4339-8e08-3b863af17548','金陵作','劉克莊','宋','宋诗','song-poetry','','[]','高牙拂雲車带雨，清曉西州氣成霧。',176,'全唐诗/poet.song.202000.json','["高牙拂雲車带雨，清曉西州氣成霧。", "玉麟堂上少文書，白鷺亭前多杖屨。", "古來此地一都會，城郭樓臺盡非故。", "落日曚曨江北山，斷煙髣髴新亭路。", "神州豈但夷甫責，西風更有元規污。", "是中端的得長城，正自不能堪短簿。", "戲馬頻從九日遊，南樓許共諸君住。", "眼前突兀坡老碑，醉裏吟哦謫仙句。", "只今蕙帳怨猿鶴，想見齊盟憶鷗鷺。", "淮南四月蠶麥熟，宮闕山河煩卧護。", "了知此意誠能馴，未許尋公遂初賦。"]'),
('96cda577-bc1d-48fa-82ea-db05e33ebe05','梅花','劉克莊','宋','宋诗','song-poetry','','[]','木落山空獨占春，十分清瘦轉精神。',64,'全唐诗/poet.song.202000.json','["木落山空獨占春，十分清瘦轉精神。", "雪疎雪密花添伴，溪淺溪深樹寫真。", "三弄笛聲風過耳，一枝筇影月隨身。", "吟罷欲斷相逢處，恐是孤山隠逸人。"]'),
('7a783f01-2819-47f7-a1aa-23a86a540075','六言三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','表賀赤烏白兔，韋布披襟巨題。',28,'全唐诗/poet.song.202000.json','["表賀赤烏白兔，韋布披襟巨題。", "定價堪提鰲嶺，逢辰不讓龍溪。"]'),
('ce157cc7-5eb7-4cdc-a002-49c57da864dd','六言三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','錦機組織尤巧，紙田收獲甚微。',28,'全唐诗/poet.song.202000.json','["錦機組織尤巧，紙田收獲甚微。", "即今束閣藏起，多時掃閣載歸。"]'),
('5dd2509a-aa8e-4bd0-b49a-07c3e76220be','六言三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','南塘登極數袁，平圍冊后尾聯。',28,'全唐诗/poet.song.202000.json','["南塘登極數袁，平圍冊后尾聯。", "已矣諸老絕筆，勉哉吾子著鞭。"]'),
('80561b56-0e32-46c6-af4c-a8dd99944bf8','至人六言','劉克莊','宋','宋诗','song-poetry','','[]','幽子多棲白雲，至人或混紅塵。',28,'全唐诗/poet.song.202000.json','["幽子多棲白雲，至人或混紅塵。", "有時鼻涕擇菜，有時丫髻負薪。"]'),
('aec03a23-c10e-4e7b-88b8-8278a50f1bb0','懷人','劉克莊','宋','宋诗','song-poetry','','[]','節物隨時換，朱明斗轉杓。',48,'全唐诗/poet.song.202000.json','["節物隨時換，朱明斗轉杓。", "波肥溪𩼈壯，風暖谷鶑嬌。", "青草溪頭岸，紅欄水際橋。", "懷人無數舍，我欲致書招。"]'),
('610db21b-e9e9-4fe5-8d1e-36299dbc4809','玉蘂花','劉克莊','宋','宋诗','song-poetry','','[]','竹院過僧話，山門掃地迎。',48,'全唐诗/poet.song.202000.json','["竹院過僧話，山門掃地迎。", "英雄猶有迹，般若太無情。", "玉蘂春陰密，琅玕晚暑清。", "半生來往屢，也合送人行。"]'),
('d4cc7a52-e769-441f-bb0b-f38946d7f913','春暮','劉克莊','宋','宋诗','song-poetry','','[]','一畝青苔半落英，蜂忙蝶懶互卿卿。',64,'全唐诗/poet.song.202000.json','["一畝青苔半落英，蜂忙蝶懶互卿卿。", "燕泥乾後兒初落，魚尾輕時子徧成。", "閒拂午窗驚野馬，夢遊天竺聽華鯨。", "舍南有柳纖纖在，不奈雙蟬占取鳴。"]'),
('6eb6a985-a21f-40d9-be18-db2fcfd59a35','鶑梭','劉克莊','宋','宋诗','song-poetry','','["\u6625\u5929", "\u5199\u666f", "\u548f\u7269", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u5199\u9e1f"]','擲柳遷喬大有情，交交時作弄機聲。',32,'全唐诗/poet.song.202000.json','["擲柳遷喬大有情，交交時作弄機聲。", "洛陽三月春如錦，多少工夫織得成。"]'),
('f6f094d2-a0b1-4ef2-a7a9-8c3c97eda4d8','秋晚','劉克莊','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u5199\u666f"]','江頭落日照平沙，潮退漁舟閣岸斜。',32,'全唐诗/poet.song.202000.json','["江頭落日照平沙，潮退漁舟閣岸斜。", "白鳥一雙臨水立，見人驚起入蘆花。"]'),
('7f82527d-7816-499e-9aa5-4b716f344911','句  其一','劉克莊','宋','宋诗','song-poetry','','[]','過江人物萃樵引。',8,'全唐诗/poet.song.202000.json','["過江人物萃樵引。"]'),
('97887d77-c354-4d86-adba-cd334e557e20','句  其二','劉克莊','宋','宋诗','song-poetry','','[]','更高千萬丈，還我上頭行。',12,'全唐诗/poet.song.202000.json','["更高千萬丈，還我上頭行。"]'),
('2872edda-c15a-44ce-b5ba-003e6c5186b3','句  其三','劉克莊','宋','宋诗','song-poetry','','[]','楊柳春風丞相府，梧桐夜雨濟王家。',16,'全唐诗/poet.song.202000.json','["楊柳春風丞相府，梧桐夜雨濟王家。"]'),
('835f84d1-af44-46cf-b324-d1570b920cd4','安晚先生貺以丹劑四種古調謝之','陳起','宋','宋诗','song-poetry','','[]','陳子一畝宮，居來七十年。',132,'全唐诗/poet.song.202000.json','["陳子一畝宮，居來七十年。", "當其春盛時，庭花發幽妍。", "轉矚長養天，青子垂簷前。", "秋收備百禮，冬享意則虔。", "年來風雨凌，垣倒壁四穿。", "上漏下卑濕，敗隙遥瞻天。", "三生結施仁，睹此殊興憐。", "捨以四條柱，俾之撐危顛。", "工師得大木，裁製精且專。", "尚欠櫨與楣，況復棟與椽。", "再干大檀越，結此歡喜緣。"]'),
('c09719fa-aae7-4c3c-bdca-55c018e50c97','履齋先生下頒參附往體以謝','陳起','宋','宋诗','song-poetry','','[]','有客號奚毒，西來自赤水。',144,'全唐诗/poet.song.202000.json','["有客號奚毒，西來自赤水。", "外負炎炎氣，內存溫粹美。", "當年楊天惠，夸大不絕齒。", "解后段氏子，即之殊可喜。", "却邪廼素心，調中古無比。", "世仰大醫王，民瘼咨朝市。", "二子願託身，赴湯任驅使。", "興憐維摩老，遣前護衰毀。", "病魔亟退舍，怡然得安壘。", "緬想蓄牛溲，陋哉子韓子。", "既非瞑眩劑，厥疾無瘳理。", "一念衛生恩，百拜額加子。"]'),
('48702e51-7aba-4fc1-abde-86739805133b','友人新息滿月','陳起','宋','宋诗','song-poetry','','[]','蘭砌懽傳書種子，寶刀剃髮月初彌。',32,'全唐诗/poet.song.202000.json','["蘭砌懽傳書種子，寶刀剃髮月初彌。", "絕憐雅致高於俗，點易殘朱抹顖兒。"]'),
('644ac69d-4e6c-42dc-9546-ea438ea2d562','汎湖紀所遇','陳起','宋','宋诗','song-poetry','','[]','六橋鶑花春色濃，十年情緒藥裹中。',128,'全唐诗/poet.song.202000.json','["六橋鶑花春色濃，十年情緒藥裹中。", "筆牀茶竈塵土積，爲君拂拭臨東風。", "可笑衰翁不自忖，少年場中分險韻。", "畫舸輕移柳線迎，侈此清遊逢道韞。", "銖衣飄飄凌綠波，翡翠壓領描新荷。", "雍容肯就文字飲，烏絲細染還輕哦。", "一杯絕類陽關酒，流水高山意何厚。", "曲未終兮袂已揚，一目歸鴉噪棲柳。"]'),
('609924a2-c3bf-4f14-b035-25a93d88a41a','賀友人絲桐復歸','陳起','宋','宋诗','song-poetry','','[]','春到牡丹花事闌，惜春約客遊湖山。',160,'全唐诗/poet.song.202000.json','["春到牡丹花事闌，惜春約客遊湖山。", "煙光萬態屬吟思，白石清泉流指間。", "雙成解后蘭舟駐，索紙大書春草句。", "成此風流一段奇，樂事百年能幾遇。", "薄暮歸來雨濕衣，買舟庇此十三徽。", "小梢愚怮阻人意，客散河梁燈火微。", "方將清事夸兒婦，桐君羽化無何有。", "一壺千金何處尋，愁絕瓠巴無措手。", "要知煩惱所根株，以愛布種當芟除。", "趙璧既返懽如初，哦詩稱賀敢後歟。"]'),
('cf29d5db-e29c-4d7c-81d1-e4f3844d1c65','適安惠糟蟹新酒','陳起','宋','宋诗','song-poetry','','[]','偉哉無腸公，橫行占江湖。',132,'全唐诗/poet.song.202000.json','["偉哉無腸公，橫行占江湖。", "幾欲肆其雄，上山攫於菟。", "無端四五輩，懷椒尋酒壚。", "枕藉糟丘下，醉魂呼不甦。", "尚想橫戈勇，胸次與世殊。", "開懷風味佳，大丹液膏腴。", "此寶君所儲，何爲貽老夫。", "麴生挾之前，爛然陳座隅。", "當其左持螯，不知竭此壺。", "酩酊無何鄉，軒冕不關渠。", "東望歌老饕，前溪梅影疎。"]'),
('a3a6f158-2848-45b0-9566-cc780c7066c9','題適安清湖寓居','陳起','宋','宋诗','song-poetry','','[]','薰風軒檻曉晴開，鬰鬰桐陰手自栽。',64,'全唐诗/poet.song.202000.json','["薰風軒檻曉晴開，鬰鬰桐陰手自栽。", "二水合流當戶過，一山分影入樓來。", "琴逢良夜時揮弄，詩欲名家巧翦裁。", "可羨一廛安所適，紛紛車馬汩黄埃。"]'),
('05d64cce-edc0-4b67-83fc-73e5f590e6d8','燈花戲簡西鄰','陳起','宋','宋诗','song-poetry','','[]','西鄰逸韻偕秋清，瑶琴曾許月下聽。',144,'全唐诗/poet.song.202000.json','["西鄰逸韻偕秋清，瑶琴曾許月下聽。", "神馳吟境日復日，金飈轉矣寒此盟。", "昨夕相逢再有約，六花飛時湖上行。", "短檠不密泄此意，煇煌粟粟攢金英。", "鬨堂一笑前未睹，信手閒閲燈花經。", "一主飲席設林麓，一主盍簪獲良朋。", "便欲牋天檄滕六，銀盃逐馬快此情。", "曉來喜見萬瓦白，迺是天宇清霜明。", "得非分薄誤燈花，還復燈花戲老兄。"]'),
('ae12a645-c154-4744-b868-9d4f8b44de95','武兄惠藥','陳起','宋','宋诗','song-poetry','','[]','昔人饋藥不敢嘗，未達寒溫良毒旨。',96,'全唐诗/poet.song.202000.json','["昔人饋藥不敢嘗，未達寒溫良毒旨。", "朝來剝啄客問病，寶劑盈奩意何侈。", "便當三咽答殷勤，兒欲先嘗還且止。", "平生結交結以心，豈有鴆人羊叔子。", "多君相濟義薄雲，友道綫絕今振起。", "綠陰庭院趁清和，抖擻精神迎藥喜。"]'),
('f6aec39e-d135-4491-9534-18ecdf9c3a40','秋懷','陳起','宋','宋诗','song-poetry','','[]','又見街頭賣紫茱，老懷擾擾類催租。',32,'全唐诗/poet.song.202000.json','["又見街頭賣紫茱，老懷擾擾類催租。", "客來喜得吳江紙，欲寫新吟一字無。"]'),
('72de0679-2af2-4447-87a5-6a4af66344e8','懷三山友人','陳起','宋','宋诗','song-poetry','','[]','春前深惜別，病後政無詩。',48,'全唐诗/poet.song.202000.json','["春前深惜別，病後政無詩。", "青又生菱角，紅應熟荔枝。", "魚甘賓席暖，風逆客帆遲。", "徒結連宵夢，郵音負所期。"]'),
('b240c5bc-5121-4881-9701-a07b5072b735','寄彭勿菴','陳起','宋','宋诗','song-poetry','','[]','一片巴江月，移輝到庾梅。',24,'全唐诗/poet.song.202000.json','["一片巴江月，移輝到庾梅。", "孤山春事早，疎影望東回。"]'),
('7cfa1f7a-42cc-420b-afa2-2a8f60f944f6','以仁者壽爲韻壽侍讀節使鄭少師  其一','陳起','宋','宋诗','song-poetry','','[]','一氣妙磅礴，萬彙屈者伸。',60,'全唐诗/poet.song.202000.json','["一氣妙磅礴，萬彙屈者伸。", "方寸函太極，宇宙皆吾仁。", "端平改化絃，真儒手洪鈞。", "厥今扶公道，皆昔夾袋人。", "丙午成樂歲，甲午無窮春。"]'),
('1ea64115-92df-44f1-b99c-00d9ca07af65','以仁者壽爲韻壽侍讀節使鄭少師  其二','陳起','宋','宋诗','song-poetry','','["\u897f\u6e56"]','岧嶢閶闔雲，蹀躞誌鞍馬。',60,'全唐诗/poet.song.202000.json','["岧嶢閶闔雲，蹀躞誌鞍馬。", "細氈侍珠旒，治道談帝者。", "歸來西湖濱，岸幘松蓋下。", "秋淥晚涵山，挹以薦殘斝。", "北第何三辭，泉石懷綠野。"]'),
('54790a2a-3f52-4727-9b11-92f6d38186e9','以仁者壽爲韻壽侍讀節使鄭少師  其三','陳起','宋','宋诗','song-poetry','','[]','賦詩投金瀨，俸入猶半有。',60,'全唐诗/poet.song.202000.json','["賦詩投金瀨，俸入猶半有。", "煇煌奉國節，一粟迺不受。", "贏副初何心，國計要豐阜。", "一丸濟世德，陽報期千壽。", "會須煩潞公，再與佐元祐。"]'),
('3101f9df-1464-4df3-8cd8-ebac0e3ce439','枕上','陳起','宋','宋诗','song-poetry','','[]','病與仇謀酒作成，藥爐又復伴深更。',32,'全唐诗/poet.song.202000.json','["病與仇謀酒作成，藥爐又復伴深更。", "鄰鍾自是常時聽，纔到霜天分外清。"]'),
('da7951f9-3534-4a4e-b00a-39eb6de66c16','郭聖與黄希聲問候','陳起','宋','宋诗','song-poetry','','[]','山有靈芽可點金，名醫未遇若爲尋。',64,'全唐诗/poet.song.202000.json','["山有靈芽可點金，名醫未遇若爲尋。", "藥房掩晝情多感，竹榻逢秋老不禁。", "座上遍將唐帖揭，架中閑取晉詩吟。", "病懷得此相料理，更接蘭交問訊音。"]'),
('bfd3e024-233a-45d7-b496-29c558e24450','過三橋懷山臺','陳起','宋','宋诗','song-poetry','','[]','賣花聲裏憑闌處，沽酒樓前對雨時。',32,'全唐诗/poet.song.202000.json','["賣花聲裏憑闌處，沽酒樓前對雨時。", "景物如初人自老，夕陽波上燕差池。"]'),
('8edaef53-9fa6-4986-88c0-fa0af8fdec3e','題玉泉畫像次來軸韻','陳起','宋','宋诗','song-poetry','','[]','鹿隨寒策穿雲，解后靈峰時節。',28,'全唐诗/poet.song.202000.json','["鹿隨寒策穿雲，解后靈峰時節。", "含毫誰貌閑情，莫盡胸中風月。"]'),
('e5daac11-c19c-4600-a3d4-7b48118f5855','奉酬竹溪陳史君新詩墨梅之貺','陳起','宋','宋诗','song-poetry','','[]','千里雙魚賁草堂，中藏瓌異夜騰光。',64,'全唐诗/poet.song.202000.json','["千里雙魚賁草堂，中藏瓌異夜騰光。", "興因東閣增懷想，影落前榮不寄香。", "四韻休誇毛穎伎，幾回曾誤壽陽妝。", "感公意過兼金餽，慚乏瓊琚展報襄。"]'),
('170a31f8-c0c5-45cb-96f1-47a2f4eb433e','壽大丞相安晚先生','陳起','宋','宋诗','song-poetry','','[]','嵯峨補陀山，下視海水流。',168,'全唐诗/poet.song.202000.json','["嵯峨補陀山，下視海水流。", "風波定以梢，穩穩濟川舟。", "皇穹祐炎祚，黍稌慶有秋。", "繄誰致此祥，上相今伊周。", "赫赫命世賢，師道輔前旒。", "暨湯同格天，康濟仰廟謀。", "向來三邊塵，化作和氣游。", "橫戈枕月戍，擊壤歌西疇。", "小春明日是，泰階射斗牛。", "見說老人星，交曜光九州。", "宣勸下紫宸，雕盤羅珍羞。", "北禁詔墨香，昌熾頌魯侯。", "鯫生戴厚恩，一詩何能酬。", "擬辦八千首，從今歲歲投。"]'),
('a7d9681c-c2b4-45b8-ab21-783887bdfb90','紙帳送梅屋小詩戲之','陳起','宋','宋诗','song-poetry','','[]','十幅溪藤皺縠紋，梅花夢裏閟氤氳。',32,'全唐诗/poet.song.202000.json','["十幅溪藤皺縠紋，梅花夢裏閟氤氳。", "裴航莫作瑶臺想，約取希夷共白雲。"]'),
('934a13e9-1112-4254-bf44-8063afebf3dd','迎月','陳起','宋','宋诗','song-poetry','','[]','尊酒貪迎月，人生醉後嘉。',24,'全唐诗/poet.song.202000.json','["尊酒貪迎月，人生醉後嘉。", "夜來窗不掩，吹落一瓶花。"]'),
('0070d958-2d2f-4e9f-8535-c6447f989a16','止酒示圭','陳起','宋','宋诗','song-poetry','','[]','一病杯中物致危，翰林何事酷耽之。',32,'全唐诗/poet.song.202000.json','["一病杯中物致危，翰林何事酷耽之。", "酒經若果通仙道，不向青山立斷碑。"]'),
('34c2ed14-3a89-491b-b6e2-d7aed5aa2269','適安有湖山之招病不果赴','陳起','宋','宋诗','song-poetry','','[]','蘭契簡以詩，金鏗而玉戛。',60,'全唐诗/poet.song.202000.json','["蘭契簡以詩，金鏗而玉戛。", "招邀訪逋仙，劇飲擬投轄。", "事有違人意，十常居七八。", "文園病政濃，況復泥濘滑。", "老懷欲舒散，天心若是恝。"]'),
('58a12957-47ab-42e6-81eb-7d6f38ddbd69','挽梅屋','陳起','宋','宋诗','song-poetry','','[]','桐陰吟社憶當年，別後攀梅結數椽。',64,'全唐诗/poet.song.202000.json','["桐陰吟社憶當年，別後攀梅結數椽。", "湖海有聲推逸韻，弓旌不至歎遺賢。", "兒收殘稿能傳業，自誌平生不愧天。", "航便雙魚無復得，夾山西望淚潺湲。"]'),
('a454b198-c8fc-4439-bc95-c9fd608e6d61','挽林夫人','陳起','宋','宋诗','song-poetry','','[]','懿德遐齡世所尊，濃薰班馬到諸孫。',64,'全唐诗/poet.song.202000.json','["懿德遐齡世所尊，濃薰班馬到諸孫。", "疏榮花誥加宏邑，賜第蘭階侈異恩。", "了了三乘言外趣，如如一性定中存。", "魚軒應向西方去，知在蓮花第幾根。"]'),
('e0f8f1fe-b1ee-481e-89e7-f4d49c8943d7','病中偶成','陳起','宋','宋诗','song-poetry','','[]','平生謹樽酒，投老更齊聖。',84,'全唐诗/poet.song.202000.json','["平生謹樽酒，投老更齊聖。", "優游接嘉賓，能使百憂屏。", "可憐陶士行，飲少亦致病。", "豐下改舊容，浮采滿青鏡。", "升降氣失常，醫經云上盛。", "亟試黄昏湯，要期勿藥慶。", "朝來覺清爽，臨窗發幽詠。"]'),
('3f8cca82-d92b-4460-ac19-039c597ad6ed','薄命','陳起','宋','宋诗','song-poetry','','[]','薄命畏庚金，那逢閹茂臨。',48,'全唐诗/poet.song.202000.json','["薄命畏庚金，那逢閹茂臨。", "一尊花下飲，半載藥邊吟。", "食味同玄酒，形骸類槁林。", "但存元氣在，會見綠成陰。"]'),
('8c625be2-11f4-4ef7-aa7e-e2f2e6c032c0','消遣','陳起','宋','宋诗','song-poetry','','[]','夜雨生寒換夾衣，形臞貌悴歎衰遲。',32,'全唐诗/poet.song.202000.json','["夜雨生寒換夾衣，形臞貌悴歎衰遲。", "病中何物能消遣，一榻揩摩十載詩。"]'),
('46f9d02d-373f-4e59-bb43-940337b9a828','題西窗食芹稿','陳起','宋','宋诗','song-poetry','','[]','曾味西窗稿，經年齒頰清。',24,'全唐诗/poet.song.202000.json','["曾味西窗稿，經年齒頰清。", "細評何物似，碧澗一盃羹。"]'),
('2f0bd6d7-2773-4ddf-8bed-8cf86db64c0b','一念','陳起','宋','宋诗','song-poetry','','[]','一念無塵雜，三更有夢回。',24,'全唐诗/poet.song.202000.json','["一念無塵雜，三更有夢回。", "同他石橋老，過水探寒梅。"]'),
('6a4464f2-0fa5-47df-8238-ea23c067c846','買花','陳起','宋','宋诗','song-poetry','','[]','今早神清覺步輕，杖藜聊復到前庭。',32,'全唐诗/poet.song.202000.json','["今早神清覺步輕，杖藜聊復到前庭。", "市聲亦有關情處，買得秋花插小瓶。"]'),
('493b610d-e461-4882-b943-a7f1eaabe1da','一榻','陳起','宋','宋诗','song-poetry','','[]','一榻世緣輕，毋將事物縈。',24,'全唐诗/poet.song.202000.json','["一榻世緣輕，毋將事物縈。", "昔人言豈誤，慧自靜中生。"]'),
('b89bd3ae-a625-4dd0-bb5f-7ba6815b2548','同清兄看猿','陳起','宋','宋诗','song-poetry','','[]','藜杖同僧扣，譍門野叟閑。',24,'全唐诗/poet.song.202000.json','["藜杖同僧扣，譍門野叟閑。", "放他猿摘果，莫把白雲關。"]'),
('89aea5c7-e414-4795-afa6-a04dac0d2512','薄暮','陳起','宋','宋诗','song-poetry','','[]','寂寥誰作侶，耿耿一寒釭。',24,'全唐诗/poet.song.202000.json','["寂寥誰作侶，耿耿一寒釭。", "薄暮西風急，呼童掩却窗。"]'),
('37b86986-6bfc-478e-a79e-d299afd46784','秋夜懷康節','陳起','宋','宋诗','song-poetry','','[]','無眠輾轉聽更殘，心緒如絲起萬端。',64,'全唐诗/poet.song.202000.json','["無眠輾轉聽更殘，心緒如絲起萬端。", "煎藥爐邊童夢曉，讀書檠下婦紉寒。", "狻猊斷火香猶婉，促織催秋袂怯單。", "願子大賢康節語，此情於我一般般。"]'),
('d5b9b065-14ab-46a9-bdc3-091fe2423d96','冷泉凭欄','陳起','宋','宋诗','song-poetry','','[]','此山泉石勝，還思日日登。',24,'全唐诗/poet.song.202000.json','["此山泉石勝，還思日日登。", "那知三生前，不是住山僧。"]'),
('55f3fd1f-d347-4e27-9f21-5d0b2a2f4cc6','冷泉解后友人留飲','陳起','宋','宋诗','song-poetry','','[]','倦叟尋芳藉短筇，故人解后一尊同。',64,'全唐诗/poet.song.202000.json','["倦叟尋芳藉短筇，故人解后一尊同。", "明霞浸水疑鋪錦，彩閣橫溪儼卧虹。", "猿去復歸啼曉嶂，僧來相伴立春風。", "雪濤湍激開寒閘，滌盡塵襟萬慮空。"]'),
('54a04fb6-33b9-460b-9989-80ed24387b51','黄路鈐詩來告別','陳起','宋','宋诗','song-poetry','','[]','玉泉馳一紙，八韻有情詩。',48,'全唐诗/poet.song.202000.json','["玉泉馳一紙，八韻有情詩。", "不肯面相別，恐成離索悲。", "江聲噴岸坼，潮勢激帆危。", "舊制邊州守，方令典轄司。"]'),
('2bc60680-87a8-4d30-ac4a-01c6232464bc','適安招遊湯鎮不果赴','陳起','宋','宋诗','song-poetry','','[]','湯鎮古祠宮，招邀及倦翁。',48,'全唐诗/poet.song.202000.json','["湯鎮古祠宮，招邀及倦翁。", "輕裘乘曉月，駿馬逐東風。", "野色觀無分，春光病見攻。", "行將迎誕日，一瓣擬遥通。"]'),
('bed483f0-46b8-4816-a414-f1d1558c0252','寄東齋','陳起','宋','宋诗','song-poetry','','[]','又復逢初度，尪羸異昔時。',48,'全唐诗/poet.song.202000.json','["又復逢初度，尪羸異昔時。", "預愁臨丙戌，所願值天醫。", "翦綵裝茶果，裁牋薦壽卮。", "今年都告免，湯餠却相宜。"]'),
('c1065af2-03c3-4d4f-9289-b610d9a10346','寒吹','陳起','宋','宋诗','song-poetry','','[]','寒吹西軒入，罘罳設座隅。',48,'全唐诗/poet.song.202000.json','["寒吹西軒入，罘罳設座隅。", "腰圍同沈約，指爪類麻姑。", "靜卧氈三疊，清齋飯一盂。", "曉來香滿室，巖桂侈缾鑪。"]'),
('97411f5f-b2c2-47c9-bdfb-fa39419c18c0','適安夜訪讀靜佳詩卷','陳起','宋','宋诗','song-poetry','','[]','情同義合亦前緣，得此蘭交慰晚年。',64,'全唐诗/poet.song.202000.json','["情同義合亦前緣，得此蘭交慰晚年。", "旋爇古香延夜月，試他新茗瀹秋泉。", "君停逸駕談何爽，客寄吟編句極圓。", "可惜病翁初止酒，不能共醉桂花前。"]'),
('b0cc820c-dedc-4e10-aa75-288b71b1414e','所適','陳起','宋','宋诗','song-poetry','','[]','釣鼇東海頭，經春醉一舟。',24,'全唐诗/poet.song.202000.json','["釣鼇東海頭，經春醉一舟。", "西溪拗罾人，小鮮終日求。"]'),
('fdd6b766-3d53-4f1d-a5d8-b9cd2849e11e','庚戌秋作','陳起','宋','宋诗','song-poetry','','[]','甲辰迤邐至今年，藥竈殊勞日夕煎。',32,'全唐诗/poet.song.202000.json','["甲辰迤邐至今年，藥竈殊勞日夕煎。", "血氣任他銷與鑠，向來詩骨已成仙。"]'),
('97eaab85-47ad-4cbd-b203-abc791c64fb2','耘業許印章四韻叩之','陳起','宋','宋诗','song-poetry','','[]','近因稚子傳來意，知許衰翁兩印章。',64,'全唐诗/poet.song.202000.json','["近因稚子傳來意，知許衰翁兩印章。", "字畫莫教凡手刻，形模當取古人長。", "六書今獨行秦嶧，三體空聞設漢庠。", "後世陽冰能復古，未知何日寄文房。"]'),
('715c7f45-0330-49d6-9615-8e2dfc397754','婚嫁','陳起','宋','宋诗','song-poetry','','[]','婚嫁債羈縻，何時是了期。',48,'全唐诗/poet.song.202000.json','["婚嫁債羈縻，何時是了期。", "每嗟身外累，無出女和兒。", "聽漏寒無夢，添香夜有詩。", "沈沈澄萬境，梅影月初移。"]'),
('b01651ee-c6c8-425a-af65-c139c00597c3','六言簡耘業','陳起','宋','宋诗','song-poetry','','[]','露濕螢光愈熾，月斜蛩韻尤清。',28,'全唐诗/poet.song.202000.json','["露濕螢光愈熾，月斜蛩韻尤清。", "微物得時若此，人生可不求名。"]'),
('1742f933-b533-4492-8cb3-27667d3bd8be','束起','陳起','宋','宋诗','song-poetry','','[]','束起仙翁肘後經，且參思邈枕中吟。',32,'全唐诗/poet.song.202000.json','["束起仙翁肘後經，且參思邈枕中吟。", "夜來獨卧寒無寐，憶殺黄紬舊破衾。"]'),
('364a643e-6094-4956-a6ff-78dfc88b5970','聞鄰寺粥','陳起','宋','宋诗','song-poetry','','[]','寒釭旋擿動冥搜，泓玉摩研萬象愁。',64,'全唐诗/poet.song.202000.json','["寒釭旋擿動冥搜，泓玉摩研萬象愁。", "鐵版響廊催早粥，銅壺添水易新籌。", "一聲雞唱驚殘夢，再聽鴉羣過小樓。", "可惜秋光帷帟隔，料應河漢五更收。"]'),
('b043bcd4-c0e9-4745-9658-c136c946cc5b','汪夫人筵上口號','陳起','宋','宋诗','song-poetry','','[]','今朝王母讌西池，葱蒨祥煙靄繡帷。',64,'全唐诗/poet.song.202000.json','["今朝王母讌西池，葱蒨祥煙靄繡帷。", "坐摘蟠桃華壽席，行看丹桂發孫枝。", "魚軒錦轂花千疊，鸞誥金鈴絡四垂。", "好是殷勤千歲祝，老萊先酌後門楣。"]'),
('412e0baf-c809-4f9d-a8b5-99f423ca0ff2','翛然','陳起','宋','宋诗','song-poetry','','[]','向來蓮社本遺榮，勾引淵明造道場。',64,'全唐诗/poet.song.202000.json','["向來蓮社本遺榮，勾引淵明造道場。", "梵葉翻殘空佛印，念珠持久現圓光。", "秋花依約生凉意，暑雨微茫送夕陽。", "客退飯餘無箇事，翛然一枕到羲皇。"]'),
('ee7f5509-9091-4f2c-92a7-73ca0fcb9e8d','風雨作','陳起','宋','宋诗','song-poetry','','[]','無成老見過，望望太平歌。',48,'全唐诗/poet.song.202000.json','["無成老見過，望望太平歌。", "驚雨愁扃戶，聞風慮偃禾。", "杯中醇止久，瓶底粟無多。", "畎畝憂時切，天乎少警何。"]'),
('e2bd17aa-f895-48da-b371-05baf83278e3','葵窗送酒','陳起','宋','宋诗','song-poetry','','[]','久藏斗酒謀諸婦，婢子倉皇錯授醯。',32,'全唐诗/poet.song.202000.json','["久藏斗酒謀諸婦，婢子倉皇錯授醯。", "解后芸居初止酒，小厨海錯旋開泥。"]'),
('05709a3b-0598-4eb8-9cc6-1e7290adac06','望曉','陳起','宋','宋诗','song-poetry','','[]','要知筋力衰多少，一覺纔回常了了。',32,'全唐诗/poet.song.202000.json','["要知筋力衰多少，一覺纔回常了了。", "鄰鐘無奈五更何，望斷窗紗不能曉。"]'),
('c2ae3ef5-306f-4756-b2b4-8fc34bac2a50','湖上即事','陳起','宋','宋诗','song-poetry','','[]','波光山色兩盈盈，短策青鞋信意行。',64,'全唐诗/poet.song.202000.json','["波光山色兩盈盈，短策青鞋信意行。", "葑草煙開遥認鷺，柳條春早未藏鶑。", "誰家豔飲歌初歇，有客孤舟笛再橫。", "風景無窮吟莫盡，且將酩酊樂浮生。"]'),
('74b3bc48-a2ff-42fd-b33a-14c26ea16345','朝宗餽食且復招飲','陳起','宋','宋诗','song-poetry','','[]','相親逾骨肉，何以結情深。',48,'全唐诗/poet.song.202000.json','["相親逾骨肉，何以結情深。", "下箸覺可口，同盤還上心。", "撥灰君句就，曝背我寒侵。", "屢有梅窗約，行將共晚斟。"]'),
('4c654648-d605-48c2-a1c3-64a031f9444a','送印寒鄧簿得闕西歸','陳起','宋','宋诗','song-poetry','','[]','才藻世於家，勾朱新職華。',48,'全唐诗/poet.song.202000.json','["才藻世於家，勾朱新職華。", "學能如藝木，春到可生花。", "野店寒吟月，輕裝曉度沙。", "君行余止酒，一念一興嗟。"]'),
('40e0ad51-80aa-4ead-9f47-f05a64eaf386','圭示急須制作亭當喜成一絕','陳起','宋','宋诗','song-poetry','','[]','博古圖中無此樣，繄誰匠意巧胚胎。',32,'全唐诗/poet.song.202000.json','["博古圖中無此樣，繄誰匠意巧胚胎。", "槐堂新送黄封酒，便可衝寒暖一杯。"]'),
('17e5f56c-fee8-4826-b0a6-847c5e015989','梅花怨爲汪耘業賦','陳起','宋','宋诗','song-poetry','','[]','崢嶸歲事春將至，寂寞梅花雪失期。',32,'全唐诗/poet.song.202000.json','["崢嶸歲事春將至，寂寞梅花雪失期。", "獨有垂楊伴幽怨，豈堪臨水折長枝。"]'),
('776ad882-d677-458b-a0de-928f115225d9','舊題隠者壁一絕','陳起','宋','宋诗','song-poetry','','[]','妻嗔山犬踐園蔬，兒釣溪魚餧鶴雛。',32,'全唐诗/poet.song.202000.json','["妻嗔山犬踐園蔬，兒釣溪魚餧鶴雛。", "總道村居無外事，有人庭下索詩逋。"]'),
('1d0481bc-f48c-4e32-a960-ebdd31e502da','酬成賢良','陳起','宋','宋诗','song-poetry','','[]','獻璞無成喜弄璋，世間得失事相參。',32,'全唐诗/poet.song.202000.json','["獻璞無成喜弄璋，世間得失事相參。", "劉蕡不得言時事，半爲當時記樸菴。"]'),
('faeb094f-6029-413b-bff3-4abaa23772f6','同友人汎舟過斷橋登壽星江湖偉觀歸舟聽客謳清真詞意甚適分得江字奉寄季大著鄉執兼呈真靜先生','陳起','宋','宋诗','song-poetry','','["\u897f\u6e56"]','辛亥仲春將徂兮，有客踵門曰風日流麗，邀余共泛西湖之舽。',298,'全唐诗/poet.song.202000.json','["辛亥仲春將徂兮，有客踵門曰風日流麗，邀余共泛西湖之舽。", "伋南去而忽西兮，昨之折檻今復飾以成杠。", "背蘇堤萬絲之綠陰兮，望一簇孤山之青橦。", "層峰疊嶂巉絕露天巧，珠英琪樹發越地之靈，一聲何處兮鐘撞。", "篙師告余曰，此壽星古剎。", "上有奇觀，開宇宙於八窗。", "捨舟策杖，步步巍峩，謝屐殊勞雙。", "回廊曲轉忽軒豁，檐飛棟複，青綠交輝。", "心開目駭，而揖西子之湖，子胥之江。", "觀者雜遝，儵去儵來。", "余獨凭欄，境與心會，便欲馭風跨蜿虹。", "煙雲萬態，客擬狀而運思，羿今老退，且遜銳逄。", "莊嚴世界，合爪讚歎。", "要使天下名山夸詠者，睹此奇偉而心降。", "風寒下山吹欲倒，連呼春酒亟開缸。", "簫鼓畫船徒自紛耳目，何如美成清絕按新腔。", "詩成肯對俗子哦，馳介城南寄老龐。"]'),
('09aabf39-d5b3-474d-abb5-190670fdc47c','舊挽汪隠君  其一','陳起','宋','宋诗','song-poetry','','[]','棲志浮雲小萬鍾，带經高壟度春風。',32,'全唐诗/poet.song.202000.json','["棲志浮雲小萬鍾，带經高壟度春風。", "義方莫問當年事，十五男兒識阿戎。"]'),
('10aa40bc-5058-4606-a21c-908ab2ae23ad','舊挽汪隠君  其二','陳起','宋','宋诗','song-poetry','','[]','遺碣鑽辭掩夜臺，脩文空歎逞餘才。',32,'全唐诗/poet.song.202000.json','["遺碣鑽辭掩夜臺，脩文空歎逞餘才。", "鹿坡明月成惆悵，不見高人自往來。"]'),
('3a4da3ac-9705-4fa7-a7b0-4fb5a469c139','靜江商宰書來且索鄙語要道其冰雪相看之意古調代書','陳起','宋','宋诗','song-poetry','','[]','連牆不通問，千里迺寄音。',132,'全唐诗/poet.song.202000.json','["連牆不通問，千里迺寄音。", "平生於締交，淡泊味最深。", "吳山青插天，應同碧玉簪。", "尚憐風馬牛，暌若商與參。", "一聲南來鴈，西風又相尋。", "君其念衰朽，余亦懷瑶林。", "一廉了官事，吟外時鳴琴。", "識量萬頃陂，文華實南金。", "向來唐相璟，疑事問崔琳。", "諸臺貴得賢，而肯捨此琛。", "會晤喜有期，寬此離索襟。"]'),
('0bbe1acb-d0db-42f8-8319-e1a7fc50030d','安晚先生送自贊太上感應篇帙首御題諸惡莫作衆善奉行八字輔以佑聖像一軸兩詩見意云  其一','陳起','宋','宋诗','song-poetry','','[]','公衮殊相念，奇書寄布衣。',48,'全唐诗/poet.song.202000.json','["公衮殊相念，奇書寄布衣。", "此心纔動處，萬善要同歸。", "本旨詳敷衍，奎題重發揮。", "應憐蘧伯玉，投老始知非。"]'),
('47ce9a74-6e97-4b64-978a-63af589966c2','安晚先生送自贊太上感應篇帙首御題諸惡莫作衆善奉行八字輔以佑聖像一軸兩詩見意云  其二','陳起','宋','宋诗','song-poetry','','[]','稽首玄真像，當年助我軍。',48,'全唐诗/poet.song.202000.json','["稽首玄真像，當年助我軍。", "龜蛇裨聖武，龍鳳煥奎文。", "劍聳燒空焰，旗翻渡海雲。", "上公傳琬琰，分惠感慇懃。"]'),
('d8c8bd70-a228-4b64-a7e9-5ec5d3a2e8f1','雜言送歙研廣香與友人有懷楊校書幼度','陳起','宋','宋诗','song-poetry','','[]','我有龍尾雙槽之研，肌潤而若沐空濛。',100,'全唐诗/poet.song.202000.json','["我有龍尾雙槽之研，肌潤而若沐空濛。", "舊藏古香氤氳，來自廣之東。", "多君博雅，舉以爲贈，三嗅而抹月批風。", "要若鎔金加萬佛經上，更須滴露點四聖書中。", "往昔濃薰懷太史，而今一瓣爲南豐。", "藜光下照人何在，閤下閑花馥舊叢。"]'),
('77428c6b-fabc-46cd-8e2c-9c15c1a8b754','真靜饋新茶菰乾黄獨乳酪約葵窗適安共享適安不赴葵窗詩來道謝次韻答之兼呈真靜適安','陳起','宋','宋诗','song-poetry','','[]','千載靖節翁，秫向公田種。',204,'全唐诗/poet.song.202000.json','["千載靖節翁，秫向公田種。", "萬鍾於我何，肯戀五斗俸。", "長歌歸去來，田園聊自奉。", "高蹈世莫儔，器局小管仲。", "嗟余昧於時，退思心每痛。", "世人不我知，小畦親抱甕。", "唯有竹宮仙，時復致一供。", "四清山中珍，凡目爲之動。", "黄獨前未識，勿誚仲宣憃。", "春茗摘新芽，秋菰懷舊葑。", "江南貴乳酪，此意兼金重。", "得君同下箸，詩來再三諷。", "韻意兩相高，文史歎足用。", "續貂愧狗尾，敢與賢者共。", "語奚較工拙，年來此心縱。", "軟飽黑甜餘，無復春草夢。", "可人招不來，屬篇亟持送。"]'),
('9692dfcf-c9cb-4c63-8620-9962d57e8253','哭丹池王隠君','陳起','宋','宋诗','song-poetry','','[]','憶昔相逢初，一見即刮目。',168,'全唐诗/poet.song.202000.json','["憶昔相逢初，一見即刮目。", "出處雖不齊，椒蘭則同馥。", "論心到極處，情愛逾骨肉。", "十年傳成癖，搰搰閉門讀。", "高志尊所傳，而肯曲從俗。", "抱此奇特操，平步可金玉。", "況復同窗友，槐庭秉鈞軸。", "事有反所料，軒冕笑羈束。", "縉雲邈千里，訪道求辟穀。", "食棗懷安期，竊桃小方朔。", "平生精進心，自可登仙錄。", "一著偶失算，九書無復續。", "洞霄有猿號，丹池無鶴浴。", "昨病失會葬，生芻東望哭。"]'),
('39ce315e-5118-4e3a-bff1-fcbe254f989b','寄汪起潛簽判','陳起','宋','宋诗','song-poetry','','[]','飛雲起伏龍，大鵬運以風。',108,'全唐诗/poet.song.202000.json','["飛雲起伏龍，大鵬運以風。", "風雲一朝會，前塞今迺通。", "斂翼賢景略，時哉使其逢。", "腰錢與騎鶴，事或有適同。", "青門瓜吹香，綠水蓮泛紅。", "人物王謝家，風雅眼底空。", "參畫聳臺府，宜護碧紗籠。", "鄱江萬折東，獨鶚摩蒼穹。", "浮圖快一擲，歸騎先賓鴻。"]'),
('a5156666-c8af-4879-b27a-dda015577cb8','史記送後村劉秘監兼致欲見之悰','陳起','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昏聵嗟耳目，管絃堂上調。',132,'全唐诗/poet.song.202000.json','["昏聵嗟耳目，管絃堂上調。", "世事每相背，秋月虛良宵。", "涓吉擬登龍，疾雨驚風飄。", "禰刺不得前，東睇心旌遥。", "近履傳康强，變體筆更饒。", "風響雖時接，未若親聞韶。", "憶昔西湖濱，別語請教條。", "囑以馬遷史，文貴細字彫。", "名言猶在耳，堤柳凡幾凋。", "茲焉得蜀刻，持贈踐久要。", "會晤知何時，霽色審來朝。"]'),
('5231d5a0-4ea4-49fc-aeb6-3560c7d9d80a','題建溪劉希和吟趣園','陳起','宋','宋诗','song-poetry','','[]','佳氣滿吳洲，琅琅謫仙句。',96,'全唐诗/poet.song.202000.json','["佳氣滿吳洲，琅琅謫仙句。", "當其傲雲月，風流良可慕。", "寂寥數百載，何人踵逸步。", "建溪有劉侯，於吟契其趣。", "是知建與吳，妙處同一悟。", "水石巧縈紆，烟雲互吞吐。", "花光時變眩，山色無旦暮。", "物物可供吟，先爲梅花賦。"]'),
('2927f97f-8b77-4474-995f-3a068187bf79','趙紫芝運幹','陳起','宋','宋诗','song-poetry','','[]','陋室與高門，東西互接畛。',72,'全唐诗/poet.song.202000.json','["陋室與高門，東西互接畛。", "相聚雖不稠，相別殊難忍。", "風帆去程遥，到時秋未盡。", "少試裨畫材，計臺作標準。", "恨無雙羽翔，汩汩成蠹隠。", "便結南浦夢，獨立江風緊。"]'),
('030915bc-e121-4bf6-8a9b-e80d90cd93d2','芸隠提管詩來依韵奉答  其一','陳起','宋','宋诗','song-poetry','','[]','君詩如梅花，將盡春意函。',48,'全唐诗/poet.song.202000.json','["君詩如梅花，將盡春意函。", "一枝漏泄處，踏雪寒曾諳。", "肯踐桃李場，溪山還自甘。", "破玉暗香度，似親夷甫談。"]'),
('a9cb0fc2-07f5-4747-a05b-13c8289cf170','芸隠提管詩來依韵奉答  其二','陳起','宋','宋诗','song-poetry','','[]','我詩如折桐，經霜爲一空。',48,'全唐诗/poet.song.202000.json','["我詩如折桐，經霜爲一空。", "尚可親時髦，託根日華宮。", "莫謂背於時，會在春風中。", "小雨灑清明，又是一番紅。"]'),
('5fd1560d-7d38-43c8-89e4-d3762fbefa6e','芸隠再和復用以酬  其一','陳起','宋','宋诗','song-poetry','','[]','大藏五千卷，齋沐啟寶函。',48,'全唐诗/poet.song.202000.json','["大藏五千卷，齋沐啟寶函。", "强名禪教律，心了一一諳。", "向來曾乞食，此味醍醐甘。", "拈花飲先笑，意會不待談。"]'),
('e2f34b27-1fa8-4d04-86a6-83fe8f65f3ac','芸隠再和復用以酬  其二','陳起','宋','宋诗','song-poetry','','[]','芸隠抱奇偉，未可論苦空。',48,'全唐诗/poet.song.202000.json','["芸隠抱奇偉，未可論苦空。", "吾皇樂詢道，日御賦政宮。", "會看召嚴徐，敷奏陛殿中。", "鳴靴踏龍尾，豈久蓮依紅。"]'),
('f0f02fb5-e363-48cc-a4e7-a4c91b17c6e3','送別曾幼廣赴漕試歸','陳起','宋','宋诗','song-poetry','','[]','疋馬來東吳，策勳在一戰。',60,'全唐诗/poet.song.202000.json','["疋馬來東吳，策勳在一戰。", "文場老燕代，餘子自北面。", "西風敲鐙歸，山應過處戀。", "英氣凜橫槊，河海能幾見。", "自識韓將軍，論交今惓惓。"]'),
('72f131f0-adf5-4642-a9be-aab34f906374','洪扇贈別芮通父','陳起','宋','宋诗','song-poetry','','[]','春冰幕千絲，我箑美無度。',96,'全唐诗/poet.song.202000.json','["春冰幕千絲，我箑美無度。", "習習南浦秋，受藏憶襲護。", "之子思吳鱗，觸熱遥問津。", "舉箑寄薄劣，却暑兼障塵。", "荆榛道崎嶇，輕車宜徐徐。", "戴星秣驪駒，未午投林廬。", "酌月重來期，名言毋重違。", "自嗟君是客，忍賦別離詩。"]'),
('6b3f907e-bad2-4dd0-ab95-c254a7251d6d','送賀某赴興化任  其一','陳起','宋','宋诗','song-poetry','','[]','賀公夢三刀，恩榮被詔函。',48,'全唐诗/poet.song.202000.json','["賀公夢三刀，恩榮被詔函。", "家山繄比隣，風俗應夙諳。", "承流復宣化，使民思棠甘。", "向來愷悌心，今足副時談。"]'),
('278b3a80-085d-4543-a57d-83ae15ba7180','送賀某赴興化任  其二','陳起','宋','宋诗','song-poetry','','[]','壺山邈千里，旌旗拂摇空。',48,'全唐诗/poet.song.202000.json','["壺山邈千里，旌旗拂摇空。", "是邦足文物，教宜先泮宮。", "嗟余病十載，置身藥裹中。", "追送不能遠，望望晝錦紅。"]'),
('d0b392e9-58a6-43cd-84d0-eebed7427ce9','呈朱叢瑞','陳起','宋','宋诗','song-poetry','','[]','囊中五色絲，擬將舜裳補。',60,'全唐诗/poet.song.202000.json','["囊中五色絲，擬將舜裳補。", "玉階遠於天，莫睹干戚舞。", "治朝足文物，一室自規矩。", "少賤人或欺，黔婁况貧窶。", "毋作飯牛歌，春滋夜來雨。"]'),
('08b4afc1-5974-4dd4-a87a-f84acdfa0728','寄題當湖隠淥亭','陳起','宋','宋诗','song-poetry','','[]','曲逕一亭幽，三十六水聚。',48,'全唐诗/poet.song.202000.json','["曲逕一亭幽，三十六水聚。", "簷影接波光，蟬聲入秋思。", "開薸靜看雲，愛月懶種樹。", "濠上意如何，疎鍾烟外寺。"]'),
('0f01257a-d3ba-4b66-954e-48a06fe51695','對菊有懷東園','陳起','宋','宋诗','song-poetry','','["\u897f\u6e56"]','青女凌波楚江冷，庭前一葉鳴金井。',96,'全唐诗/poet.song.202000.json','["青女凌波楚江冷，庭前一葉鳴金井。", "砧杵誰家試夾衣，西風攪碎蘆花影。", "呼童折取籬下金，旋汲山泉注古缾。", "細哦七字延秋色，寒香似欠東園清。", "江上子牟懷魏闕，離情一動腸千結。", "急呼斗酒破霜螯，楚月不礙西湖月。"]'),
('2dd6878d-adf0-4eca-b622-c60d27327679','答熟庵','陳起','宋','宋诗','song-poetry','','[]','昨宵約月臨西池，冰蟾不至鶉火飛。',160,'全唐诗/poet.song.202000.json','["昨宵約月臨西池，冰蟾不至鶉火飛。", "歸來一室白於晝，乃是新詩光陸離。", "當年應剖瓊蚌腹，不然何以明於燭。", "細窺字字欲走盤，三復庵名悟圓熟。", "一片情田萬古耕，有年能得幾書經。", "小疵終是未全稔，孰若先生耨穫精。", "南窗寄傲遂初欲，移石畦蘭更紉菊。", "茶烟細雜玉爐沉，研影凈涵金井淥。", "林下今纔見一人，却疑圖任思舊臣。", "自昔東山豈終隠，似聞鸞詔下蒼旻。"]'),
('590df318-d121-4055-bfc0-733afb1d66a3','送郭聖與就監試歸兼簡其弟','陳起','宋','宋诗','song-poetry','','[]','楚尾吳頭月光冷，山鳥不鳴桂浮影。',128,'全唐诗/poet.song.202000.json','["楚尾吳頭月光冷，山鳥不鳴桂浮影。", "破霜採得蟾邊香，蘭菊無言秋耿耿。", "萬年枝外淺紅牆，胥山小閣憇晚凉。", "湖波江浪座中接，寒篝凝夢歌雲觴。", "明朝忙踏槐花市，萬丈光芒生璧水。", "瓜金繭紙市相高，兀兀鉤提笑韓子。", "小雁汀沙振寒羽，亦復搴衣告歸去。", "近別難甚况遠離，一日仙舟隔輕霧。"]'),
('4187fb0c-2d32-4696-84e0-8a829073cad5','信步','陳起','宋','宋诗','song-poetry','','[]','信步過高崗，隨僧到上方。',48,'全唐诗/poet.song.202000.json','["信步過高崗，隨僧到上方。", "泉浸松逕潤，風出稻畦薌。", "地險人誰問，山深屋亦藏。", "惜無碑可考，創立自南唐。"]'),
('55de49a4-13c5-4a17-9f5a-dbf95bed3bc6','三遊錢園併題四時畫圖','陳起','宋','宋诗','song-poetry','','[]','只因閒未得，又慕得閒名。',48,'全唐诗/poet.song.202000.json','["只因閒未得，又慕得閒名。", "一幅無盡態，四時有餘情。", "吟清招鶴伴，機熟付鷗盟。", "坐久不知晚，前汀烟水橫。"]'),
('8cc793e0-05c3-4d92-a819-478569314238','遊禹廟','陳起','宋','宋诗','song-poetry','','[]','何期來此地，重謁告成祠。',48,'全唐诗/poet.song.202000.json','["何期來此地，重謁告成祠。", "菲飲泉堪酌，桐棺事莫知。", "蟾分丹桂影，龍矯老松枝。", "拂石尋遺字，苔荒大業碑。"]'),
('d0b4fb96-c19c-425e-9d03-09ac9ac14a11','雪中送黄希聲西歸','陳起','宋','宋诗','song-poetry','','[]','可是歸心急，行裝冒雪天。',48,'全唐诗/poet.song.202000.json','["可是歸心急，行裝冒雪天。", "向來期重任，未可羨先鞭。", "人事虧盈月，烟波遠近船。", "明時困英特，此別又三年。"]'),
('d9d62c1b-7059-4840-a8f1-0ebdbb20265b','蘭亭歸途','陳起','宋','宋诗','song-poetry','','[]','山水佳如此，都忘客路難。',48,'全唐诗/poet.song.202000.json','["山水佳如此，都忘客路難。", "鷗明寒渚浄，鴈入野田寬。", "事久人多厭，心清夢却安。", "獨憐鸞翼遠，誰念篋衣單。"]'),
('f539ab33-d32f-4fe4-853a-bd22b7a7f05a','還劉雪坡詞藁','陳起','宋','宋诗','song-poetry','','[]','誰與分天巧，裁成雲錦裳。',48,'全唐诗/poet.song.202000.json','["誰與分天巧，裁成雲錦裳。", "春花籠淡月，秋水照斜陽。", "得句皆奇偉，知音盡老蒼。", "尚期京國路，相與較宮商。"]'),
('c7cf32ac-6926-411b-a644-b5d328f5c2fe','嘉平旦雪  其一','陳起','宋','宋诗','song-poetry','','[]','天欲做奇事，清寒發化機。',48,'全唐诗/poet.song.202000.json','["天欲做奇事，清寒發化機。", "一雲無不覆，萬物盡同輝。", "水合漁烟暝，山空獵火微。", "夜窗歌七月，三歎及無衣。"]'),
('d348138a-715a-4342-9031-8d439cd5f4fb','嘉平旦雪  其二','陳起','宋','宋诗','song-poetry','','[]','天一孕真精，裁成六出霙。',48,'全唐诗/poet.song.202000.json','["天一孕真精，裁成六出霙。", "大聲聞竹折，空色助梅清。", "節壯氈甘囓，兵奇鶩自驚。", "男兒須事業，謾說剡舟明。"]'),
('2725c88e-d41f-40a6-8133-a48c0e635a01','答趙章泉','陳起','宋','宋诗','song-poetry','','[]','新詩將遠意，千里附文鱗。',48,'全唐诗/poet.song.202000.json','["新詩將遠意，千里附文鱗。", "清響蟬噓露，高閒鶴卧雲。", "但知耕野水，不暇問朝紳。", "賸欲陪顔笑，凄凉吳楚分。"]'),
('ad37cf72-22ba-4623-8a4d-c41f7eecd2b3','借居值雪','陳起','宋','宋诗','song-poetry','','["\u897f\u6e56"]','已歎長安索米難，可禁風雪滿長安。',64,'全唐诗/poet.song.202000.json','["已歎長安索米難，可禁風雪滿長安。", "無家又是於人借，有命從來只自寬。", "春入園林根覺煖，色連天地眼生寒。", "西湖寂寞梅無伴，合向孤山忍凍看。"]'),
('36568b7b-c9cf-4ea7-91e7-c858d338ba24','夜聽誦太極西銘','陳起','宋','宋诗','song-poetry','','[]','六經宇宙包無際，消得斯文一貫穿。',64,'全唐诗/poet.song.202000.json','["六經宇宙包無際，消得斯文一貫穿。", "萬水混茫潮約海，三辰煥爛斗分天。", "鳶魚察理河洛後，金玉追章秦漢前。", "遥夜並聽仍闇味，奎明誰敢第三篇。"]'),
('928cb16e-65b4-4bd1-8b90-c659f2202a47','挽宣教郎新差通判慶元府王琮','陳起','宋','宋诗','song-poetry','','[]','前月相過了無恙，小窗畫卷手親開。',64,'全唐诗/poet.song.202000.json','["前月相過了無恙，小窗畫卷手親開。", "不知翁作仙遊去，忽見兒封壙記來。", "寂寂芸居香不斷，悽悽松塢韻堪哀。", "客中爲灑秋風淚，尚想吟魂遶夜臺。"]'),
('02703cda-19a7-4b8e-b16f-0bd850db1298','謁陽明洞天','陳起','宋','宋诗','song-poetry','','[]','羈游何事復來東，豈是三生太史公。',64,'全唐诗/poet.song.202000.json','["羈游何事復來東，豈是三生太史公。", "舞鶴臺空丹蛻井，見龍壇古瑞名宮。", "石帆酒甕遺秦蹟，玉簡金書閟禹功。", "萬壑松風秋愈壯，直將幽意問穹隆。"]'),
('3c13015d-ef4b-4fa8-b810-0b4e931cc506','雪後','陳起','宋','宋诗','song-poetry','','[]','青山當戶牖，雪後非吾有。',24,'全唐诗/poet.song.202000.json','["青山當戶牖，雪後非吾有。", "爲問謝家池，綠波還在否。"]'),
('f9ab98fc-2904-413c-846c-a8890629e99c','雪中三絕  其一','陳起','宋','宋诗','song-poetry','','[]','一天和氣到柴門，檻內蘭芽也玉溫。',32,'全唐诗/poet.song.202000.json','["一天和氣到柴門，檻內蘭芽也玉溫。", "靜炷衙香誰與伴，慈悲大士共黄昏。"]'),
('e967f08b-7e00-47aa-b144-cbcd0609b1d0','雪中三絕  其二','陳起','宋','宋诗','song-poetry','','[]','探梅又復負前盟，曾念霜風病不禁。',32,'全唐诗/poet.song.202000.json','["探梅又復負前盟，曾念霜風病不禁。", "清曉擔頭和雪買，數枝親插供觀音。"]'),
('fe958dff-dc0a-478e-bc92-f7289bcab1d3','雪中三絕  其三','陳起','宋','宋诗','song-poetry','','[]','可憐切切度衆生，千百年來魄尚靈。',32,'全唐诗/poet.song.202000.json','["可憐切切度衆生，千百年來魄尚靈。", "自幼歸依今老矣，濯雲曉汲薦清泠。"]'),
('2dbb6a93-7b5f-4873-971e-c478d67db1bf','曉寒即事','陳起','宋','宋诗','song-poetry','','[]','芳意迢迢客夢閒，亂紅飛盡曉泥乾。',32,'全唐诗/poet.song.202000.json','["芳意迢迢客夢閒，亂紅飛盡曉泥乾。", "薄羅尚怯餘寒在，一陣東風剪牡丹。"]'),
('d9882cfd-b0ee-4449-8a96-dc692c8e48e4','趙濟民生日','陳起','宋','宋诗','song-poetry','','[]','今歲呈祥殊勝昔，六花端爲壽筵開。',32,'全唐诗/poet.song.202000.json','["今歲呈祥殊勝昔，六花端爲壽筵開。", "小詩聊寓千秋意，不得相陪法喜來。"]'),
('c5e72cc9-eaa2-4749-b5f2-635ffd6def2a','第三橋詩','陳起','宋','宋诗','song-poetry','','[]','梅花雪岸去舟單，茅屋水田白鷺寒。',32,'全唐诗/poet.song.202000.json','["梅花雪岸去舟單，茅屋水田白鷺寒。", "好景幾回吟不得，重來無語立闌干。"]'),
('3d154ffa-cb13-45e7-b5b3-b5e0222a685c','留題天樂寓張氏湖亭','陳起','宋','宋诗','song-poetry','','[]','沉水香銷一局棋，客來淺酌旋分題。',32,'全唐诗/poet.song.202000.json','["沉水香銷一局棋，客來淺酌旋分題。", "畫欄占得春多少，簾捲東風日未西。"]'),
('c5f72c93-8266-4e76-b369-340f53c4b075','次黄伯厚惠紙衾韻','陳起','宋','宋诗','song-poetry','','[]','冷浸溪藤松下月，密緘遠寄袁安雪。',32,'全唐诗/poet.song.202000.json','["冷浸溪藤松下月，密緘遠寄袁安雪。", "忍蹴茸茸一徑氈，依約江行曉時節。"]'),
('58d53025-a8b7-46ed-92e3-695bc85cc502','明遠閣','陳起','宋','宋诗','song-poetry','','[]','風捲疎烟遠岫分，天開一鏡皎無雲。',32,'全唐诗/poet.song.202000.json','["風捲疎烟遠岫分，天開一鏡皎無雲。", "衰荷摇落汀洲晚，猶舞餘香墜茜裙。"]'),
('e3870fe9-d6e4-4696-b39c-2320da56a84e','雪中簡趙德行','陳起','宋','宋诗','song-poetry','','[]','滕六庭前三致意，應翻奚錦報瓊瑶。',32,'全唐诗/poet.song.202000.json','["滕六庭前三致意，應翻奚錦報瓊瑶。", "剡梅莫訝山陰棹，寒色欺人是灞橋。"]'),
('98448b30-52f5-4532-ae6a-0300fae9d2ed','脩父知縣萬里寄詩久未能答午枕夢見之覺而有答','陳起','宋','宋诗','song-poetry','','[]','夢覺疎蟬韵更凄，闌干曲曲柳陰移。',32,'全唐诗/poet.song.202000.json','["夢覺疎蟬韵更凄，闌干曲曲柳陰移。", "吳蠶蜀繭繰千尺，一種愁機兩處絲。"]'),
('8349e3d5-2b2c-409b-a3f6-ccdca36bba4c','夜誦','陳起','宋','宋诗','song-poetry','','[]','父子跏趺絕似僧，青燈一琖夜三更。',32,'全唐诗/poet.song.202000.json','["父子跏趺絕似僧，青燈一琖夜三更。", "讀殘戴記兒將倦，山栗旋煨仍擘橙。"]'),
('777f8538-0930-4657-8103-4615f9966783','月下聞桂花','陳起','宋','宋诗','song-poetry','','[]','一庭人靜月當空，桂不多花細細風。',32,'全唐诗/poet.song.202000.json','["一庭人靜月當空，桂不多花細細風。", "香露滴衣凉似水，恍然移下廣寒宮。"]'),
('de4da331-eaa6-41f6-9fdb-53805971c6d4','胡季懷有詩約羣從爲秋泉之集輒以山果助筵戲作二疊  其一','陳起','宋','宋诗','song-poetry','','[]','近詩通譜江西社，新釀攙先天下秋。',32,'全唐诗/poet.song.202000.json','["近詩通譜江西社，新釀攙先天下秋。", "已許眼中窺一豹，可容杯裏散千憂。"]'),
('b8ba96d7-f8eb-46e2-bc93-e00b2483c0cc','胡季懷有詩約羣從爲秋泉之集輒以山果助筵戲作二疊  其二','陳起','宋','宋诗','song-poetry','','[]','君家香醪蜜不如，試投桃李望瑶琚。',32,'全唐诗/poet.song.202000.json','["君家香醪蜜不如，試投桃李望瑶琚。", "敢誇所無易所有，潘郎一出果盈車。"]'),
('b8efbb17-2664-4160-8457-d907ba2352e1','詠琴上曹先生','陳起','宋','宋诗','song-poetry','','[]','清如雅操直如絃，此意于今久不傳。',32,'全唐诗/poet.song.202000.json','["清如雅操直如絃，此意于今久不傳。", "月冷風高清禁地，只將古調奏鈞天。"]'),
('32d773ab-927a-4ffb-9843-3df0188b3414','與適安夜飲憶葵窗','陳起','宋','宋诗','song-poetry','','[]','人在江干月上巵，不妨想像一篇詩。',32,'全唐诗/poet.song.202000.json','["人在江干月上巵，不妨想像一篇詩。", "月來即是葵窗至，對景成三憶曩時。"]'),
('f455fa76-b95f-45ed-a97d-22cac5fcc062','與葦航適安飲  其一','陳起','宋','宋诗','song-poetry','','[]','獻酬無算是盃行，午酌從容至四更。',32,'全唐诗/poet.song.202000.json','["獻酬無算是盃行，午酌從容至四更。", "陶母侈於真率約，退思無倦若爲情。"]'),
('84f51610-d66b-47ce-a043-47d6cc0adb23','與葦航適安飲  其二','陳起','宋','宋诗','song-poetry','','[]','觥籌交錯舞傞傞，延得嫦娥泛醁波。',32,'全唐诗/poet.song.202000.json','["觥籌交錯舞傞傞，延得嫦娥泛醁波。", "客謂平生無此樂，二章聊繼飲中歌。"]'),
('3cc31a49-af7b-4e36-a84d-5c1213647b18','井亭橋','陳起','宋','宋诗','song-poetry','','[]','桐花夾岸柳遮山，水面誰家燕子還。',32,'全唐诗/poet.song.202000.json','["桐花夾岸柳遮山，水面誰家燕子還。", "摩利閣邊唐相井，濯衣人散暮潺潺。"]'),
('5252e04b-776f-4eb3-a827-8ad511d22411','分得春禽效香奩體','陳起','宋','宋诗','song-poetry','','[]','數聲應寄春消息，纔轉花梢濃綠隔。',32,'全唐诗/poet.song.202000.json','["數聲應寄春消息，纔轉花梢濃綠隔。", "早知襟韵倦逢迎，莫遣臨風情脈脈。"]'),
('f644f46c-53be-4f26-a560-eab6ce44b4e8','喚渡','陳起','宋','宋诗','song-poetry','','[]','一帆又是過西陵，天正寒時雨欲冰。',32,'全唐诗/poet.song.202000.json','["一帆又是過西陵，天正寒時雨欲冰。", "心地自平潮自險，回瞻絳闕認觚稜。"]'),
('a04e3bf4-6147-4bbe-829d-93538e727685','夜過西湖','陳起','宋','宋诗','song-poetry','','["\u897f\u6e56"]','鵲巢猶挂三更月，漁板驚回一片鷗。',32,'全唐诗/poet.song.202000.json','["鵲巢猶挂三更月，漁板驚回一片鷗。", "吟得詩成無筆寫，蘸他春水畫船頭。"]'),
('074e982d-5663-4e60-8710-140a0ef62af6','以毅齋曾先生詩法曰能以無情作有情子熊舉以見教兼示學詩如學禪之句次韻聲謝','陳起','宋','宋诗','song-poetry','','[]','西禪欲南闡，胡僧越海來。',168,'全唐诗/poet.song.202000.json','["西禪欲南闡，胡僧越海來。", "一蹴嵩山雲，支分五岐開。", "逢人問靈源，要識老牛胎。", "半生苦迷此，所見祇瞢哉。", "有時面壁求，眼底仍飛埃。", "誰知機湊到，却自詩中回。", "無中寫出有，金枝生蒿萊。", "再拜先生語，段段空中裁。", "當此意會處，高唱還自咍。", "如得合浦珠，如獲荆山瑰。", "方信春力到，無地匝蒼苔。", "可憐思花人，區區羯鼓催。", "我今得密旨，敢熄爐中灰。", "瓣香爲南豐，用酬開靈臺。"]'),
('56abfcd8-2491-4686-823e-ed4afb3949ca','天台桐柏觀李高士惠詩兼寄其遊山紀詠一編且復見招予不能赴約敬次來韻以謝','陳起','宋','宋诗','song-poetry','','[]','景物寫成編，清新人競傳。',48,'全唐诗/poet.song.202000.json','["景物寫成編，清新人競傳。", "風輕花自若，雨驟鳥悽然。", "老我塵中累，多君物外仙。", "未能拋世慮，山館借牀眠。"]'),
('3f419ba6-d950-4dce-838a-2d1b7c96546b','汪起潜謝送唐詩用韻再送劉滄小集','陳起','宋','宋诗','song-poetry','','["\u897f\u6e56"]','二年不覿盂山賢，戍客打門驚幽禪。',128,'全唐诗/poet.song.202000.json','["二年不覿盂山賢，戍客打門驚幽禪。", "手持姑溪之雙鯉，中藏片玉龍鸞鎸。", "弘璧天球匠意古，未數大曆郎與錢。", "自非仙蛻得靈骨，何以坐拍洪崖肩。", "秋高約我西湖邊，是時抱衾借枕眠。", "未賡疎影暗香句，且繼寒泉秋菊篇。", "篋中尚有詩一編，持贈雖微意則虔。", "錦段料應重下剪，向來清思湧如泉。"]'),
('32f6dcdc-b6d5-434e-aab4-05eb5243c249','趙監簿寄建寧諸詩','陳起','宋','宋诗','song-poetry','','[]','推敲久不見新裁，函軸光芒寄草萊。',64,'全唐诗/poet.song.202000.json','["推敲久不見新裁，函軸光芒寄草萊。", "音調似於清廟聽，風騷知自建安來。", "每嗟衰晚同籬菊，豈意先春得嶺梅。", "拂拭塵軒對清絕，媿無錦段報瓊瑰。"]'),
('b15c6ed0-9776-4661-a83e-47fb8118f0b2','六言','陳起','宋','宋诗','song-poetry','','[]','破窗有子書鴉，杜門無客嘗茶。',28,'全唐诗/poet.song.202000.json','["破窗有子書鴉，杜門無客嘗茶。", "春事應憐幽獨，隔牆飛過楊花。"]'),
('8ac2cac2-951a-4209-9186-c396b4c7ecd0','同毛誼夫喻可中夜汎西湖','陳起','宋','宋诗','song-poetry','','["\u897f\u6e56"]','又復移舟踐舊盟，喜隨師友挹湖光。',64,'全唐诗/poet.song.202000.json','["又復移舟踐舊盟，喜隨師友挹湖光。", "一番雨勢生秋意，幾處蟬聲送夕陽。", "亭榭家家增藻飾，星河歲歲曜文章。", "斷橋向午蟾方出，載月乘風更舉觴。"]'),
('b30a1d91-9f87-4be4-a5e6-7f2bd3d73172','湖上曲','陳起','宋','宋诗','song-poetry','','[]','鞦韆索外闌干側，一曲凝雲花影直。',32,'全唐诗/poet.song.202000.json','["鞦韆索外闌干側，一曲凝雲花影直。", "玉瓶風暖醉忘歸，春水不分楊柳色。"]'),
('d5600e71-9cb4-4fb1-8fa9-e3cae80c19f3','梅谷毛應麟畫梅','陳起','宋','宋诗','song-poetry','','[]','生平只爲愛梅看，故喜春風上筆端。',64,'全唐诗/poet.song.202000.json','["生平只爲愛梅看，故喜春風上筆端。", "短軸携來新繭密，橫枝化作老龍蟠。", "瘦於影落蟾波夜，清似香飄雪嶺寒。", "擬貼曲屏圓好夢，苦吟依舊錯憑欄。"]'),
('e79c64ef-0c21-43f2-b8dd-78a2e4d25155','三江斗門','陳起','宋','宋诗','song-poetry','','[]','短艇漾秋霞，江村數百家。',48,'全唐诗/poet.song.202000.json','["短艇漾秋霞，江村數百家。", "水聲鳴轣轆，山骨瘦槎枒。", "自笑如浮梗，何期又泛楂。", "人傳前岸石，曾化作蝦蟆。"]'),
('22592785-c5aa-4cde-b453-a3f734cc716a','西興道間','陳起','宋','宋诗','song-poetry','','[]','此心只欲與民安，不要人知道有官。',32,'全唐诗/poet.song.202000.json','["此心只欲與民安，不要人知道有官。", "顧得簥來雖是小，買他船去却須寬。"]'),
('a45dd15a-41d4-4392-bf9a-543bf8bc6721','元夕雨中偶成四絕奉寄東齋  其一','陳起','宋','宋诗','song-poetry','','[]','片雲纔起月無輝，一縷沉煙對雨時。',32,'全唐诗/poet.song.202000.json','["片雲纔起月無輝，一縷沉煙對雨時。", "病後情懷慵把酒，看他兒輩探官嬉。"]'),
('21ae7f98-b854-4748-a852-32c6aa67c753','元夕雨中偶成四絕奉寄東齋  其二','陳起','宋','宋诗','song-poetry','','[]','歌吹蕭條燈火稀，况逢連夕雨垂垂。',32,'全唐诗/poet.song.202000.json','["歌吹蕭條燈火稀，况逢連夕雨垂垂。", "黄堂景色非街市，應對山棚賦好詩。"]'),
('c9162a17-a953-4a4e-951b-9704a034730e','元夕雨中偶成四絕奉寄東齋  其三','陳起','宋','宋诗','song-poetry','','[]','車駕行將享孟春，月收梅影可愁人。',32,'全唐诗/poet.song.202000.json','["車駕行將享孟春，月收梅影可愁人。", "雨師不管閒歌舞，預向天街灑暗塵。"]'),
('17cd2ef1-4d7b-4ed3-8dba-e4ec95cc6faf','元夕雨中偶成四絕奉寄東齋  其四','陳起','宋','宋诗','song-poetry','','[]','浪兒歸去抱愁眠，孤負霜蛾與孟蟬。',32,'全唐诗/poet.song.202000.json','["浪兒歸去抱愁眠，孤負霜蛾與孟蟬。", "潤澤翻爲田父喜，紅燈带雨卜豐年。"]'),
('01d3b9a0-346f-465f-844c-6fb86f59da42','曝背','陳起','宋','宋诗','song-poetry','','[]','曝背向梅邊，清閑且信緣。',48,'全唐诗/poet.song.202000.json','["曝背向梅邊，清閑且信緣。", "籬疏編荻補，簾斷索麻聯。", "道在貧何慮，天高聽不偏。", "案頭詩幾卷，腸斷鶺鴒篇。"]'),
('490a029d-0223-47ff-8193-67ecc6212bb5','羊羔酒呈朱叢瑞','陳起','宋','宋诗','song-poetry','','[]','前坡風雨夕，髯奴惡顛怪。',48,'全唐诗/poet.song.202000.json','["前坡風雨夕，髯奴惡顛怪。", "銜林幻金波，灧灧玉船載。", "雪邊春意回，風味幾鵝兒。", "若與曹瞞說，翻樽左慈慈。"]'),
('4a79c13d-9524-441a-97d0-c053907794c2','罷酒','陳起','宋','宋诗','song-poetry','','[]','罷酒尋花涉斷磯，顛躋猶復强褰衣。',32,'全唐诗/poet.song.202000.json','["罷酒尋花涉斷磯，顛躋猶復强褰衣。", "可憐醉眼無分別，却把旁邊柳折歸。"]'),
('34c5ea29-2a39-4996-aaec-84b472b3694b','舊居有懷','陳起','宋','宋诗','song-poetry','','[]','粲粲高陽裔，浩氣凌華星。',48,'全唐诗/poet.song.202000.json','["粲粲高陽裔，浩氣凌華星。", "當春擬判花，投老身如萍。", "抱瑟東乘桴，寂寥扉晝扃。", "海霧尚沾袂，北窗從雨零。"]'),
('5ce2c37d-b78e-4891-85c5-070717e06693','楷書歌贈人','陳起','宋','宋诗','song-poetry','','[]','大哉易畫包犧生，鳥迹科斗相繼永。',184,'全唐诗/poet.song.202000.json','["大哉易畫包犧生，鳥迹科斗相繼永。", "六體中間亦湮昧，次仲楷到鍾王精。", "獻捷之表最近古，莊正如持干戚舞。", "黄庭字字能通神，强弓千挽筋力均。", "寶書遥遥名不朽，正法歐虞遠能守。", "後生不作諸老亡，睹君筆法得仙手。", "况君變格睨逸少，秋霽憑高森晚照。", "須知伯英到極工，中存楷則方入妙。", "我初不識君，見君石上文。", "從今便著青眼視，王謝庭前佳子弟。", "才能素所喜，喜極爲君歌。", "君今弱冠不可那，更後十年當君何。"]'),
('76efae5f-2bbf-43ba-b16d-91edb142377d','寄劉茂實','陳起','宋','宋诗','song-poetry','','[]','送君登廣陌，楊柳正依依。',48,'全唐诗/poet.song.202000.json','["送君登廣陌，楊柳正依依。", "別後人應老，庭前葉又飛。", "闖簷迎過鴈，無語立斜暉。", "還憶西樓月，雲寒白雪微。"]'),
('64dbec28-9860-4051-a5dc-33fbd303c3cc','嗚嗚','陳起','宋','宋诗','song-poetry','','[]','嗚嗚畫角悲，又復掩柴扉。',48,'全唐诗/poet.song.202000.json','["嗚嗚畫角悲，又復掩柴扉。", "夜月雲千里，春城水四圍。", "連宵燈報喜，幾日鳥啼歸。", "飛盡東郊絮，誰憐尚夾衣。"]'),
('d0a0a920-0560-40f4-b1b2-b4294b713590','鳳凰曲','陳起','宋','宋诗','song-poetry','','[]','丹穴來鳳皇，彩羽輝朝陽。',60,'全唐诗/poet.song.202000.json','["丹穴來鳳皇，彩羽輝朝陽。", "綠竹清溪邊，激揚鳴宮商。", "嗈嗈鳳皇曲，清風輕度竹。", "明時自歌舞，款步踏寒玉。", "啾啁雀聲喧，去覓梧桐宿。"]'),
('cbe85f3c-9927-422b-8380-46ab0f63117c','觀羊吟','陳起','宋','宋诗','song-poetry','','[]','拂石坐秋綠，寓目山之陽。',48,'全唐诗/poet.song.202000.json','["拂石坐秋綠，寓目山之陽。", "有白類積雪，誰放前村羊。", "冗蹄求一飽，寒草嚼峁藏。", "日晚山下路，西風吹稻香。"]'),
('f2bcda9b-89fa-433a-b037-fb265d575b83','東郊瞻四望亭有感','陳起','宋','宋诗','song-poetry','','[]','有盃莫向前山舉，楚水吳雲此地分。',32,'全唐诗/poet.song.202000.json','["有盃莫向前山舉，楚水吳雲此地分。", "竹外誰家霜鶴唳，吟逋梅下昔曾聞。"]'),
('a508dae0-976e-4ab5-9408-ed7bc4bf6dc9','秋步吳濟川別業','陳起','宋','宋诗','song-poetry','','[]','聞逐秋雲去，東西任所如。',48,'全唐诗/poet.song.202000.json','["聞逐秋雲去，東西任所如。", "偶過揚子宅，盡見鄴侯書。", "疏竹難藏鶴，清流可數魚。", "隔牆秋更迥，殘柳夕陽初。"]'),
('20c9e65f-807b-4ffb-85d5-e2add25d1c68','分得無題','陳起','宋','宋诗','song-poetry','','[]','露杯雲館昔相留，解珮人歸暗綠洲。',64,'全唐诗/poet.song.202000.json','["露杯雲館昔相留，解珮人歸暗綠洲。", "八斗才高空賦洛，九層臺迥易悲秋。", "定知玉鳳人吹怨，還念金龜婿遠遊。", "屏曲鴛鴦三十六，夜凉誰與結綢繆。"]'),
('b018932d-98fa-48fd-84d8-cc3031102b8f','觀張也愚作草聖','陳起','宋','宋诗','song-poetry','','[]','髯張學書雙鬢白，餘子百駕終莫及。',64,'全唐诗/poet.song.202000.json','["髯張學書雙鬢白，餘子百駕終莫及。", "曉兔經霜湘竹寒，秋蛇引露剡藤濕。", "拙時每向巧中生，聖處更從顛裏入。", "素鵝春晝厭欄時，綠水波重竹風急。"]'),
('29ff2d3e-f9d8-4e0b-88dc-5bd49d60a629','送楊明叔上舍歸蜀','陳起','宋','宋诗','song-poetry','','["\u897f\u6e56"]','東書西向泝波行，霜冷風凄定幾程。',64,'全唐诗/poet.song.202000.json','["東書西向泝波行，霜冷風凄定幾程。", "客枕夜長熊入夢，故園春到燕來迎。", "丈人山上芝堪友，西子湖邊柳結情。", "回首堯天鄉月皎，對床那不憶難兄。"]'),
('1f55b8de-0bb7-488c-8318-85a94912f01b','壽禮部喬文昌','陳起','宋','宋诗','song-poetry','','[]','璇杓西揭將指乾，商飆萬里清無邊。',220,'全唐诗/poet.song.202000.json','["璇杓西揭將指乾，商飆萬里清無邊。", "亭亭東峴聳蒼玉，雙溪露凈銀河鮮。", "天應歛此山川氣，九秋藴作人間瑞。", "當年寶婺所寶何，今日我公廊廟器。", "秘殿吾伊墳典光，粲然禮樂隆周王。", "滿懷獻納琅玕露，筆底璠璵金匱香。", "晚節黄花清上苑，雝雝宗祀儀將蕆。", "星辰直上復聲隆，看踵臺司調玉鉉。", "抱琴江臯客影單，四年指下不成彈。", "瓠巴一曲西風遞，請聽雙溪之水聲潺潺。", "舂崖漱石鳴湍玉，带月泠泠下溪曲。", "須臾峴首片雲生，雨雜寒泉座飛瀑。", "山清波明公與溪山一樣清，康寧千齡遥祝壽山福海之高深。"]'),
('5bc4e2c1-b818-4352-9312-ef41b3f792d7','壽樓監丞','陳起','宋','宋诗','song-poetry','','[]','十洲三島日月長，殷紅軟紫秋更香。',352,'全唐诗/poet.song.202000.json','["十洲三島日月長，殷紅軟紫秋更香。", "銀河倒浸珊瑚冷，十二樓高玉露瀼。", "九老仙都在何許，縹緲五雲鸞對舞。", "璇臺寶榭居者誰，迺是仙翁宣獻府。", "芙蓉爲城桂爲房，商盤周鼎東西廂。", "牙籤漆玉紛寶墨，未數人間集古堂。", "中有一仙炯雙目，清於秋月溫如玉。", "盡得仙翁肘後傳，千古韋經播餘馥。", "環珮鏘鏘侍玉墀，補天妙手帝所知。", "三十六宮煥王度，涉筆五工勞設施。", "八極遨遊思汗漫，山川先向峨眉翫。", "江風千里月一輪，亟上崚嶒快分半。", "風煙入興知幾詩，鳳鳴鵾化今其時。", "是誰紀德道旁石，重見邦人歌海沂。", "登龍元是當年客，再遇江城頭盡白。", "懷思每與阿戎談，清賞敢忘今阮籍。", "雙星佳會又兼旬，崧高此日曾生申。", "東樓瑞彩接南極，長生籙鏤黄金文。", "和仲吹商酌璇斗，白苧西風小垂手。", "幅巾醉倚漆園椿，人比靈椿更長久。", "我公自是天上人，商之霖雨虞卿雲。", "姑溪父老不余聽，謂是聖宋之景星。"]'),
('b20f9a89-7e94-40f3-b793-bdb1290957f5','壽喬樞密','陳起','宋','宋诗','song-poetry','','[]','明明我周王，四國文德撫。',84,'全唐诗/poet.song.202000.json','["明明我周王，四國文德撫。", "昭假天所監，時生仲山甫。", "訓儀系力式，剛柔不茹吐。", "一片翼翼心，冰霜映西府。", "凉秋九月朔，玉簫紫鸞舞。", "惟昴昔孕蕭，眉壽今頌魯。", "千載慶風雲，色絲期衮補。"]'),
('7e2935ca-9518-47e4-a7af-6fda8caebe45','句','陳起','宋','宋诗','song-poetry','','[]','秋雨梧桐皇子府，春風楊柳相公橋。',16,'全唐诗/poet.song.202000.json','["秋雨梧桐皇子府，春風楊柳相公橋。"]'),
('8b8b83b1-6132-42f5-807e-1f24089f900d','贈楊山人','張明中','宋','宋诗','song-poetry','','[]','有客針磁覓秀峯，展松高識可追風。',64,'全唐诗/poet.song.202000.json','["有客針磁覓秀峯，展松高識可追風。", "掌中訣是眼中法，天上仙爲地上翁。", "不向箇邊求指顧，更於何處訪窮通。", "荷囊金紫無難致，莫問肥家金粟紅。"]'),
('e4fe8576-31dd-48eb-a76e-00e8cedeed5c','活人','張明中','宋','宋诗','song-poetry','','[]','扁鵲倉公一笑還，頓令僵仆忽開顔。',64,'全唐诗/poet.song.202000.json','["扁鵲倉公一笑還，頓令僵仆忽開顔。", "君於那處傳衣鉢，名與古人齊等班。", "直欲陰功垂後世，肯同流俗戰蝸蠻。", "書生若得君醫法，醫國還同反掌間。"]'),
('a16a7177-4ba1-4ab3-9a78-987e74f74cbd','題活人堂','張明中','宋','宋诗','song-poetry','','[]','臞仙浩養蓬萊山，煉成九轉黄金丹。',64,'全唐诗/poet.song.202000.json','["臞仙浩養蓬萊山，煉成九轉黄金丹。", "丹成不忍都餐餌，刀圭留得活人間。", "上池之水君曾飲，咄嗟取效千倉廩。", "祝君更學寶藏公，兩月超遷到三品。"]'),
('c7c084c9-972a-4359-9138-5ed759be35da','真帥','張明中','宋','宋诗','song-poetry','','[]','也不學肉作臺盤與屏風，自然席上浮春容。',102,'全唐诗/poet.song.202000.json','["也不學肉作臺盤與屏風，自然席上浮春容。", "也不學論功封侯爲羹頡，無妨門外多車舝。", "看來不儉亦不豐，知渠別有箇家風。", "嚅嚌吾道爲殽核，膾炙人口有詩筒。", "要知應酬任真意，略去繁文併縟禮。", "儘渠世態謾炎凉，真帥堂中蜀君子。"]'),
('8b87f271-4153-4d39-b919-2c879efb6269','贈曾五行','張明中','宋','宋诗','song-poetry','','[]','洪水滔天泛濫秋，鯀汩五行貽帝憂。',116,'全唐诗/poet.song.202000.json','["洪水滔天泛濫秋，鯀汩五行貽帝憂。", "禹膺天錫箕釋囚，洪範五行著九疇。", "爾後星家幾者流，車載斗量二百州。", "是中談吐俱悠悠，曾君獨可古人儔。", "逢人何許便相投，禍福累累龜告猶。", "許我詩書晚到頭，鹽車寧久伏驊騮。", "異時果若斯言酬，看君羲和職裏獨步運星籌。"]'),
('5e1deba8-6ef3-4ad4-a929-b6f1b565ba22','謝陳教授','張明中','宋','宋诗','song-poetry','','[]','倒峽詞章了不難，氣吞雲夢有餘寬。',64,'全唐诗/poet.song.202000.json','["倒峽詞章了不難，氣吞雲夢有餘寬。", "社間宰相當推漢，圯下書生空念韓。", "傾蓋金蘭如舊契，把杯魚水便相歡。", "詩肩聳折酬君貺，弄斧般門奚足看。"]'),
('b6e147e6-5d67-499a-9774-395155051bcc','謝叔子陽丈惠詩','張明中','宋','宋诗','song-poetry','','[]','老子詩盟久廢閑，喜君步驟少陵壇。',64,'全唐诗/poet.song.202000.json','["老子詩盟久廢閑，喜君步驟少陵壇。", "句敲金玉聲名遠，韻險車斜心膽寒。", "傾出囊中和月露，皎如盤底走珠丸。", "苦莍難沒詩家事，會看塵冠早一彈。"]'),
('d8af8d7f-d80c-44bb-a087-b8416ad9aee5','木犀五首 花','張明中','宋','宋诗','song-poetry','','[]','天將秋氣搓金粟，堆作庭前滿樹黄。',32,'全唐诗/poet.song.202000.json','["天將秋氣搓金粟，堆作庭前滿樹黄。", "姚魏娉婷雖較好，問渠還有許多香。"]'),
('44f84b1d-d970-4838-858f-5b0e75ee3bcd','木犀五首 色','張明中','宋','宋诗','song-poetry','','[]','月影摇波碎未沉，灑將葉底簇成林。',32,'全唐诗/poet.song.202000.json','["月影摇波碎未沉，灑將葉底簇成林。", "却移右轂傍邊看，篩盡西風無限金。"]'),
('002c822e-7fcd-4b9e-ad4b-55a31a602d5e','木犀五首 香','張明中','宋','宋诗','song-poetry','','[]','不是天香與國香，如何釀得許芬芳。',32,'全唐诗/poet.song.202000.json','["不是天香與國香，如何釀得許芬芳。", "黄花嚼蕊非人世，身在蟾宮寒欲霜。"]'),
('c5fe5d6a-e721-4c44-a02e-8a2f7126a473','木犀五首 清','張明中','宋','宋诗','song-poetry','','[]','冶蕊倡花浪說馨，艷姚妖魏眩雙明。',32,'全唐诗/poet.song.202000.json','["冶蕊倡花浪說馨，艷姚妖魏眩雙明。", "黄金四出薰蘭麝，箇是花中第一清。"]'),
('d7ee6469-2efd-450d-a519-8d552ac30f85','木犀五首 味','張明中','宋','宋诗','song-poetry','','[]','收拾西風點點金，旋煩玉杵擣香塵。',32,'全唐诗/poet.song.202000.json','["收拾西風點點金，旋煩玉杵擣香塵。", "松梢鼓吹湯翻鼎，酥蜜澆來絕逼真。"]'),
('667c2be1-e540-4291-9911-b0cb206237a7','薔薇','張明中','宋','宋诗','song-poetry','','[]','長養風來新樣凉，薔薇嬌姹靚濃妝。',96,'全唐诗/poet.song.202000.json','["長養風來新樣凉，薔薇嬌姹靚濃妝。", "貴妃得酒沁紅色，更著領巾龍腦香。", "萬花卸盡錦機空，留得薔薇揖曉風。", "賸把胭脂勻笑靨，不施鉛粉涴潮紅。", "東君來與夏交割，西子出爲春送終。", "不是□□閒暇客，也拚終日對芳叢。"]'),
('66f8cb7d-ccd7-4fe0-bae5-88ae70eacb5c','拒霜二首  其一','張明中','宋','宋诗','song-poetry','','[]','天與司花細細論，秋花雖是殿花軍。',64,'全唐诗/poet.song.202000.json','["天與司花細細論，秋花雖是殿花軍。", "拒霜假得後凋操，造化豈容先策勳。", "濃著胭脂潮醉暈，蹙成玉板摺裙紋。", "遊蜂識盡千紅紫，只這寒芳竟不聞。"]'),
('3a249984-2d16-4853-9923-bb39a639bc2f','拒霜二首  其二','張明中','宋','宋诗','song-poetry','','[]','九月清霜可拒哉，芙蓉剛欲拒霜開。',32,'全唐诗/poet.song.202000.json','["九月清霜可拒哉，芙蓉剛欲拒霜開。", "不知拒著清霜後，還有三冬傲雪材。"]'),
('ecbf1635-aa20-46c9-9d08-2c5e0db57802','和秀卿梅二首  其一','張明中','宋','宋诗','song-poetry','','[]','疏枝冷蕊乍開緘，名在花中喚斗南。',32,'全唐诗/poet.song.202000.json','["疏枝冷蕊乍開緘，名在花中喚斗南。", "踏雪來看猶未盛，惱人兩兩更三三。"]'),
('a9a4dcc1-4288-4ea4-a663-ccf1f4670ef9','和秀卿梅二首  其二','張明中','宋','宋诗','song-poetry','','[]','月中仙子解征驂，不是株林見夏南。',32,'全唐诗/poet.song.202000.json','["月中仙子解征驂，不是株林見夏南。", "松竹不凋霜後翠，玉肌得共歲寒三。"]'),
('f1ad3cb6-d769-4116-aad0-1a1261d01112','和叔子梅','張明中','宋','宋诗','song-poetry','','[]','暖入孤根冷莫欺，冰魂幻出許多奇。',64,'全唐诗/poet.song.202000.json','["暖入孤根冷莫欺，冰魂幻出許多奇。", "輕霜弄粉清無涴，淡月浮香暗自知。", "莫管玉龍橫吹曉，要陪鸞鑑巧妝時。", "作詩換取梅花好，未必梅花肯要詩。"]'),
('a18e1e06-9f89-4d71-987d-188ed912fb7f','和景夔梅四首  其一','張明中','宋','宋诗','song-poetry','','[]','雪映橫塘月浸階，半扃庭戶未全開。',32,'全唐诗/poet.song.202000.json','["雪映橫塘月浸階，半扃庭戶未全開。", "猛香特地清人骨，多謝溪風爲送來。"]'),
('3b2ef352-6826-4bc5-9afa-1926b2454b07','和景夔梅四首  其二','張明中','宋','宋诗','song-poetry','','[]','暖入南枝春便回，北枝何似讓渠開。',32,'全唐诗/poet.song.202000.json','["暖入南枝春便回，北枝何似讓渠開。", "化工也解齊開却，留引詩人日日來。"]'),
('bcf76a75-a8d0-40cf-bef7-6e39b2569e08','和景夔梅四首  其三','張明中','宋','宋诗','song-poetry','','[]','淡月黄昏靜處芬，風來花氣奪清罇。',32,'全唐诗/poet.song.202000.json','["淡月黄昏靜處芬，風來花氣奪清罇。", "玉妃舞罷霓裳寂，安得真香爲返魂。"]'),
('534a365d-1fb3-4cf5-a6dc-18c62ad01831','和景夔梅四首  其四','張明中','宋','宋诗','song-poetry','','[]','雪月精神冰玉肌，未饒六六詫宮妃。',32,'全唐诗/poet.song.202000.json','["雪月精神冰玉肌，未饒六六詫宮妃。", "玉龍春筍調三弄，更向妝臺簷外飛。"]'),
('33a6e758-90bb-4adc-a169-06a4f49fafc4','鄰笛','張明中','宋','宋诗','song-poetry','','[]','璧雲和雲兩不移，一天染就碧玻璃。',32,'全唐诗/poet.song.202000.json','["璧雲和雲兩不移，一天染就碧玻璃。", "生憎哽咽鄰家笛，彼自追歡我自悽。"]'),
('d44431ea-4f7c-4492-8ec1-6e60a33945ec','贈棋客黄尤工象棋','張明中','宋','宋诗','song-poetry','','[]','黑甜政飽誰剝啄，手提楸枰敲軟玉。',112,'全唐诗/poet.song.202000.json','["黑甜政飽誰剝啄，手提楸枰敲軟玉。", "浩浩胸中龍虎韜，冷笑局邊人射鵠。", "粵昔嘗聞黄石公，圯橋一卷豈易通。", "報韓孺子未傳者，秘謀猶有在江夏。", "君今寓意在弈棋，計畫何止六出奇。", "長驅席卷容易取，不羨宣城與別墅。", "皇家今欲復土疆，煩公赤手縛鬼章。"]'),
('ef915991-12d0-45a1-8dcb-e68f4fe49624','延昌觀道紀堂','張明中','宋','宋诗','song-poetry','','[]','馬遷信史炳丹青，黄老攙先六籍名。',64,'全唐诗/poet.song.202000.json','["馬遷信史炳丹青，黄老攙先六籍名。", "清浄元非人紀有，虛無幻出道家聲。", "時揮麈尾談天統，冷笑蠅頭閙世情。", "待飲瓊漿擗麟脯，芙蓉爲舘玉爲城。"]'),
('97b9d952-33d3-4862-b327-b576260e3d9f','題朱陵觀三首  其一','張明中','宋','宋诗','song-poetry','','[]','欹窗飋飋漏風聲，壞壁斜斜半草行。',32,'全唐诗/poet.song.202000.json','["欹窗飋飋漏風聲，壞壁斜斜半草行。", "莫怨空齋對塵榻，碧油幢下是書生。"]'),
('8c52a0ce-fcad-4e62-81df-d3b46eea7c89','題朱陵觀三首  其二','張明中','宋','宋诗','song-poetry','','[]','一雨絲絲弄小春，物情何許舊還新。',32,'全唐诗/poet.song.202000.json','["一雨絲絲弄小春，物情何許舊還新。", "青楓忽換紅裝束，却笑松杉滿面塵。"]'),
('4e17063c-eb2e-4257-bfca-2884d8e7915e','題朱陵觀三首  其三','張明中','宋','宋诗','song-poetry','','[]','不怪豐年屢足書，此鄉民力看何如。',32,'全唐诗/poet.song.202000.json','["不怪豐年屢足書，此鄉民力看何如。", "依山靠嶺都開墾，二歲爲新三歲畬。"]'),
('c071974e-a5bd-40a9-afc4-7cfddc7a5eb3','和陳丞題陽家洞','張明中','宋','宋诗','song-poetry','','[]','溪繚飛虹聽不潺，山琱翠玉望來寒。',64,'全唐诗/poet.song.202000.json','["溪繚飛虹聽不潺，山琱翠玉望來寒。", "門牆面水臨橋靜，今古無虞枕自安。", "桐帽椶鞋非巧僞，花朝月夕幾團欒。", "箇中習尚元淳厚，論性空煩喻决湍。"]'),
('f71f72cd-9798-4bfa-b944-5657d5bbaf1c','三月二日紫牡丹','張明中','宋','宋诗','song-poetry','','[]','見說西京有魏家，瑞雲吹紫染芳華。',64,'全唐诗/poet.song.202000.json','["見說西京有魏家，瑞雲吹紫染芳華。", "移將萬里豪門貴，幻出千枝傾國葩。", "新佩荷囊重漬色，更乘蘭馥七香車。", "倡花野蕊都銷盡，來配姚黄得共誇。"]'),
('348eafbf-af33-4a7c-bfbc-fcef3a216e90','閏重陽菊花','張明中','宋','宋诗','song-poetry','','[]','鈿金拖蠟道家妝，籬下秋風久久香。',32,'全唐诗/poet.song.202000.json','["鈿金拖蠟道家妝，籬下秋風久久香。", "前後開來二十日，只應分付兩重陽。"]'),
('cca0c367-feeb-4402-a4aa-178979eadefa','金鳳花','張明中','宋','宋诗','song-poetry','','[]','妃子釵頭小鳳輕，飛來闌檻鬭芳英。',64,'全唐诗/poet.song.202000.json','["妃子釵頭小鳳輕，飛來闌檻鬭芳英。", "何曾枳棘棲留著，却傍梧桐雨露榮。", "濃紫鮮紅兼瑩白，春暄夏熱更秋清。", "冷齋塵榻空淹汝，不去秦樓作麽生。"]'),
('2ad882f9-ebe1-4ba2-9401-3afa1cf9267e','齋樓之西有木花','張明中','宋','宋诗','song-poetry','','[]','密蔭繁枝覆簷額，萬蕊千葩描不得。',96,'全唐诗/poet.song.202000.json','["密蔭繁枝覆簷額，萬蕊千葩描不得。", "晚風不動日微烘，遊蜂成陣香成國。", "野花有史說山礬，尺許來高塵土間。", "樹頭初拆千臍麝，花女吹香寧復慳。", "試登樓上憑闌看，花與詩人忽爲伴。", "恍疑身在廣寒宮，笑折一枝歸几案。"]'),
('564ca74c-86b4-4e52-b5b5-4437406fbd10','小亭前白牡丹','張明中','宋','宋诗','song-poetry','','[]','舊說花王稱洛蘇，洛蘇還識此花無。',64,'全唐诗/poet.song.202000.json','["舊說花王稱洛蘇，洛蘇還識此花無。", "紫綃層出黄金蕊，粉面仍看白玉膚。", "带雨含情揮淚重，迎風無力欲人扶。", "不堪老大渾無味，妬見渠儂美且都。"]'),
('02c115c1-6b07-4385-98c7-ee52ae6f85d2','齋前紅黄心芍藥','張明中','宋','宋诗','song-poetry','','[]','斗絕山原春亦妍，一欄紅藥小池邊。',64,'全唐诗/poet.song.202000.json','["斗絕山原春亦妍，一欄紅藥小池邊。", "淡妝玉臉半醒醉，高擁檀心相後先。", "頭重小垂嬌眩日，肌明偏喜掩輕烟。", "如何客裏生疏手，不折紅香來几前。"]'),
('f255e9ad-1ffc-4e70-83ec-695ccd338fcb','瓶簪緋桃','張明中','宋','宋诗','song-poetry','','[]','誰向南園剪膩雲，膽瓶微浸兩枝春。',64,'全唐诗/poet.song.202000.json','["誰向南園剪膩雲，膽瓶微浸兩枝春。", "一家姊妹紅裝束，千種精神粉淡勻。", "只有低昂分大小，更無妍巧可儔倫。", "綺窗書僻渾無耐，喚取渠儂作上賓。"]'),
('0dbd2983-3abc-40a7-a528-ca8f388580c3','瓶裏桃花','張明中','宋','宋诗','song-poetry','','[]','折得蒸紅簪小瓶，掇來几案自生春。',32,'全唐诗/poet.song.202000.json','["折得蒸紅簪小瓶，掇來几案自生春。", "珠唇絳口都開了，始信桃花解笑人。"]'),
('fdddea98-c372-4a88-97c4-8358e49a101f','檉桐二首  其一','張明中','宋','宋诗','song-poetry','','[]','百花耐久說檉桐，選甚薰風秋雨中。',32,'全唐诗/poet.song.202000.json','["百花耐久說檉桐，選甚薰風秋雨中。", "誰道花無紅十日，此花日日醉潮紅。"]'),
('bee2f765-966a-45d0-b268-8fe8b7d15318','檉桐二首  其二','張明中','宋','宋诗','song-poetry','','[]','石榴安敢擬檉桐，借問司花也不中。',32,'全唐诗/poet.song.202000.json','["石榴安敢擬檉桐，借問司花也不中。", "鶴頂丹砂猩血服，試評却有此來紅。"]'),
('f10f9fb2-6748-42c8-a7ff-3a0ad45ea6f5','白牡丹','張明中','宋','宋诗','song-poetry','','[]','看詩醉眼便醒蘇，索句吟花一字無。',64,'全唐诗/poet.song.202000.json','["看詩醉眼便醒蘇，索句吟花一字無。", "虢國夫人呈素面，滕家仙子削瓊膚。", "姚黄於后貪妖冶，魏紫逢君用夾扶。", "試問此花清白不，不聞吁咈只聞都。"]'),
('964bd966-54d5-4659-85ba-253859c309ce','諸公詠探春花二首  其一','張明中','宋','宋诗','song-poetry','','[]','飛瓊將命下瑶臺，欲探新春口未開。',32,'全唐诗/poet.song.202000.json','["飛瓊將命下瑶臺，欲探新春口未開。", "剛被東風留住著，却酡醉臉未歸來。"]'),
('e79bcb7e-5248-4fec-9388-57e77b4df655','諸公詠探春花二首  其二','張明中','宋','宋诗','song-poetry','','[]','海棠伎倆山茶色，未葉先花作麽生。',32,'全唐诗/poet.song.202000.json','["海棠伎倆山茶色，未葉先花作麽生。", "道是探春春已半，命名都不近人情。"]'),
('2a10f23e-cf07-48c7-b7e9-7022916208b4','歐陽新卿賦薇藥','張明中','宋','宋诗','song-poetry','','[]','東皇又罷調春手，花飛十不啻八九。',256,'全唐诗/poet.song.202000.json','["東皇又罷調春手，花飛十不啻八九。", "不論韋曲與少城，卸盡錦機忍回首。", "唯餘芍藥不攙先，却與薔薇相爭妍。", "小欄逼束恣嬌姹，高架支撐儘蔓延。", "倡花冶蕊都妝靚，贏得先開不相見。", "若令環列見傾城，羞殺群芳爭掩面。", "瑞雲吹紫染二葩，只讓西京一魏家。", "新佩荷囊重漬色，更乘蘭馥七香車。", "主人壽樂獻壽觴，哦詩都带花邊香。", "看來詩胞雲夢豁，只愁拶破古錦囊。", "昨宵點滴山間雨，弄晴賸著花上露。", "主人曉起試吸將，便得長生之妙處。", "醉潮玉頰十分紅，主人與花恰相同。", "興來持酒繞豔叢，更折繁枝簪席東。", "看花醉眼未惺鬆，忽然跳入花蕊宮。", "壽仙喜與花仙逢，更入太史滑稽中。"]'),
('d78789ee-1048-40eb-abbc-f76fb2bf3f3e','賦山茶示陳慧甫三首  其一','張明中','宋','宋诗','song-poetry','','[]','老葉莍紅爲怯冬，却將醉臉對東風。',32,'全唐诗/poet.song.202000.json','["老葉莍紅爲怯冬，却將醉臉對東風。", "丹砂一夜勻千萼，造化如何不費工。"]'),
('ba30d064-a75d-49ac-b9f3-5b17d7e47a04','賦山茶示陳慧甫三首  其二','張明中','宋','宋诗','song-poetry','','[]','檀心絳蕊壓牆低，南海山根巧自移。',32,'全唐诗/poet.song.202000.json','["檀心絳蕊壓牆低，南海山根巧自移。", "濃艷未應輸石醋，吹香底用倩風姨。"]'),
('2ef83988-29e1-4db5-8ee4-96060840cad3','賦山茶示陳慧甫三首  其三','張明中','宋','宋诗','song-poetry','','[]','春風未晚凌霜葉，夜雨催開紅玉花。',32,'全唐诗/poet.song.202000.json','["春風未晚凌霜葉，夜雨催開紅玉花。", "絳雪膩酥猶未有，饑蜂瘦蝶漫交加。"]'),
('26f895ae-5ce1-4a20-b8ad-cdb2a6781cf9','謝惠紅桃二首  其一','張明中','宋','宋诗','song-poetry','','[]','朱雀窗間小小窺，詼諧兒子已心知。',32,'全唐诗/poet.song.202000.json','["朱雀窗間小小窺，詼諧兒子已心知。", "如何仙種今流落，萬顆甘寒付阿誰。"]'),
('00084576-d028-40c2-bc02-622ae6eefee7','謝惠紅桃二首  其二','張明中','宋','宋诗','song-poetry','','[]','報我勤渠有木桃，膚腴密灑茜花膏。',32,'全唐诗/poet.song.202000.json','["報我勤渠有木桃，膚腴密灑茜花膏。", "枯腸消得三十顆，只恐兒曹賦老饕。"]'),
('fb41c449-b291-4ce9-b5ff-1e2370e18040','鶑','張明中','宋','宋诗','song-poetry','','[]','柳接飛來影，花翻過後枝。',48,'全唐诗/poet.song.202000.json','["柳接飛來影，花翻過後枝。", "金衣摇日色，簧口弄晴絲。", "遊子錯回首，何人澀小詞。", "楊園好風景，莫與負佳期。"]'),
('ef2dc3b6-aadf-4cb0-92e8-645030972d84','燕二首  其一','張明中','宋','宋诗','song-poetry','','[]','芹泥夾岸融融日，野水當門淡淡花。',32,'全唐诗/poet.song.202000.json','["芹泥夾岸融融日，野水當門淡淡花。", "王謝堂前舊時客，如何肯訪野人家。"]'),
('586a1d2e-577c-4835-8d4b-8b849c71b5a9','燕二首  其二','張明中','宋','宋诗','song-poetry','','[]','烏衣國裏未安渠，萬里來從天一隅。',32,'全唐诗/poet.song.202000.json','["烏衣國裏未安渠，萬里來從天一隅。", "道是能傳香閣恨，來時曾到故鄉無。"]'),
('e78e4962-6b84-4005-a7ec-029025678a8f','蝶','張明中','宋','宋诗','song-poetry','','[]','攬得風光忘却愁，千葩萬蕊恣追遊。',64,'全唐诗/poet.song.202000.json','["攬得風光忘却愁，千葩萬蕊恣追遊。", "香鬚點染黄金濕，小翅輕翻白玉柔。", "舞態恨渠春晝短，狂情不管好花羞。", "膩酥絳雪都相識，莫向紅窗繡室休。"]'),
('92697f3b-c37b-45ba-b96e-d96ace56ea6c','蟬二首  其一','張明中','宋','宋诗','song-poetry','','[]','翅剪霜綃別樣輕，腹饕風露有餘清。',32,'全唐诗/poet.song.202000.json','["翅剪霜綃別樣輕，腹饕風露有餘清。", "一泓池水兩垂柳，彼此賡酬無限聲。"]'),
('4918f2b3-1637-481c-a161-3e90a1a11990','蟬二首  其二','張明中','宋','宋诗','song-poetry','','[]','抱葉吟風相後先，綠楊影裏夕陽天。',32,'全唐诗/poet.song.202000.json','["抱葉吟風相後先，綠楊影裏夕陽天。", "如何不管人孤寂，却把繁聲暗裏牽。"]'),
('b4c7d5a8-8390-4255-b8d3-a7fd2ee519db','靜室','張明中','宋','宋诗','song-poetry','','[]','當年梁武造佛寺，子雲飛帛書蕭字。',96,'全唐诗/poet.song.202000.json','["當年梁武造佛寺，子雲飛帛書蕭字。", "李君得字煨燼中，建立小室有深意。", "如今靜室傍花巖，此室比心爲一致。", "峯巒底裏著軒窗，明月清風爲誰至。", "三千世界闊如許，雜遝喧囂鼎方沸。", "銅爐添穗坐結趺，更倩白雲鎖蒼翠。"]'),
('1f8ad8fe-6ae4-4915-913e-e7162eff27a2','冷齋','張明中','宋','宋诗','song-poetry','','[]','雨濕桑樞夜不關，北窗誰更肯遮闌。',64,'全唐诗/poet.song.202000.json','["雨濕桑樞夜不關，北窗誰更肯遮闌。", "冷侵硯滴渾無潤，凍折詩眉未係寒。", "萬里雲容同水墨，四垂簷溜欲琅玕。", "梅花枝上春應到，袖手窗前子細看。"]'),
('d7d61c20-6f0d-4e73-8a7f-48ce1184e708','澹軒','張明中','宋','宋诗','song-poetry','','[]','主張老氏欲何求，恬澹中間覓自由。',64,'全唐诗/poet.song.202000.json','["主張老氏欲何求，恬澹中間覓自由。", "直把沖虛超俗界，何須芻豢作嘉羞。", "滿懷明月黄庭古，一段清風白帝秋。", "載詠此軒新句子，羨君傑出道家流。"]'),
('84fdf697-3094-44c9-bc09-f02e4f4a085d','題曾運使水亭','張明中','宋','宋诗','song-poetry','','[]','笥山之水磨銅綠，秀氣都在山之麓。',64,'全唐诗/poet.song.202000.json','["笥山之水磨銅綠，秀氣都在山之麓。", "就中卜築小仙居，面面軒亭看不足。", "主人倒屣浮春容，囊詩拶破古錦紅。", "書生幸有登龍便，願到壇邊揖下風。"]'),
('fa4b33ff-f3b6-40fc-919f-6ce646e4d368','賀郭落成新宅','張明中','宋','宋诗','song-poetry','','[]','人言創業世所難，我謂守成寧易得。',130,'全唐诗/poet.song.202000.json','["人言創業世所難，我謂守成寧易得。", "守成創業併二難，况以守成而建宅。", "翼翼翬飛奐且輪，均輸殫巧斷雲斤。", "晴嵐暖翠十分好，水鏡山鬟四序新。", "子儀甲第在何許，怱此巍峩基千古。", "諸郎他日到鳳池，便是潭潭公相府。", "嘉賓滿座酒盈罇，常棣怡怡堂上春。", "書生無物表賀成，袖有新詩聊當野人芹。"]'),
('3bebef28-d36d-4c77-bc4f-fd0a805b91b0','和書壁','張明中','宋','宋诗','song-poetry','','[]','平生蹇足媿蹣跚，流落荒凉强自安。',64,'全唐诗/poet.song.202000.json','["平生蹇足媿蹣跚，流落荒凉强自安。", "邊月一聲秋雁切，江風五鼓漏花寒。", "青燈黄嬭令人老，流水高山底處彈。", "須信窮通翻覆手，到頭應不誤儒冠。"]'),
('e4c4a408-860c-4963-a84d-3a447950094c','和故舊招館','張明中','宋','宋诗','song-poetry','','[]','牢落詩盟寒欲灰，非君懷抱若爲開。',32,'全唐诗/poet.song.202000.json','["牢落詩盟寒欲灰，非君懷抱若爲開。", "未闌罇酒論文意，拂榻應須有待來。"]'),
('d32be1a5-b1c8-4d51-8e42-47e415128ca9','吉祥寺默軒','張明中','宋','宋诗','song-poetry','','[]','默識何銷語話詳，心齋也則坐能忘。',64,'全唐诗/poet.song.202000.json','["默識何銷語話詳，心齋也則坐能忘。", "如何孔氏家傳底，却在高僧衣鉢傍。", "併把禪機俱寂滅，不教妙理費商量。", "白雲深鎖軒前路，看盡金爐幾篆香。"]'),
('f32880a2-d33e-4d31-b76a-7520f4c70558','到野寺','張明中','宋','宋诗','song-poetry','','[]','搘杖尋春過小溪，小溪過了到招提。',64,'全唐诗/poet.song.202000.json','["搘杖尋春過小溪，小溪過了到招提。", "插天翠巘青絲幛，委地落花紅繡泥。", "箇裏囂塵都浄盡，只餘啼鳥自東西。", "興濃底用忙歸去，莫管山銜晚日低。"]'),
('b81362ef-e2ca-4563-bafe-5b44f9285abc','華巖僧舍聳翠','張明中','宋','宋诗','song-poetry','','[]','峻極攢空新潑藍，山山頭上立松杉。',32,'全唐诗/poet.song.202000.json','["峻極攢空新潑藍，山山頭上立松杉。", "高僧高處存高躅，不但雲蘿花作巖。"]'),
('e4e50957-a810-463e-ae19-d64109ddc214','擬盤','張明中','宋','宋诗','song-poetry','','[]','君不見夾谷伯圖方湊輻，英雄摧挫俳優戮。',118,'全唐诗/poet.song.202000.json','["君不見夾谷伯圖方湊輻，英雄摧挫俳優戮。", "又不見金谷妙歌翻綺縠，到頭也則貽羞辱。", "儘渠富貴莫擬倫，豈如李愿歸盤谷。", "君今築臺名擬盤，看盡浮雲幾翻覆。", "茂林修竹同歲寒，明月清風伴幽獨。", "抱琴高卧西窗紅，哦詩更盡杯中綠。", "雙蝸蠻觸戰方酣，藜杖逍遥巾一幅。"]'),
('ec373da0-96ed-4d58-8d0f-1caf074a3eeb','回鄉偶書','張明中','宋','宋诗','song-poetry','','[]','不見眉間半點黄，花開花落總他鄉。',32,'全唐诗/poet.song.202000.json','["不見眉間半點黄，花開花落總他鄉。", "子規偏向三更月，喚起愁人也斷腸。"]'),
('db9a3d41-70f7-4779-be6b-6195182b2ff6','謝惠三賢文集三首  其一','張明中','宋','宋诗','song-poetry','','[]','□□修藏日，干戈澒洞秋。',48,'全唐诗/poet.song.202000.json','["□□修藏日，干戈澒洞秋。", "詩文工霧縠，論議壯春流。", "瀲水昔三子，廬陵舊一歐。", "自憐生已晚，不獲與同遊。"]'),
('57521932-4bbf-4368-8db2-77365842abdc','謝惠三賢文集三首  其二','張明中','宋','宋诗','song-poetry','','[]','璧水還多士，文鋒豈易戡。',48,'全唐诗/poet.song.202000.json','["璧水還多士，文鋒豈易戡。", "積分陞以內，優占斗維南。", "天府榮登四，人材况有三。", "秀鍾蕞爾地，如許富奇男。"]'),
('0abe7c4b-8561-411f-86cd-d9c243b9d7dc','謝惠三賢文集三首  其三','張明中','宋','宋诗','song-poetry','','[]','三子久埋沒，遺文富百篇。',48,'全唐诗/poet.song.202000.json','["三子久埋沒，遺文富百篇。", "冰涵心底鑑，雪釋性中天。", "濟楚鯉庭下，瀾翻螢案邊。", "著靴鬼爲祟，容易復青氈。"]'),
('262d2094-02cb-4874-b9a0-1d11a1f8db1e','謝惠詩','張明中','宋','宋诗','song-poetry','','[]','君詩來貺我難當，語带誠齋句妙香。',64,'全唐诗/poet.song.202000.json','["君詩來貺我難當，語带誠齋句妙香。", "鮫室垂垂新下泣，蠙珠顆顆爛生光。", "魂飛錦里花爭巧，夢到池塘草又芳。", "早晚交遊逢大手，急將名姓爲傳揚。"]'),
('cadf09c7-843b-4d2f-87da-05dd17dee16f','辭世偈','釋妙印','宋','宋诗','song-poetry','','[]','六十九年，一場大夢。',20,'全唐诗/poet.song.202000.json','["六十九年，一場大夢。", "歸去來兮，珍重珍重。"]'),
('b03effd5-731a-4bde-9de6-d9b82986241d','香城寺','劉元剛','宋','宋诗','song-poetry','','[]','末行陶令里，早自慣舁籃。',48,'全唐诗/poet.song.202000.json','["末行陶令里，早自慣舁籃。", "米市呼干許，香城訪晉曇。", "神遊青黛岳，詩到碧雲菴。", "不管衝寒去，乘風破曉嵐。"]'),
('ad62ca06-9ef8-4376-8bcb-0b6e8f923213','武夷九曲棹歌圖  其一','劉元剛','宋','宋诗','song-poetry','','[]','一曲初篙上水船，翠嵐蒼壁挾洄川。',32,'全唐诗/poet.song.202000.json','["一曲初篙上水船，翠嵐蒼壁挾洄川。", "綵幢幔屋今何在，空有丹爐石鼎烟。"]'),
('d953ecf5-34a7-470c-8ed5-ba28d7580abc','武夷九曲棹歌圖  其二','劉元剛','宋','宋诗','song-poetry','','[]','二曲崚嶒三石峰，當時秦女採芙蓉。',32,'全唐诗/poet.song.202000.json','["二曲崚嶒三石峰，當時秦女採芙蓉。", "至今湯沐臨清泚，不作巫山十二重。"]'),
('5ac09a91-1ff8-48de-8e4c-ac1c9b684161','武夷九曲棹歌圖  其三','劉元剛','宋','宋诗','song-poetry','','[]','三曲懸崖插匭船，春秋八百又千年。',32,'全唐诗/poet.song.202000.json','["三曲懸崖插匭船，春秋八百又千年。", "不知天地黄心木，控鶴仙人肯汝憐。"]'),
('02edc022-3be8-484b-884c-d4b932db01c5','武夷九曲棹歌圖  其四','劉元剛','宋','宋诗','song-poetry','','[]','五曲雲崖有許深，石門書屋著修林。',32,'全唐诗/poet.song.202000.json','["五曲雲崖有許深，石門書屋著修林。", "堂堂不泯清風在，一片寒潭印我心。"]'),
('07662b01-4ae5-4791-84cf-d9e0607f4e7e','武夷九曲棹歌圖  其五','劉元剛','宋','宋诗','song-poetry','','[]','七曲催船快上灘，好山留與漫郎看。',32,'全唐诗/poet.song.202000.json','["七曲催船快上灘，好山留與漫郎看。", "經行雪瀑仙屏下，恍記齋堂夜帳寒。"]'),
('3b3c2380-d868-4a36-bcb9-237b6795a98d','武夷九曲棹歌圖  其六','劉元剛','宋','宋诗','song-poetry','','[]','八曲雲山歛復開，長年倚棹立裴徊。',32,'全唐诗/poet.song.202000.json','["八曲雲山歛復開，長年倚棹立裴徊。", "俄然聽得林間語，知道新村貰酒來。"]'),
('fe2baa60-12f1-4bbc-9fb0-05a3690c393d','武夷九曲棹歌圖  其七','劉元剛','宋','宋诗','song-poetry','','[]','九曲遥岑更鬰然，板橋漁市引長川。',32,'全唐诗/poet.song.202000.json','["九曲遥岑更鬰然，板橋漁市引長川。", "喚回白馬賓雲夢，來看桑麻萬里天。"]'),
('515e7fc3-9d01-4dcb-8116-83f00f035722','登九會臺','于炳文','宋','宋诗','song-poetry','','[]','今日重陽日，菊花開未開。',48,'全唐诗/poet.song.202000.json','["今日重陽日，菊花開未開。", "飄飄風掃徑，泛泛露迎杯。", "甚喜諸同□，相期九會臺。", "臨歸逢勝賞，留句在巖隈。"]'),
('1aa2919d-6dc2-4fcf-831e-11671ec15b94','仲夏賞月次雪齋韵二首  其一','司馬述','宋','宋诗','song-poetry','','[]','喜約當余望，開樽對月圓。',48,'全唐诗/poet.song.202000.json','["喜約當余望，開樽對月圓。", "一時如素定，四美復兼全。", "清影浮瓊斚，高歌樂性天。", "主賓歡意洽，不惜且留延。"]'),
('aebfab60-5280-4c99-bac3-2a9c5404a4f7','仲夏賞月次雪齋韵二首  其二','司馬述','宋','宋诗','song-poetry','','[]','停杯待明月，喜見十分圓。',48,'全唐诗/poet.song.202000.json','["停杯待明月，喜見十分圓。", "曩昔詩猶在，今宵事偶全。", "浩歌休問夜，至樂莫非天。", "願侍金樽側，時來接款延。"]'),
('3bfc176f-a9fa-4a43-9e64-ced6fd5a2c2d','虎嘯巖','黄鑑','宋','宋诗','song-poetry','','[]','探奇乍入昇真洞，泛度先來覓虎溪。',64,'全唐诗/poet.song.202000.json','["探奇乍入昇真洞，泛度先來覓虎溪。", "劈立高巖容廣厦，紆迴流水稱幽棲。", "樓臺錯落通窗牖，石磴參差藉杖藜。", "無數風光供騁望，更聞山鳥向林啼。"]'),
('e0397a51-d0ce-457a-b500-f74934ecc8d9','金陵懷古','吳陵','宋','宋诗','song-poetry','','[]','烟雲莽莽對窮秋，六代雄豪見古丘。',64,'全唐诗/poet.song.202000.json','["烟雲莽莽對窮秋，六代雄豪見古丘。", "萬里長波東赴海，千年閑客獨登樓。", "山川冥漠天難問，運數推移地莫留。", "終信東南多王氣，浙中今是帝王州。"]'),
('e4ee2593-30b7-4594-bfa8-26b3dc932702','盱眙郡樓','吳陵','宋','宋诗','song-poetry','','[]','風物凄凉天地秋，憑高不盡古今愁。',64,'全唐诗/poet.song.202000.json','["風物凄凉天地秋，憑高不盡古今愁。", "關河北望三千里，淮泗東來第一州。", "日暮邊聲傳畫角，早寒霜氣襲重裘。", "干戈澒洞何時靜，王粲長吟獨倚樓。"]'),
('20ce4f43-89bd-49fd-b163-b300a763b355','登南浦亭','吳陵','宋','宋诗','song-poetry','','[]','飄泊豫章城，登臨南浦亭。',48,'全唐诗/poet.song.202000.json','["飄泊豫章城，登臨南浦亭。", "乾坤遺落羽，江海一浮萍。", "宿雨桃花水，春風杜若汀。", "古今離別地，那許客愁醒。"]'),
('13314aaa-1bb5-495e-bc39-01f25b2d3307','古意','吳陵','宋','宋诗','song-poetry','','[]','莫結蕩子心，恩情信難保。',24,'全唐诗/poet.song.202000.json','["莫結蕩子心，恩情信難保。", "楊花縱可變，奈是浮萍草。"]'),
('8b1191aa-4e99-4e6f-b6f5-78a4b06f6870','句','戴衍','宋','宋诗','song-poetry','','[]','源水不移當日岸，桃花猶是昔年春。',16,'全唐诗/poet.song.202000.json','["源水不移當日岸，桃花猶是昔年春。"]'),
('7f1df3af-20ef-4006-82cf-9c0bd6ba789f','鄉飲酒唱和詩','童頤','宋','宋诗','song-poetry','','[]','兩轓來自殿東西，要使旴民習俗移。',64,'全唐诗/poet.song.202000.json','["兩轓來自殿東西，要使旴民習俗移。", "可但官條扶世教，更從鄉飲敘倫彝。", "一堂禮樂情何厚，四面衣冠樂有儀。", "我老亦陪賓席後，蹣跚非據只心知。"]'),
('9b081c4d-cd2f-423c-88fa-e691557dbe14','句','桂如琥','宋','宋诗','song-poetry','','[]','雲氣有時迷洞口，塵埃飛不到胸中。',16,'全唐诗/poet.song.202000.json','["雲氣有時迷洞口，塵埃飛不到胸中。"]'),
('50478a52-0ae5-4e4c-967b-2ff34fc117a8','題梅山雲悅樓','朱渙','宋','宋诗','song-poetry','','[]','和衣高卧白雲堆，門倩雲封不妄開。',32,'全唐诗/poet.song.202000.json','["和衣高卧白雲堆，門倩雲封不妄開。", "留向山中自娛悅，莫教一片出山來。"]'),
('924dd2a7-f6c4-433b-81f9-a06fd341ee08','爐寒無灰','朱渙','宋','宋诗','song-poetry','','[]','地爐寒無灰，相對空四壁。',24,'全唐诗/poet.song.202000.json','["地爐寒無灰，相對空四壁。", "豈無可熱者，此事不慣炙。"]'),
('28985e6e-3d9a-4c5e-9488-c54a35df693d','題秀巖用蔡鐵窗韻','朱渙','宋','宋诗','song-poetry','','[]','一溪隔斷人來去，巖路荆榛到者希。',64,'全唐诗/poet.song.202000.json','["一溪隔斷人來去，巖路荆榛到者希。", "見石乳懸繁欲墮，聽泉聲冷坐忘歸。", "地寬飲可百人共，谷靜塵無半點飛。", "所恨世無挾山手，爲予移取□柴扉。"]'),
('6848eedb-ae6e-4653-9a8f-f109b3fb6434','游寶相院','林觀過','宋','宋诗','song-poetry','','[]','古人期年變，拙政媿格頑。',84,'全唐诗/poet.song.202000.json','["古人期年變，拙政媿格頑。", "觸此三伏暑，招提解征鞍。", "好風隨過雨，稻花秀可餐。", "南窗大榻凉，久輸老僧閒。", "盤飱息萬慮，竹梧凜相看。", "清陰交蔽芾，直節不可干。", "斯來結三友，欲去復盤桓。"]'),
('18dec000-e514-4b8e-8526-950fd80a6c7c','棋盤山','林觀過','宋','宋诗','song-poetry','','[]','山頂仙翁一局棋，不知人世幾推移。',32,'全唐诗/poet.song.202000.json','["山頂仙翁一局棋，不知人世幾推移。", "玉枰石座今存否，空使朝猿暮鶴悲。"]'),
('88b450f4-1f48-4cbc-9b7c-ad3a75270945','天柱窟','林觀過','宋','宋诗','song-poetry','','[]','六丁擎柱上天門，石窟空遺透地根。',32,'全唐诗/poet.song.202000.json','["六丁擎柱上天門，石窟空遺透地根。", "不是溪人嚴守護，靈蹤那得至今存。"]'),
('05436f34-f91b-4ca9-8054-449295870db9','句  其一','林觀過','宋','宋诗','song-poetry','','[]','公來無琴鶴，公去有芒鞋。',12,'全唐诗/poet.song.202000.json','["公來無琴鶴，公去有芒鞋。"]'),
('2cbab6c5-707e-4fb9-9951-39f40780e363','句  其二','林觀過','宋','宋诗','song-poetry','','[]','漢皇未下復讎詔，奈此匹夫匹婦何。',16,'全唐诗/poet.song.202000.json','["漢皇未下復讎詔，奈此匹夫匹婦何。"]'),
('2c32a7d4-cf90-43f0-8227-a50d7b2ca96b','弔瓊花','趙炎','宋','宋诗','song-poetry','','[]','名擅無雙氣色雄，忍將一死報東風。',32,'全唐诗/poet.song.202000.json','["名擅無雙氣色雄，忍將一死報東風。", "他年我若修花史，合傳瓊花烈女中。"]'),
('f04b77a4-bd5d-43f3-baf6-a1b417e2d2f2','虎跑泉','楊端叔','宋','宋诗','song-poetry','','[]','蒼髯白甲深山龍，山門高高龍所宮。',64,'全唐诗/poet.song.202000.json','["蒼髯白甲深山龍，山門高高龍所宮。", "青苔夭矯絕可喜，滿地狼籍拋頑銅。", "於菟殷勤水供養，道人回施無盡藏。", "匏樽一滴到陶泓，灘聲浩浩西山漲。"]'),
('3ede9c12-bc3c-4a9e-83d9-8c45b010492b','浮遠堂','楊端叔','宋','宋诗','song-poetry','','[]','萬松相摩天籟作，一塵不留心鏡空。',64,'全唐诗/poet.song.202000.json','["萬松相摩天籟作，一塵不留心鏡空。", "毋庸寶焰照牛渚，已見浮涎吹龍宮。", "零丁沙洲抗水勢，替淚塔鈴語天風。", "賈胡惜錢不自惜，晝夜牙籌澎湃中。"]'),
('6d7af6ac-0a02-4d71-8e88-03dd152ffb79','悼步月','趙崇滋','宋','宋诗','song-poetry','','[]','雁過妝樓人不見，斷腸又是一黄昏。',64,'全唐诗/poet.song.202000.json','["雁過妝樓人不見，斷腸又是一黄昏。", "不知天上嬋娟影，能照人間寂寞魂。", "響屧廊深空認步，唾茸窗暖尚留痕。", "合將一把香酥骨，葬在巫陽雲雨村。"]'),
('1bb787c4-a56b-4e30-aab2-0e37ed7aeca2','趙容州新居','趙崇滋','宋','宋诗','song-poetry','','[]','舊日水心路，新添趙倚樓。',48,'全唐诗/poet.song.202000.json','["舊日水心路，新添趙倚樓。", "詩名不寂寞，此地合風流。", "隔浦荷花雨，當門杜若秋。", "有時清興到，夜半喚孤舟。"]'),
('6800d1e3-1bcb-491d-82bb-991f358ca0b3','春晚','趙崇滋','宋','宋诗','song-poetry','','[]','水邊寂寂蒼苔晚，猶有東風爲掩扉。',64,'全唐诗/poet.song.202000.json','["水邊寂寂蒼苔晚，猶有東風爲掩扉。", "一硯落花人睡起，半簾微雨燕飛歸。", "舊時小草塵侵戶，隔日餘薰潤入衣。", "客又不來吟又懶，小山相對拂金徽。"]'),
('bedaf8e9-cb0c-472b-a985-99271c9ca400','客舍','趙崇滋','宋','宋诗','song-poetry','','[]','巷深人寂靜，蛩守客牀鳴。',48,'全唐诗/poet.song.202000.json','["巷深人寂靜，蛩守客牀鳴。", "夜半後風雨，一燈前弟兄。", "愁來無好夢，吟到有新聲。", "不信看雙鬢，蕭蕭白幾莖。"]'),
('7d7f6d2b-9634-4320-a907-89519bcf7cee','求酒趙評事','趙崇滋','宋','宋诗','song-poetry','','[]','半老情懷睡不能，小簷霜月當寒燈。',32,'全唐诗/poet.song.202000.json','["半老情懷睡不能，小簷霜月當寒燈。", "無人來問相如渴，敲碎梅花一夜冰。"]'),
('7081012a-b923-4db7-9f99-c06eddc5d342','題飛霞觀','趙崇滋','宋','宋诗','song-poetry','','[]','水上紅雲岸上風，玄都觀裏又相逢。',32,'全唐诗/poet.song.202000.json','["水上紅雲岸上風，玄都觀裏又相逢。", "世間是色皆爲妄，好去桃花只種松。"]'),
('28251f24-72b6-457a-bfcd-69e0799e234c','句  其一','趙崇滋','宋','宋诗','song-poetry','','[]','事纔有意終須失，人到無求始自高。',48,'全唐诗/poet.song.202000.json','["事纔有意終須失，人到無求始自高。", "貧悟交游秋後葉，老看富貴霧中花。", "從來盡說天堪問，天到如今亦厭煩。"]'),
('c61d34c0-3b44-4480-a1f5-83a18caacf70','句  其二','趙崇滋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','何消百萬西湖宅，遇有梅花便可居。',16,'全唐诗/poet.song.202000.json','["何消百萬西湖宅，遇有梅花便可居。"]'),
('ca658244-779d-468d-8037-333d6c774f40','句  其三','趙崇滋','宋','宋诗','song-poetry','','[]','落花遇雨掃不去，敗草經春剗又生。',16,'全唐诗/poet.song.202000.json','["落花遇雨掃不去，敗草經春剗又生。"]'),
('aea3c795-e566-483e-8260-6fbf7fbb23d2','三臺山','劉子寰','宋','宋诗','song-poetry','','[]','山木鎖冥迷，山前無路歧。',24,'全唐诗/poet.song.202000.json','["山木鎖冥迷，山前無路歧。", "無端流菜葉，剛被世人知。"]'),
('72569ee7-3a76-45a5-9968-07bfbcf82101','芙蓉花','劉子寰','宋','宋诗','song-poetry','','[]','曉粧如玉暮如霞，濃淡分秋染此花。',32,'全唐诗/poet.song.202000.json','["曉粧如玉暮如霞，濃淡分秋染此花。", "終日獨醒干底事，晚知爛醉是生涯。"]'),
('01b69735-9cb1-47ca-9951-4e66ffb27a89','金鳳花','劉子寰','宋','宋诗','song-poetry','','[]','天霜凋九陵，梧桐日枯槁。',84,'全唐诗/poet.song.202000.json','["天霜凋九陵，梧桐日枯槁。", "鳳德何其衰，驚飛下幽草。", "九苞空髣髴，衆彩各自好。", "黄中獨含章，見晚更傾倒。", "託根幔亭峰，弱質深自保。", "便翾金翅短，淡泊乃幾道。", "俗眼迷是非，人間跡如掃。"]'),
('c5597285-67a8-4564-b805-4fd555000800','杜若','劉子寰','宋','宋诗','song-poetry','','[]','欽州五月土如炊，滿山杜若芳菲菲。',134,'全唐诗/poet.song.202000.json','["欽州五月土如炊，滿山杜若芳菲菲。", "素英綠葉紛可喜，勁烈不避炎歊威。", "採之盈掬薦蔬食，臧獲失笑庖人譏。", "君不見屈平夕餐賦秋菊，魂兮無南盍來歸。", "又不見坡公服食得枲耳，扣角自嘆從前非。", "伊予假祿二千石，窮比二子猶庶幾。", "餐花嚼蘂有真樂，一飽何必謀甘肥。", "尚餘升合漬生蜜，從他薏苡生珠璣。"]'),
('da92f142-dd43-437c-bb7d-9400da43924a','賀宰相生日','劉子寰','宋','宋诗','song-poetry','','[]','天開名世五百年，運當啟聖先儲賢。',336,'全唐诗/poet.song.202000.json','["天開名世五百年，運當啟聖先儲賢。", "威靈祥鳳出奇瑞，十洲三島高騰騫。", "爲天立心民立極，續道命脈開真傳。", "日生暘谷蒼凉間，輔道王德充其全。", "輝光篤實君蒙著，一朝扶翊昇虞淵。", "黄樞紫闥求甘盤，風雲赫奕龍飛天。", "正君定國有根本，披腹造膝無拘攣。", "聖皇動息結師保，宮事府事咸咨焉。", "功業巍巍心翼翼，不白得君如此專。", "已知步武通霄漢，但視富貴如雲烟。", "先生所樂非世權，要以道覺天民先。", "經綸盡信中庸旨，業履可稽儒行篇。", "指揮丙魏去痹陋，洗刷周召增光鮮。", "至誠待物微且及，未施而信民陶然。", "四方善類今徯志，直道共由無覺偏。", "惟天大任固有屬，囊括四海空三邊。", "九秋碩果標林端，天根已具陽萌前。", "六度芝耀啟初度，頌聲洋溢瞻霄躚。", "先知已契蓍百莢，久視更期椿八千。", "青衿學子愚且孱，龍門夙昔慚扳牽。", "願依金鼎力薪水，庶與雞犬同登仙。"]'),
('771db473-5a22-4c67-986e-d2e3243df023','壽周丞相益公  其一','劉子寰','宋','宋诗','song-poetry','','["\u534e\u5c71"]','小住人間五百年，因緣真是午橋仙。',64,'全唐诗/poet.song.202000.json','["小住人間五百年，因緣真是午橋仙。", "應期却笑河汾早，占節從教寇相先。", "獨立青雲高兩地，曾扶紅日見三天。", "封疆峻極連華嶽，飲壽應宜吸錦川。"]'),
('60899690-5f1b-423e-bd61-8a0b5a61738b','壽周丞相益公  其二','劉子寰','宋','宋诗','song-poetry','','[]','濟川功就等虛舟，恰似當年溪石遊。',64,'全唐诗/poet.song.202000.json','["濟川功就等虛舟，恰似當年溪石遊。", "月滿東樓新嘯詠，壽高西洛舊風流。", "蒲團看釋千回夏，楸局觀成幾度秋。", "賸喜深衣歸奉檄，分將風月薦金甌。"]'),
('0bff2e3b-efea-4467-a63f-77fb4f675ea9','壽周丞相益公  其三','劉子寰','宋','宋诗','song-poetry','','[]','六月麟書雨作霖，生賢此際見天心。',64,'全唐诗/poet.song.202000.json','["六月麟書雨作霖，生賢此際見天心。", "江都分灑雖名世，莘野商霖始見今。", "門館無于儀表正，經綸有道本源深。", "正人命脈常家主，一念公□□盍簪。"]'),
('78738bc1-b2b5-4003-9102-90673e8e4d00','壽周丞相益公  其四','劉子寰','宋','宋诗','song-poetry','','[]','昨丙辰年相魏公，當時克敵首歸功。',64,'全唐诗/poet.song.202000.json','["昨丙辰年相魏公，當時克敵首歸功。", "何如手補天西漏，仍更神□塞北空。", "一隙暇時關國祚，十分重任頼臣忠。", "天生賢佐興王業，正看周詩六月中。"]'),
('13bc84e9-a58f-4e6a-ba1a-12d19d167ade','壽周丞相益公  其五','劉子寰','宋','宋诗','song-poetry','','[]','兼善工夫自古難，有誰志學合伊顔。',64,'全唐诗/poet.song.202000.json','["兼善工夫自古難，有誰志學合伊顔。", "儒先拈得四書出，名相措諸萬事間。", "功向時危尤易見，道于世運實相關。", "魯論一半猶收效，壽國應須安似山。"]'),
('0ee912bf-74e1-431f-b5a4-bbf377af88be','賀鄭樞齊  其一','劉子寰','宋','宋诗','song-poetry','','[]','鄮峻鄞深鞏會稽，氣鍾神秀半千期。',32,'全唐诗/poet.song.202000.json','["鄮峻鄞深鞏會稽，氣鍾神秀半千期。", "龍飛虎變具元化，地闢天開衍慶基。"]'),
('e426e62e-2b5c-4e80-afba-3e8aa61bcd40','賀鄭樞齊  其二','劉子寰','宋','宋诗','song-poetry','','[]','身扶晹谷出昇日，手引咸池更洗光。',32,'全唐诗/poet.song.202000.json','["身扶晹谷出昇日，手引咸池更洗光。", "須信洪釣有根極，直從朱邸植忠良。"]'),
('ac0781b3-3072-4f50-9ab5-c22bfa8b99a8','賀鄭樞齊  其三','劉子寰','宋','宋诗','song-poetry','','[]','中庸功用本明誠，心正身修久著刑。',32,'全唐诗/poet.song.202000.json','["中庸功用本明誠，心正身修久著刑。", "涵養君心三達國，圖回天下九爲經。"]'),
('7ae96ae8-3567-4409-aca6-150007dd2c74','賀鄭樞齊  其四','劉子寰','宋','宋诗','song-poetry','','[]','人間日月聲名重，筆下波瀾帝澤多。',32,'全唐诗/poet.song.202000.json','["人間日月聲名重，筆下波瀾帝澤多。", "獻納淵衷資啟沃，笑嚬寒谷轉陽和。"]'),
('4ccc320f-9afd-4209-bb4c-0652b03b063d','賀鄭樞齊  其五','劉子寰','宋','宋诗','song-poetry','','[]','紫闥黄樞功已著，蒼生黔首望逾深。',32,'全唐诗/poet.song.202000.json','["紫闥黄樞功已著，蒼生黔首望逾深。", "公施政術施仁術，公得人心得士心。"]'),
('f50778d4-d8eb-4cc8-acc0-0ba76d0257c1','賀鄭樞齊  其六','劉子寰','宋','宋诗','song-poetry','','[]','已觀瑚璉登宗廟，未覺龍淵露穎鋩。',32,'全唐诗/poet.song.202000.json','["已觀瑚璉登宗廟，未覺龍淵露穎鋩。", "好看和風將瑞露，更飛紫電極青霜。"]'),
('40750a03-b9b4-4da8-a521-6c2828516d5c','賀鄭樞齊  其七','劉子寰','宋','宋诗','song-poetry','','[]','樞庭齋閣五雲深，一穗爐薰靜養心。',32,'全唐诗/poet.song.202000.json','["樞庭齋閣五雲深，一穗爐薰靜養心。", "雅志未先天下樂，兩望鐘鼎與山林。"]'),
('80c6cd7c-f247-4f9f-8b6f-74b35bcd9659','賀鄭樞齊  其八','劉子寰','宋','宋诗','song-poetry','','[]','盛麗紛華念不萌，位高心小古難能。',32,'全唐诗/poet.song.202000.json','["盛麗紛華念不萌，位高心小古難能。", "祇今翹館延人物，只似蕭齋接友朋。"]'),
('a6ceedb8-7390-470b-a802-f482a0492985','賀鄭樞齊  其九','劉子寰','宋','宋诗','song-poetry','','[]','君臣魚水方行道，德性鸞凰素服人。',32,'全唐诗/poet.song.202000.json','["君臣魚水方行道，德性鸞凰素服人。", "四海衣冠祈宋祚，萬年基業繫公身。"]'),
('b56eee83-7c2e-4fba-8c80-9c1003e65eeb','賀鄭樞齊  其一○','劉子寰','宋','宋诗','song-poetry','','[]','九秋碩果爛枝繁，中養蟠桃千歲根。',32,'全唐诗/poet.song.202000.json','["九秋碩果爛枝繁，中養蟠桃千歲根。", "政用斯時祝箕壽，永扶皇極正乾坤。"]'),
('24ea8298-8545-47f4-8052-ee8d36e0a763','閑日偶懷','劉子寰','宋','宋诗','song-poetry','','[]','欲將閑日課桑麻，徙倚無端易日斜。',64,'全唐诗/poet.song.202000.json','["欲將閑日課桑麻，徙倚無端易日斜。", "幽野情懷憐碧草，寂寥門館稱黄花。", "末年函席瞻先哲，幾世繩樞守故家。", "今古有誰心事了，隙駒超忽是年華。"]'),
('84e57b9c-13da-429c-8e14-e42f0bfc6d3e','效王建從軍後答','劉子寰','宋','宋诗','song-poetry','','[]','愛山無術住家貧，晚曳長裾傍主人。',64,'全唐诗/poet.song.202000.json','["愛山無術住家貧，晚曳長裾傍主人。", "七十老親拋菽水，二千長路逐風塵。", "瞻雲望月懷三徑，種藥移花嗟一春。", "援筆謾題形語影，及時收取自由身。"]'),
('9372dbba-2de2-4594-993f-b73ee4912e95','嚴江舟次','劉子寰','宋','宋诗','song-poetry','','[]','烟弄晨光雨弄梅，浦痕微漲認潮來。',64,'全唐诗/poet.song.202000.json','["烟弄晨光雨弄梅，浦痕微漲認潮來。", "棹隨縴道青蘆折，路入漁家碧草開。", "指點水程期買酒，追尋古迹謾登臺。", "歸舟不共商人載，便覺新詩得細裁。"]'),
('370f1188-da8d-4200-9001-3e570df8e23d','玉隆宮','劉子寰','宋','宋诗','song-poetry','','[]','避地西山占一區，高風遥想列仙儒。',64,'全唐诗/poet.song.202000.json','["避地西山占一區，高風遥想列仙儒。", "雲開異日人傳見，天上如今宅在無。", "丹去一函空鎖鑰，柏枯千載尚支吾。", "逍遥峰外烟霞鑰，猶恐岡巒落畫圖。"]'),
('18d231c2-579a-4084-8025-9e7bd67f1b32','鼓山靈源洞天風海濤亭','劉子寰','宋','宋诗','song-poetry','','[]','路入靈源洞壑深，側攀巖磴度嶔崟。',64,'全唐诗/poet.song.202000.json','["路入靈源洞壑深，側攀巖磴度嶔崟。", "憑陵萬里烟塵外，虛豁一生江海心。", "雞溆風濤長蕩薄，鴈湖島嶼半浮沉。", "茲遊不減騎鯨背，莫爲天涯嘆滯淫。"]'),
('00926e46-ecf1-4953-9338-5a221dc1c8cd','題梨山祠','劉子寰','宋','宋诗','song-poetry','','[]','慶源仙李蟠根大，形寄叢梨肖像真。',64,'全唐诗/poet.song.202000.json','["慶源仙李蟠根大，形寄叢梨肖像真。", "畏壘一方尸祝地，桐鄉千古子孫民。", "自時厥後來爲牧，沒世不忘知幾人。", "正直不應私有禱，但吟歌樂送迎神。"]'),
('a02a99dc-f311-41c3-bfa4-92858b6d2d18','當陽玉州城','劉子寰','宋','宋诗','song-poetry','','[]','隠隠層臺際混茫，荆關形勝古當陽。',64,'全唐诗/poet.song.202000.json','["隠隠層臺際混茫，荆關形勝古當陽。", "登樓賦裏山川在，抱玉巖前塹壘荒。", "思繞曲沮流脈脈，望迷平楚入蒼蒼。", "青林漸復昇平舊，百里康莊夾綠楊。"]'),
('3739f7a3-b18b-4c74-9fa5-08b53fbbb52d','當陽道間  其一','劉子寰','宋','宋诗','song-poetry','','[]','當陽楚名都，疇昔用武國。',126,'全唐诗/poet.song.202000.json','["當陽楚名都，疇昔用武國。", "山餘磨劍石，陵有拖鎗谷。", "自從春秋來，紛紛幾蠻觸。", "霸主爭盟會，盜賊逞殺戮。", "城郭遞鋤夷，生靈盡魚肉。", "到今猶荒凉，曠野鬼晝哭。", "道途烟火絕，一驛數茅屋。", "盛衰相乘除，治亂有反覆。", "可憐江漢民，生比牛山木。", "靈禽避天風，高士棄周粟。", "遥望武陵源。"]'),
('d79fc880-7932-4aa4-837a-be456f3d9ee5','當陽道間  其二','劉子寰','宋','宋诗','song-poetry','','[]','陵坡杳杳路如繩，緩逐楊花信馬行。',64,'全唐诗/poet.song.202000.json','["陵坡杳杳路如繩，緩逐楊花信馬行。", "芳樹晚餘紅點綴，亂山春入翠縱橫。", "平州廢壘八九里，楚子古藏三四塋。", "宇宙不能無變滅，世間修飾欲何成。"]'),
('078bcb7c-5f11-4d2a-bdc0-e63dc8268ee4','稠巖','劉子寰','宋','宋诗','song-poetry','','[]','萬里驚呼立畫圖，拍天雲浪擁蓬壺。',64,'全唐诗/poet.song.202000.json','["萬里驚呼立畫圖，拍天雲浪擁蓬壺。", "洞穿蒼壁俄空闊，海入碧虛相有無。", "漠漠風帆迷宇宙，離離烟草失江湖。", "百年一餉逢真賞，從此滄洲興轉孤。"]'),
('ec36f342-2d1c-4c4d-811f-8d12388e7d32','清溪','劉子寰','宋','宋诗','song-poetry','','[]','水作澄藍可染衣，坐來巾屨濕烟霏。',64,'全唐诗/poet.song.202000.json','["水作澄藍可染衣，坐來巾屨濕烟霏。", "魶魚時迸九泉出，鼯鼠暝緣千仞飛。", "鬼谷洞前春藥遍，法師巖畔古藤圍。", "故山不是白雲念，長揖人間竟不歸。"]'),
('7213c48e-1c25-4d4d-8132-ab8c02e5defc','荆門蒙泉','劉子寰','宋','宋诗','song-poetry','','[]','郟石玲瓏玉爲骨，下有雙泉深觱沸。',320,'全唐诗/poet.song.202000.json','["郟石玲瓏玉爲骨，下有雙泉深觱沸。", "珠泉凝白玉泉碧，含彩揚輝以其物。", "珠泉靈蚌夜出遊，忽驚月色清如秋。", "一山木葉皆倒影，月輪却在泉間浮。", "玉泉潜珍閟莫測，木石但觀皆潤澤。", "卞和生長此山間，谷邃泉深求不得。", "泉心緩緩噓浮珠，泉口急流深滿渠。", "魚蝦蛭蚓不敢狎，始知下有龍神居。", "老龍動息有常定，朝昏泉湧如潮信。", "餘波派作九曲流，百折不能違水性。", "石池數頃琉璃浸，池底金蓮鋪綠錦。", "金碧晶熒射眼明，煩襟濯盡生寒凜。", "上古消沉不可知，唐賢往往已留題。", "莓苔剝落傳師筆，沙礫滅沒文饒碑。", "汴京往昔昇平日，北上西來多墨客。", "東坡詩扁卧蠶書，魯直門顔生鐵畫。", "嚮來虜寇抄荆門，城郭屋廬俱蕩焚。", "黄頭亦恐殺風景，巋然獨有林亭存。", "古稱神瀵疑茲是，到處涔蹄無此比。", "爭得山頭無戍壘，住向荆門弄泉水。"]'),
('710edfd6-f760-4ae6-8531-cdb52c4620ab','鴈蕩凈名谷簾水','劉子寰','宋','宋诗','song-poetry','','[]','野客弄雲水，翩翩信飛車。',168,'全唐诗/poet.song.202000.json','["野客弄雲水，翩翩信飛車。", "奇峰匹鴈蕩，出沒隨猿狙。", "蒼蒼疊雲屏，下有白石廬。", "石廬故未足，洞腹開巢居。", "青藜小躋攀，路盡仍盤紆。", "呀然忽寬敞，雲霧爲支吾。", "天成與鬼鑿，罔識造物初。", "笑問主者誰，我欲攬其須。", "聳身忽滅沒，扳倒泊鴈湖。", "天風復摩盪，簸灑生明珠。", "爲簾復爲帷，與客相嬉娛。", "倏然一揮霍，五色彌空虛。", "坐來怪事發，迸落隨喧呼。", "大笑下山去，勿爲山鬼愚。"]'),
('7500dac3-187a-453a-927c-d380c7beb1e9','月夜東池賞白蓮','劉子寰','宋','宋诗','song-poetry','','[]','巉巉彼姝子，玉艷明清波。',96,'全唐诗/poet.song.202000.json','["巉巉彼姝子，玉艷明清波。", "素雲裁廣袖，淥水覆青羅。", "秀色妙天質，清香凉思多。", "駕言從之游，夜蟾生庭柯。", "徘徊碧雲暮，悵望採菱歌。", "常恐秋節晚，零落委寒莎。", "躊躇思折贈，達夕成長哦。", "非君盛才藻，如此粲者何。"]'),
('0d2b4156-ae84-43de-a05c-fd07616f8084','杜宇','劉子寰','宋','宋诗','song-poetry','','[]','鮮鮮紋綬變毛衣，帝蜀繁華夢亦非。',32,'全唐诗/poet.song.202000.json','["鮮鮮紋綬變毛衣，帝蜀繁華夢亦非。", "大好家居君不惜，到今飄泊更思歸。"]'),
('c5c09ace-d5c1-4c9e-ae68-a5fb2dc7abde','小蚋','劉子寰','宋','宋诗','song-poetry','','[]','烏蚋納如塵，終朝惱殺人。',48,'全唐诗/poet.song.202000.json','["烏蚋納如塵，終朝惱殺人。", "聚來俄擾擾，揮去大頻頻。", "不辦追忙客，偏能撓靜身。", "衁池何限飽，笑汝自迷津。"]'),
('958becb9-f7ec-4152-97db-1e7169498a7e','武夷猴','劉子寰','宋','宋诗','song-poetry','','[]','獼猴群居時，得食互爭奪。',183,'全唐诗/poet.song.202000.json','["獼猴群居時，得食互爭奪。", "囂嘵以力勝，無復長幼別。", "及其有老病，同類爭救活。", "嗛食置其旁，交來伺饑渴。", "死埋高崖巔，併力事窊掘。", "乃知稟元命，無間{羽戊}與狨。", "質性有所偏，良能或焉闕。", "惟仁乃生理，惻隠由情發。", "鳥烏知反哺，報祭及豺獺。", "人心具中和，推此與天達。", "物欲爲私蔽，真知反磨滅。", "利害怵於中，骨肉交朋絕。", "一從失本心，比獸乃反劣。", "武夷山多猴，此事樵者說。", "因書觀□篇，惟日三省察。"]'),
('c7af3c25-6653-4305-ad40-ba0f6b1258bd','教犢偶作進退格','劉子寰','宋','宋诗','song-poetry','','[]','牛角纔及繭，已須穿鼻耕。',48,'全唐诗/poet.song.202000.json','["牛角纔及繭，已須穿鼻耕。", "及茲方率性，過此失良能。", "人道事矯揉，物生殊苦辛。", "遂令禪學子，恐懼說無生。"]'),
('cc2b816c-3b1f-413b-b0c8-645227fcae41','沙溪田舍','劉子寰','宋','宋诗','song-poetry','','[]','急景蕭蕭黄葉風，野人籬落半烟中。',64,'全唐诗/poet.song.202000.json','["急景蕭蕭黄葉風，野人籬落半烟中。", "天霜點染林巒出，田水悲鳴禾稻空。", "稱貸有逋緣地瘠，偫儲無政謾年豐。", "綠林豪客饒牛酒，自保冠山竹籐叢。"]'),
('bc95c855-507b-4646-8a7e-160111af4800','建寧郡齋','劉子寰','宋','宋诗','song-poetry','','[]','鳴禽依約似山家，只欠園林好物華。',32,'全唐诗/poet.song.202000.json','["鳴禽依約似山家，只欠園林好物華。", "城角日高春寂寂，小庭行遍拾桐花。"]'),
('33ec7d13-7a79-4645-aece-ac13a0aebc52','石井亭','劉子寰','宋','宋诗','song-poetry','','[]','一樹疎桐蔽夕陽，也教客子久徬徨。',32,'全唐诗/poet.song.202000.json','["一樹疎桐蔽夕陽，也教客子久徬徨。", "隔溪可惜誰亭館，閑却竹陰無限凉。"]'),
('792c2fd5-16f4-4896-af98-e25057fdaa00','當陽新店','劉子寰','宋','宋诗','song-poetry','','[]','桑坡麥壟行百里，解鞍夜宿清漳湄。',256,'全唐诗/poet.song.202000.json','["桑坡麥壟行百里，解鞍夜宿清漳湄。", "清漳悠悠引通浦，茅廬竹屋相因依。", "米鹽一鬨商估集，舍人奪席厨爭炊。", "試登高阜望陶牧，平原沃野何逶迤。", "俗傳范子計然地，民生鹵莽今如斯。", "荆關四衝古戰國，往往赤子多殲夷。", "土人客戶幾更變，嚮之昭屈餘幾希。", "欲從故老問遺迹，百年而上無能知。", "地名多與載史合，荒城大冢猶依稀。", "沮漳二水楚之望，以此取證他無疑。", "古稱錫穴最深阻，方城漢水爲城池。", "奈何形勝不足恃，豪傑殺盡名都隳。", "自從秦漢至今日，率不百年逢亂離。", "隰臯衍沃但茅葦，時康尚欠人扶犂。", "焉得英雄守四極，封殖生齒令繁滋。", "玉州平州古磚甓，令人想見昇平時。"]'),
('3f9644d5-9e42-43cb-a63b-a6baf5435771','憶篁㟳山居','劉子寰','宋','宋诗','song-poetry','','[]','客氊靜擁爐熅坐，恍惚神遊篁㟳山。',64,'全唐诗/poet.song.202000.json','["客氊靜擁爐熅坐，恍惚神遊篁㟳山。", "巖路依依尋曲折，石泉歷歷記潺湲。", "藥畦道者多慵灌，花蔓獼猴定恣攀。", "今夜山寒松子落，居人應合夢吾還。"]'),
('58b3b8bd-3826-41c5-bd47-a5e1cc406fb2','晚宿張坂庵','劉子寰','宋','宋诗','song-poetry','','[]','問宿樵夫指翠微，溪窮路轉扣庵扉。',64,'全唐诗/poet.song.202000.json','["問宿樵夫指翠微，溪窮路轉扣庵扉。", "深沉山木日先晚，寂寞野棠春自歸。", "客路經過殊草草，舊規牢落重依依。", "勞生暫此逢休適，一餉中林笋蕨肥。"]'),
('0a88e7ff-8638-419c-89e2-5553800d3200','題靈梵院壁','劉子寰','宋','宋诗','song-poetry','','[]','世故嬰拂人，逃荒伴禪寂。',72,'全唐诗/poet.song.202000.json','["世故嬰拂人，逃荒伴禪寂。", "莓苔一古寺，塵土四立壁。", "百年諸名賢，不復見陳迹。", "舊題風雨剝，廢寢莎蔓積。", "夕陽喬木外，悵望驚獨立。", "去去勿復言，浮生盡遊客。"]'),
('fc8592bd-5105-4f1e-a271-86125955caea','靈梵院夜起','劉子寰','宋','宋诗','song-poetry','','[]','寺古居人稀，林高暑氣薄。',48,'全唐诗/poet.song.202000.json','["寺古居人稀，林高暑氣薄。", "露鳴青松枝，夜半有驚鵲。", "飛星遠長漢，白雲平大壑。", "客子開西窗，心空山月落。"]'),
('8be4cf57-6fe6-49db-bb1b-8c89a41c21b8','九峰庵偶書','劉子寰','宋','宋诗','song-poetry','','[]','山棲白雲表，高卧息煩倦。',72,'全唐诗/poet.song.202000.json','["山棲白雲表，高卧息煩倦。", "正夏谷風凉，長日嵐陰半。", "樵人歸路遠，亭午各已散。", "犬靜眠松簷，鳥下浴泉澗。", "杖藜隨興往，卷帙從風亂。", "遠我遺世情，方能涉憂患。"]'),
('a9d4d0a0-7c12-43f8-bed0-71971ffbd4dd','偶成  其一','劉子寰','宋','宋诗','song-poetry','','[]','游從舊分唯三逕，依倚新交只瘦筇。',32,'全唐诗/poet.song.202000.json','["游從舊分唯三逕，依倚新交只瘦筇。", "紅葉碧花詩滿眼，秋來多病苦無悰。"]'),
('267031ea-42d9-4b80-ad6c-95699a103bc1','偶成  其二','劉子寰','宋','宋诗','song-poetry','','[]','雲本無心盡自閑，捲舒無礙在空山。',32,'全唐诗/poet.song.202000.json','["雲本無心盡自閑，捲舒無礙在空山。", "終然未免形爲役，也逐風波浪往還。"]'),
('b7116bfa-b21d-49a5-af54-16971b8a212b','偶成  其三','劉子寰','宋','宋诗','song-poetry','','[]','蛛絲纖巧得飛蟲，鳩拙營巢子墮空。',32,'全唐诗/poet.song.202000.json','["蛛絲纖巧得飛蟲，鳩拙營巢子墮空。", "才與不才天分定，一身勞逸未應同。"]'),
('067e8341-da6a-4880-bcf9-bf0393b60ae6','續桃符句','劉子寰','宋','宋诗','song-poetry','','[]','臘雪衝風得快晴，閑簷日暖引經行。',64,'全唐诗/poet.song.202000.json','["臘雪衝風得快晴，閑簷日暖引經行。", "舊山忽趁林疎出，新水還從凍解生。", "村巷歲除聲寂寞，花梢春到色精明。", "桃符只被詩催換，自笑衰翁未老成。"]'),
('d5526262-f1b0-44c4-8552-5eddad77501b','跋舊題','劉子寰','宋','宋诗','song-poetry','','[]','溪樓逆旅棣華西，窗扇烟埃暗舊題。',32,'全唐诗/poet.song.202000.json','["溪樓逆旅棣華西，窗扇烟埃暗舊題。", "久視字書差可認，初然吟玩是誰詩。"]'),
('20d6f9b2-a2e4-4e5f-964b-268d6f43aa8c','壽史相  其一','劉子寰','宋','宋诗','song-poetry','','[]','何許生賢踵世官，十洲風物四明山。',32,'全唐诗/poet.song.202000.json','["何許生賢踵世官，十洲風物四明山。", "股肱光輔唐虛際，衮綉親傳父子間。"]'),
('a0b38aa3-494a-4c32-af8f-31b5521a4deb','壽史相  其二','劉子寰','宋','宋诗','song-poetry','','[]','秉軸持衡歲五周，從今千載國同休。',32,'全唐诗/poet.song.202000.json','["秉軸持衡歲五周，從今千載國同休。", "汾陽謾校中書考，安得如公尚黑頭。"]'),
('184f283a-fb35-40a1-a91c-45bbfdc1fc21','壽侍郎','劉子寰','宋','宋诗','song-poetry','','[]','陽萌兩日壽星光，天祐生賢侍玉皇。',64,'全唐诗/poet.song.202000.json','["陽萌兩日壽星光，天祐生賢侍玉皇。", "上世勳庸滿鍾鼎，後昆風骨總侯王。", "朝回絳闕清都曉，梅發斷橋流水香。", "政自調羹相門事，佇看衮綉作衣裳。"]'),
('fb78bdbb-69f0-43de-88bf-32c4f1084ef6','壽趙守','劉子寰','宋','宋诗','song-poetry','','[]','參橫斗轉五更寒，春入黄堂酒盞寬。',32,'全唐诗/poet.song.202000.json','["參橫斗轉五更寒，春入黄堂酒盞寬。", "幕客更賽千歲頌，家人羊薦五辛盤。"]'),
('af3392c5-1138-437c-b31f-04e7178a0fe5','壽張倉','劉子寰','宋','宋诗','song-poetry','','[]','喬木端由有世臣，傳家事業飽經綸。',64,'全唐诗/poet.song.202000.json','["喬木端由有世臣，傳家事業飽經綸。", "鵷行稍厭承明直，熊軾來頒建水春。", "暖入東君新聽朔，祥開南極慶生申。", "沙堤消息人來說，紫詔催□入秉鈞。"]'),
('ff849d4d-33de-476f-a3c9-e5162a11a13c','約友人賞春','劉子寰','宋','宋诗','song-poetry','','[]','人生何復最爲親，不看春容不認真。',64,'全唐诗/poet.song.202000.json','["人生何復最爲親，不看春容不認真。", "岸柳細摇多意思，野花初綻足精神。", "精神識得施爲別，意思到時言語新。", "爲報同門須急賞，莫教春去始傷春。"]'),
('a0cd04b9-6cba-4771-9dde-1ef1f5a3a2a2','贈寫神陳光甫  其一','劉子寰','宋','宋诗','song-poetry','','[]','寫照無因畫隠微，不差毫髮似君稀。',64,'全唐诗/poet.song.202000.json','["寫照無因畫隠微，不差毫髮似君稀。", "正須著我巖石底，是殆見我神氣機。", "行到逼真人却惡，精於懸鑑物難違。", "朱鉛莫惜饒顔色，衆目不求公是非。"]'),
('41cfe4be-a12b-449f-96be-71132586d38b','贈寫神陳光甫  其二','劉子寰','宋','宋诗','song-poetry','','[]','不論道貌與天形，纔入毫端便逼真。',64,'全唐诗/poet.song.202000.json','["不論道貌與天形，纔入毫端便逼真。", "幻出千般人面目，只憑一點自精神。", "雲臺人去丹青歇，月鑑方來事業新。", "寢陋可能當審象，且將粉澤付斯人。"]'),
('e010a9b4-4c15-47b9-9f9f-7b1a2426ac68','送劉篁㟳','馮取洽','宋','宋诗','song-poetry','','[]','來似孤雲出岫閑，去如高月耿難攀。',32,'全唐诗/poet.song.202000.json','["來似孤雲出岫閑，去如高月耿難攀。", "若爲化作修修竹，長伴先生篁㟳山。"]'),
('9cdef8e7-25e7-46e7-9a5f-58bf96d448a1','自題交游風月樓','馮取洽','宋','宋诗','song-poetry','','[]','平揖雙峰俯霽虹，近窺喬木欲相雄。',64,'全唐诗/poet.song.202000.json','["平揖雙峰俯霽虹，近窺喬木欲相雄。", "一溪流水一溪月，八面疎櫺八面風。", "取用自然無盡藏，高寒如在太虛空。", "落成恰值三秋半，爲我吹開白兔宮。"]'),
('98de8026-0a0a-4f57-b6f5-7ba8720e56d8','自淮梱代歸領累偕親友游虎丘偶成數語以紀歲月時淳祐庚戌七月廿五日','丘岳','宋','宋诗','song-poetry','','[]','一目四蒼莽，突然見林丘。',96,'全唐诗/poet.song.202000.json','["一目四蒼莽，突然見林丘。", "飛來靈鷲峰，幻出蓬萊洲。", "浮圖高崒嵂，石徑通深幽。", "生公講經臺，曾聞石點頭。", "劍池杳無底，脩綆汲寒流。", "千古詫奇傳，茲事還是不。", "我來秋向深，良苗帀平疇。", "憂國願年豐，一稔銷百憂。"]'),
('5d56b5c8-0eda-4242-ad81-b31d5cef7968','句','康南翁','宋','宋诗','song-poetry','','[]','塔何曾動誰留影，石不能言自點頭。',16,'全唐诗/poet.song.202000.json','["塔何曾動誰留影，石不能言自點頭。"]'),
('546bda6c-e188-4b9f-bdf5-1319140ce735','磊石','鄭良臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','軒轅奏樂洞庭濱，樂罷齊呼萬歲聲。',32,'全唐诗/poet.song.202000.json','["軒轅奏樂洞庭濱，樂罷齊呼萬歲聲。", "留得伶倫鍾一箇，山僧日夜祝皇明。"]'),
('babefd09-27b1-4a4a-82e5-bba9ef5da349','句  其一','張仲節','宋','宋诗','song-poetry','','[]','蝴蝶似知春夢熟，穿巷飛度畫屏東。',16,'全唐诗/poet.song.202000.json','["蝴蝶似知春夢熟，穿巷飛度畫屏東。"]'),
('7a67aeb2-cbb8-4f95-b642-760776d9000f','句  其二','張仲節','宋','宋诗','song-poetry','','[]','夜夜月明金苑裏，如何照不到長門。',16,'全唐诗/poet.song.202000.json','["夜夜月明金苑裏，如何照不到長門。"]'),
('410cce7f-ff1a-460f-b9bf-3c594bf98656','句  其三','張仲節','宋','宋诗','song-poetry','','[]','凱歌四面動地來，斬得名王歸獻闕。',16,'全唐诗/poet.song.202000.json','["凱歌四面動地來，斬得名王歸獻闕。"]'),
('54f530e2-d5ef-48e9-a103-9814e7b4d6f3','句  其四','張仲節','宋','宋诗','song-poetry','','[]','一朝驃騂先論功，封侯佩印授齊鉞。',16,'全唐诗/poet.song.202000.json','["一朝驃騂先論功，封侯佩印授齊鉞。"]'),
('bfc6ea4d-c6c6-49d6-8090-b2de0df597b8','句  其五','張仲節','宋','宋诗','song-poetry','','[]','不知去年征戰時，妾家良人在還沒。',16,'全唐诗/poet.song.202000.json','["不知去年征戰時，妾家良人在還沒。"]'),
('4e468d66-3327-4c25-9886-abdf282c5fbe','賦筆','方武裘','宋','宋诗','song-poetry','','[]','貌出中山骨欲仙，何人拔穎縛尖圓。',64,'全唐诗/poet.song.202000.json','["貌出中山骨欲仙，何人拔穎縛尖圓。", "拙夫堪笑堆成冢，豪客曾聞掃似椽。", "窗下玉蜍涵夜月，几間雪繭湧春泉。", "當時定遠成何事，輕擲毛錐恐不然。"]'),
('30d893eb-9970-446c-91af-f124174f4ce0','古樂府  其一','程垣','宋','宋诗','song-poetry','','[]','長安花如錦，不堪製郎衣。',24,'全唐诗/poet.song.202000.json','["長安花如錦，不堪製郎衣。", "拾得并州剪，剪花花忽飛。"]'),
('925db190-4b07-48f6-bf98-9f921803d414','古樂府  其二','程垣','宋','宋诗','song-poetry','','[]','清溪彩鴛鴦，野性不可馴。',24,'全唐诗/poet.song.202000.json','["清溪彩鴛鴦，野性不可馴。", "君心空愛渠，渠無愛君心。"]'),
('e91975f6-f7a7-42a0-b03c-30c8cc66ece9','古樂府  其三','程垣','宋','宋诗','song-poetry','','[]','莫嫌秋後扇，明年還六月。',24,'全唐诗/poet.song.202000.json','["莫嫌秋後扇，明年還六月。", "凄凉暫離別，恩情難斷絕。"]'),
('6eede1c9-f65c-45eb-bf9e-3f04d93d783d','探賾  其一','程垣','宋','宋诗','song-poetry','','[]','一氣自盤礴，萬物自儵忽。',48,'全唐诗/poet.song.202000.json','["一氣自盤礴，萬物自儵忽。", "盤礴運高厚，儵忽祝生沒。", "高厚固冥冥，生沒亦汩汩。", "願言握金鏡，以祛我之惑。"]'),
('573929e6-6e37-4339-a5c9-37308b8cfd95','探賾  其二','程垣','宋','宋诗','song-poetry','','[]','莊周一妄誕，丘明一浮夸。',48,'全唐诗/poet.song.202000.json','["莊周一妄誕，丘明一浮夸。", "兩都繡春英，三京組朝霞。", "楚騷哀靈均，鵩賦凄長沙。", "律以素王經，春蛙與寒鴉。"]'),
('a64b4603-1e8a-4d6d-a2f9-fdd4109382aa','雜興  其一','程垣','宋','宋诗','song-poetry','','[]','拋拋機中梭，婉婉機中淑。',48,'全唐诗/poet.song.202000.json','["拋拋機中梭，婉婉機中淑。", "蘭膏媚鬢蟬，笋纖潤紅玉。", "織成錦繡段，光耀綺霞幅。", "世無黄鍾尺，何以製華服。"]'),
('6407386d-3e46-4d22-829f-36db77e35d66','雜興  其二','程垣','宋','宋诗','song-poetry','','[]','青青琅玕竹，節直中心虛。',48,'全唐诗/poet.song.202000.json','["青青琅玕竹，節直中心虛。", "風月與相忘，雪霜不能欺。", "斸之獻良工，堪葺黄金輿。", "悲哉渭水濱，空抱歲寒姿。"]'),
('5f5375e5-6421-4eae-a18b-7a6699fcb3ba','雜興  其三','程垣','宋','宋诗','song-poetry','','[]','南山有孤松，夭矯蒼龍質。',48,'全唐诗/poet.song.202000.json','["南山有孤松，夭矯蒼龍質。", "亭亭聳華蓋，清風自永日。", "珍重棟梁材，甘心跧崖石。", "梓匠持規矩，大器匪易得。"]'),
('88ded159-11a9-491d-b0c8-b75850f780f7','樵家','程垣','宋','宋诗','song-poetry','','[]','深溪藏毒蛟，樵家冰竈口。',48,'全唐诗/poet.song.202000.json','["深溪藏毒蛟，樵家冰竈口。", "結侶腰彎刀，破衲補更厚。", "持擔俯清流，勇往不回首。", "褰裳望青採，豈暇尋枯朽。"]'),
('3fd9e35e-c0d0-4b02-addf-ad982330ee1b','樵叟','程垣','宋','宋诗','song-poetry','','[]','蒼蒼雙鬢銀，矍鑠不憚勤。',48,'全唐诗/poet.song.202000.json','["蒼蒼雙鬢銀，矍鑠不憚勤。", "背曲行步遲，徐徐溪水濱。", "羣兒喧南山，踏起南山塵。", "翁跣負薪回，換得一壺春。"]'),
('9facfeac-0947-493e-8a92-6ad35b5efd71','樵子','程垣','宋','宋诗','song-poetry','','[]','頭蓬面萎黄，身輕步忽逮。',48,'全唐诗/poet.song.202000.json','["頭蓬面萎黄，身輕步忽逮。", "方斫柴薪回，又带刀斧去。", "戲笑茅根掘，時暫松根踞。", "間道後山歸，人尋不知處。"]'),
('5bfb0e9a-2e48-4221-84f6-6b7312814ff2','樵徑','程垣','宋','宋诗','song-poetry','','[]','捫蘿登峻坂，不避嵐霾冒。',48,'全唐诗/poet.song.202000.json','["捫蘿登峻坂，不避嵐霾冒。", "拔茅過山䧆，壯者爲前導。", "陰濕留步跡，葉滑無人掃。", "誰言此地幽，亦有春風到。"]'),
('20de0641-3923-44c2-8c2e-27860a7d46f2','樵風','程垣','宋','宋诗','song-poetry','','[]','樵夫識雨候，風起裝樵歸。',48,'全唐诗/poet.song.202000.json','["樵夫識雨候，風起裝樵歸。", "只顧擔重輕，無心問是非。", "纔觀六鷁退，隨知少女機。", "同行採樵人，先後不相違。"]'),
('c067a66d-0a75-4a0c-8d6e-49bc6b16c33f','夏日下聞溪渡','程垣','宋','宋诗','song-poetry','','[]','溪橋架木度人行，人影溪中步步生。',64,'全唐诗/poet.song.202000.json','["溪橋架木度人行，人影溪中步步生。", "真水真山皆舊識，時來時去幾關情。", "魚驚鷗立無閑意，鳥逐蟬飛有遁聲。", "暫止筍輿生僕力，可人時至午風清。"]'),
('6c3733fa-45fd-4293-b3d3-5f474fb177b7','梅花  其一','黄祖潤','宋','宋诗','song-poetry','','[]','天籟消沈斗柄斜，繞枝忽起護巢鴉。',32,'全唐诗/poet.song.202000.json','["天籟消沈斗柄斜，繞枝忽起護巢鴉。", "素娥青女新梳洗，來鬭寒梅半夜花。"]'),
('966941d7-4a88-4d95-802d-9d28c853368b','梅花  其二','黄祖潤','宋','宋诗','song-poetry','','[]','白氎禪巾白石龕，跏趺無迹越山庵。',32,'全唐诗/poet.song.202000.json','["白氎禪巾白石龕，跏趺無迹越山庵。", "朝朝拱立罔明手，昨夜看梅廢小參。"]'),
('9d6a9838-bd1b-4030-8ae2-b29eb37e3de8','梅花  其三','黄祖潤','宋','宋诗','song-poetry','','[]','林間翠羽啄枯槎，邂逅孤筇次水涯。',32,'全唐诗/poet.song.202000.json','["林間翠羽啄枯槎，邂逅孤筇次水涯。", "飛過小溪留數語，殷勤報有隔橋花。"]'),
('d2789382-698a-41be-8e88-2e63fc38204c','句  其一','黄祖潤','宋','宋诗','song-poetry','','[]','何須更辨傷春謗，歲歲飄零不及春。',16,'全唐诗/poet.song.202000.json','["何須更辨傷春謗，歲歲飄零不及春。"]'),
('802158d2-e212-4837-8666-e89f8b9f04eb','句  其二','黄祖潤','宋','宋诗','song-poetry','','[]','效顰可醜張元妹，競爽宜爲束皙兄。',16,'全唐诗/poet.song.202000.json','["效顰可醜張元妹，競爽宜爲束皙兄。"]'),
('0144ddae-d4e0-42e7-a5e4-bdf9666120a3','鏡香亭','林逢子','宋','宋诗','song-poetry','','[]','綠楊深處兩三家，幾度憑闌聽吠蛙。',32,'全唐诗/poet.song.202000.json','["綠楊深處兩三家，幾度憑闌聽吠蛙。", "雲錦已空烟水闊，空教人憶舊時花。"]'),
('52869ebd-fc52-4bec-b94b-763190cf9799','宣公祠  其一','林逢子','宋','宋诗','song-poetry','','[]','仁義百篇唐孟子，排姦勁節凜秋霜。',32,'全唐诗/poet.song.202000.json','["仁義百篇唐孟子，排姦勁節凜秋霜。", "人生一死固不免，死落忠州骨也香。"]'),
('86868b9a-027f-4da0-a60c-e8dca5879676','宣公祠  其二','林逢子','宋','宋诗','song-poetry','','[]','千年往事隨流水，一縷香烟吊蜀魂。',32,'全唐诗/poet.song.202000.json','["千年往事隨流水，一縷香烟吊蜀魂。", "門掩落花人不到，野風邀月照黄昏。"]'),
('beb3a766-9b6d-489b-a628-fb380c2e46f6','送胡季昭竄象郡','翁定','宋','宋诗','song-poetry','','[]','應詔書聞便遠行，廬陵不獨詫邦衡。',64,'全唐诗/poet.song.202000.json','["應詔書聞便遠行，廬陵不獨詫邦衡。", "寸心祇恐孤天地，百口何期累弟兄。", "世態浮雲多變換，公朝初日盍清明。", "危言在國爲元氣，君子從來豈顧名。"]'),
('32d91dd7-5f9d-4a75-81c4-5375bec62cfb','賀带湖六十三','翁定','宋','宋诗','song-poetry','','[]','風吹仙夢落江南，忽忽今年六十三。',64,'全唐诗/poet.song.202000.json','["風吹仙夢落江南，忽忽今年六十三。", "嗜酒引壺傾臘蟻，揮毫落紙食春蠶。", "行觀仙籍香浮桂，榮看恩袍色鬭藍。", "他日投簪松徑下，摩挲銅狄對清談。"]'),
('3ff4fc72-087f-416b-9346-659815f5677b','春','翁定','宋','宋诗','song-poetry','','[]','睡起庭前立片時，寂無人到亂雲飛。',32,'全唐诗/poet.song.202000.json','["睡起庭前立片時，寂無人到亂雲飛。", "楊花吹盡鶑聲懶，小雨廉纖春已歸。"]'),
('d5c0b9f3-559b-47c4-b3c2-44c898cba72b','知縣','翁定','宋','宋诗','song-poetry','','[]','來時人指拙爲謀，出手方知刃解牛。',32,'全唐诗/poet.song.202000.json','["來時人指拙爲謀，出手方知刃解牛。", "有病黄堂懷藥問，丐歸紫橐列銜留。"]'),
('60c4d41d-7b1a-411b-aaed-47048086968b','垂虹橋','翁定','宋','宋诗','song-poetry','','[]','虹橋影倒中邊月，蟾鏡光浮上下磨。',32,'全唐诗/poet.song.202000.json','["虹橋影倒中邊月，蟾鏡光浮上下磨。", "未易丹青知畫少，苦難題品費詩多。"]'),
('54a04737-2739-4999-91d9-baa0d0263609','舟航','翁定','宋','宋诗','song-poetry','','[]','晚風乘興出溪邊，小立斜陽待釣船。',32,'全唐诗/poet.song.202000.json','["晚風乘興出溪邊，小立斜陽待釣船。", "喚僕去尋賒酒店，倩人來認買魚錢。"]'),
('aa58ee4a-1e34-444f-99bd-3fd7b8091a69','句  其一','翁定','宋','宋诗','song-poetry','','[]','雍容陪大政，密勿贊洪鈞。',12,'全唐诗/poet.song.202000.json','["雍容陪大政，密勿贊洪鈞。"]'),
('578cf195-c40a-470c-a8b0-4d82530a242c','句  其二','翁定','宋','宋诗','song-poetry','','[]','在朝但覺民瞻聳，參政從知國勢高。',16,'全唐诗/poet.song.202000.json','["在朝但覺民瞻聳，參政從知國勢高。"]'),
('4253a99e-4d37-43e1-83a1-aee0b9a8f5e6','句  其三','翁定','宋','宋诗','song-poetry','','[]','有少園池僅蔬竹，無多屋宇欠樓臺。',16,'全唐诗/poet.song.202000.json','["有少園池僅蔬竹，無多屋宇欠樓臺。"]'),
('c656306d-f978-4f0a-97f2-5214c42e88dc','句  其四','翁定','宋','宋诗','song-poetry','','[]','喚僕過林寺，逢僧問石橋。',12,'全唐诗/poet.song.202000.json','["喚僕過林寺，逢僧問石橋。"]'),
('af8911a3-5924-4a62-9ed9-7a75c9348747','句  其五','翁定','宋','宋诗','song-poetry','','[]','雨餘便涉嶺，風定穩行船。',12,'全唐诗/poet.song.202000.json','["雨餘便涉嶺，風定穩行船。"]'),
('9ed44b93-d5cc-4bf6-8cb2-db6cac0b187b','杜鵑花  其一','趙戣','宋','宋诗','song-poetry','','[]','雲樹重重和淚冷，故宮遺廟有知音。',32,'全唐诗/poet.song.202000.json','["雲樹重重和淚冷，故宮遺廟有知音。", "秦吳萬里皆芳草，染到山花恨最深。"]'),
('931103f2-7703-4f04-88de-b4a12af05e26','杜鵑花  其二','趙戣','宋','宋诗','song-poetry','','[]','春山未有杜鵑啼，花發杜鵑知不知。',32,'全唐诗/poet.song.202000.json','["春山未有杜鵑啼，花發杜鵑知不知。", "寄語催歸儘哀怨，莫將啼血污仙姿。"]'),
('3187e9bb-3543-474c-b3fd-6a8c95af37a8','杜鵑花  其三','趙戣','宋','宋诗','song-poetry','','[]','冰肌玉骨擅無雙，不與山花鬭艷妝。',32,'全唐诗/poet.song.202000.json','["冰肌玉骨擅無雙，不與山花鬭艷妝。", "欲染啼紅冤杜宇，爭如傅粉伴何郎。"]'),
('c2ba2805-aaad-43ab-9a6f-acd4bfeb9de8','楓','趙戣','宋','宋诗','song-poetry','','[]','黄紅紫綠巖巒上，遠近高低松竹間。',32,'全唐诗/poet.song.202000.json','["黄紅紫綠巖巒上，遠近高低松竹間。", "山色未應秋後老，靈楓方爲駐童顔。"]'),
('3b5165d4-21fa-4ce1-ba2e-925b66629420','北窗伊吾  其一','趙戣','宋','宋诗','song-poetry','','[]','伊吾維吾，椎魯株愚。',20,'全唐诗/poet.song.202000.json','["伊吾維吾，椎魯株愚。", "友資其深，片雪洪罏。"]'),
('35ea7578-93d6-4edb-9077-2167eb8fc2b1','北窗伊吾  其二','趙戣','宋','宋诗','song-poetry','','[]','伊吾維吾，甕牖繩樞。',20,'全唐诗/poet.song.202000.json','["伊吾維吾，甕牖繩樞。", "爰升其華，秋月冰壺。"]'),
('bbb030fb-2b1f-48da-abe5-648d925155d5','北窗伊吾  其三','趙戣','宋','宋诗','song-poetry','','[]','伊吾維吾，緝柳編蒲。',20,'全唐诗/poet.song.202000.json','["伊吾維吾，緝柳編蒲。", "爰席其珍，尺璧珊瑚。"]'),
('25d035ae-9a6d-4272-b9f0-0898c8953d5c','北窗伊吾  其四','趙戣','宋','宋诗','song-poetry','','[]','伊吾維吾，朝饘暮餬。',23,'全唐诗/poet.song.202000.json','["伊吾維吾，朝饘暮餬。", "爰餔其{飠臾}，醴酪醍醐。"]'),
('3572bf27-8ecf-457e-96ab-74c46fd35945','北窗伊吾  其五','趙戣','宋','宋诗','song-poetry','','[]','伊吾維吾，何以爲娛。',20,'全唐诗/poet.song.202000.json','["伊吾維吾，何以爲娛。", "爰心其聲，鐘磬笙竽。"]'),
('1c17ad6f-9d17-4306-823e-a3047da7cfc1','北窗伊吾  其六','趙戣','宋','宋诗','song-poetry','','[]','北窗伊吾，吾誰與俱。',20,'全唐诗/poet.song.202000.json','["北窗伊吾，吾誰與俱。", "融融沂風，懷哉舞雩。"]'),
('66b3d4bd-9f1a-415c-ae59-03ec7991be46','閲浯溪集用山谷韻','趙戣','宋','宋诗','song-poetry','','[]','花間小閣臨清溪，綠窗坐閲三吾碑。',192,'全唐诗/poet.song.202000.json','["花間小閣臨清溪，綠窗坐閲三吾碑。", "恍如登高俯絕壑，倚杖松陰挽兔絲。", "幽尋勝賞客思奇，一聲欵乃誰家兒。", "浯溪映带湘東西，碧山曾看漫郎棲。", "銀鈎玉筯苔蘚古，神剜天畫非人爲。", "憶昔儲皇披輿圖，白衣山人稱帝師。", "汾營老將智勇俱，陰霾四塞天戈揮。", "至今老石勵庸懦，野水亦解扶顛危。", "後來弔古者爲誰，涪翁清響車攻詩。", "當時寡和孤白雪，我故欲尾春風辭。", "恨不插羽西南飛，山前更著小艇隨。", "夜闌忽夢訪遺址，月色慘淡猿聲悲。"]'),
('931db2cd-840a-4efa-91a9-6889cd59a9b2','雨中見花','趙戣','宋','宋诗','song-poetry','','[]','細雨歛輕塵，枝間態度新。',48,'全唐诗/poet.song.202000.json','["細雨歛輕塵，枝間態度新。", "春疑天雨寶，寒怯地鋪裀。", "葉底含羞女，闌邊倚醉人。", "休將脂粉涴，一一是天真。"]'),
('0f7639b2-0f7a-4569-b8fc-58da8ffcac76','悼鶴','趙戣','宋','宋诗','song-poetry','','[]','乘化歸遼海，雙龍一不開。',48,'全唐诗/poet.song.202000.json','["乘化歸遼海，雙龍一不開。", "墜翎留片雪，遺跡印荒苔。", "月朗憐孤唳，琴間憶共來。", "瘞銘爲琢石，雞鶩不須猜。"]'),
('ddd147cf-81bf-42ac-b3d1-f6d2b417bbf9','藍溪道中','趙戣','宋','宋诗','song-poetry','','[]','綠窈雨初歇，清和日正長。',48,'全唐诗/poet.song.202000.json','["綠窈雨初歇，清和日正長。", "乳禽穿薄靄，弱蔓上頹牆。", "村市筍厨美，田家麰餌香。", "老翁扶杖出，小立看移秧。"]'),
('2e63d5f5-545a-48f1-beda-3f8c2ef517c1','詠史二十二首  其一','趙戣','宋','宋诗','song-poetry','','[]','聖德光天下，歲功成閏餘。',24,'全唐诗/poet.song.202000.json','["聖德光天下，歲功成閏餘。", "百篇推帝典，一半是農書。"]'),
('ecc171c7-5f59-47f6-9508-182f5a585e82','詠史二十二首  其二','趙戣','宋','宋诗','song-poetry','','[]','遯跡陶漁久，論功納麓多。',24,'全唐诗/poet.song.202000.json','["遯跡陶漁久，論功納麓多。", "已傳精一語，更作勅天歌。"]'),
('62329816-8704-46af-b99f-dd9d88f43579','詠史二十二首  其三','趙戣','宋','宋诗','song-poetry','','[]','地已還三壤，彝方次九疇。',24,'全唐诗/poet.song.202000.json','["地已還三壤，彝方次九疇。", "基圖天與子，典則我貽謀。"]'),
('61adaf3c-5753-4eaa-a1b3-5ae26ac39afb','詠史二十二首  其四','趙戣','宋','宋诗','song-poetry','','[]','罪己桑林六，仁心祝網三。',24,'全唐诗/poet.song.202000.json','["罪己桑林六，仁心祝網三。", "只應寬代虐，何事德懷慚。"]'),
('f97a6f8b-60f7-4dc2-8440-abb3e1c00441','詠史二十二首  其五','趙戣','宋','宋诗','song-poetry','','[]','大邑周新造，曾孫武始王。',24,'全唐诗/poet.song.202000.json','["大邑周新造，曾孫武始王。", "伯夷方馬諫，尚父已鷹揚。"]'),
('be79a49a-7dec-4d69-9c14-72e679b9a167','詠史二十二首  其六','趙戣','宋','宋诗','song-poetry','','[]','萬世家爲國，長城山作圍。',24,'全唐诗/poet.song.202000.json','["萬世家爲國，長城山作圍。", "試憑驪岫望，秦鹿幾年肥。"]'),
('11669b7d-3d9e-4d1c-8c33-9b5b8fb65cd8','詠史二十二首  其七','趙戣','宋','宋诗','song-poetry','','[]','真主乘昌運，假王恢雋功。',24,'全唐诗/poet.song.202000.json','["真主乘昌運，假王恢雋功。", "如何亡頼子，失笑未央宮。"]'),
('4bcd22e3-22af-4532-b095-730fc7ad4a6a','詠史二十二首  其八','趙戣','宋','宋诗','song-poetry','','[]','意豁高皇似，雄才大敵摧。',24,'全唐诗/poet.song.202000.json','["意豁高皇似，雄才大敵摧。", "萬方瞻日角，列宿粲雲臺。"]'),
('20788865-9f71-485c-a13a-e3f02a5c2ada','詠史二十二首  其九','趙戣','宋','宋诗','song-poetry','','[]','橫槊真名將，燃萁亦忍人。',24,'全唐诗/poet.song.202000.json','["橫槊真名將，燃萁亦忍人。", "大君時有命，雅意俗還淳。"]'),
('577cf230-ebe3-4489-a818-31a96bb9b505','詠史二十二首  其一○','趙戣','宋','宋诗','song-poetry','','[]','犬噬憂方重，羊車意轉深。',24,'全唐诗/poet.song.202000.json','["犬噬憂方重，羊車意轉深。", "可憐司馬國，又屬問蟆人。"]'),
('2045d53d-9e7a-4e94-bd6c-9adceb3e0910','詠史二十二首  其一一','趙戣','宋','宋诗','song-poetry','','[]','馬浮雖是讖，牛繼亦殊聞。',24,'全唐诗/poet.song.202000.json','["馬浮雖是讖，牛繼亦殊聞。", "昔者車書共，天乎南北分。"]'),
('dc0efa25-b532-48af-b017-fab47ab6d593','詠史二十二首  其一二','趙戣','宋','宋诗','song-poetry','','[]','已拓三秦地，寧無幾月留。',24,'全唐诗/poet.song.202000.json','["已拓三秦地，寧無幾月留。", "登城聊北望，老淚不勝流。"]'),
('c39e91fc-9c4d-4bee-93bf-f4dfc33add6b','詠史二十二首  其一三','趙戣','宋','宋诗','song-poetry','','[]','戡難功何補，欺孤計已深。',24,'全唐诗/poet.song.202000.json','["戡難功何補，欺孤計已深。", "儘饒摧導玉，那解賤黄金。"]'),
('15f2936b-768f-4554-bd5b-81fd6c0dffb0','詠史二十二首  其一四','趙戣','宋','宋诗','song-poetry','','[]','玉陛尊梁帝，金園號羣公。',24,'全唐诗/poet.song.202000.json','["玉陛尊梁帝，金園號羣公。", "聞經同泰寺，索蜜凈居宮。"]'),
('a7413d26-3884-4eb4-af78-1cd33900d619','詠史二十二首  其一五','趙戣','宋','宋诗','song-poetry','','[]','清凈方貽笑，莊嚴更舍身。',24,'全唐诗/poet.song.202000.json','["清凈方貽笑，莊嚴更舍身。", "基圖雖肇始，識趣只庸人。"]'),
('6c8c3bbf-cb41-4e3b-972b-b7994c8e6427','詠史二十二首  其一六','趙戣','宋','宋诗','song-poetry','','[]','猛上臨光殿，生擒歸命侯。',24,'全唐诗/poet.song.202000.json','["猛上臨光殿，生擒歸命侯。", "師心無學術，與子失貽謀。"]'),
('69e6572c-b6f6-4706-ae3e-7a9f3e6c435b','詠史二十二首  其一七','趙戣','宋','宋诗','song-poetry','','[]','唐室恢新造，秦王有大功。',24,'全唐诗/poet.song.202000.json','["唐室恢新造，秦王有大功。", "一人居北極，太子在東宮。"]'),
('504184e5-4afc-4d48-80d1-244a930a21b3','詠史二十二首  其一八','趙戣','宋','宋诗','song-poetry','','[]','未必黄明在，終令丑口亡。',24,'全唐诗/poet.song.202000.json','["未必黄明在，終令丑口亡。", "難教疎網漏，不直敗氈藏。"]'),
('856ed204-9258-472f-a0cb-5f01edbe4c32','詠史二十二首  其一九','趙戣','宋','宋诗','song-poetry','','[]','刺心真有志，批頰更何爲。',24,'全唐诗/poet.song.202000.json','["刺心真有志，批頰更何爲。", "試問唐新主，何如亞子時。"]'),
('a4728b51-26d1-4a95-b441-18cf98fb21ad','詠史二十二首  其二○','趙戣','宋','宋诗','song-poetry','','[]','尊以父皇帝，賂之十六州。',24,'全唐诗/poet.song.202000.json','["尊以父皇帝，賂之十六州。", "終無噉飯所，誰不石郎羞。"]'),
('2809c7bc-33ce-4b4a-b1ed-db0244c374d3','詠史二十二首  其二一','趙戣','宋','宋诗','song-poetry','','[]','不假契丹力，踢翻麥飯盂。',24,'全唐诗/poet.song.202000.json','["不假契丹力，踢翻麥飯盂。", "試看龍衮畔，還有雀兒無。"]'),
('eb9e1c46-3f64-4da9-907c-da31bb22384f','詠史二十二首  其二二','趙戣','宋','宋诗','song-poetry','','[]','坤輿聊底定，鼎祚又更新。',24,'全唐诗/poet.song.202000.json','["坤輿聊底定，鼎祚又更新。", "五代無真主，世宗差可人。"]'),
('909dbf61-4f1f-4762-bc7f-2361233114ef','和人淵明采菊圖','趙戣','宋','宋诗','song-poetry','','[]','淵明爲米腰慵折，送酒人來却强顔。',32,'全唐诗/poet.song.202000.json','["淵明爲米腰慵折，送酒人來却强顔。", "今日東籬重采菊，只應醒眼對南山。"]'),
('55a615a9-45b7-4be5-bf05-39f93aea37d5','錦鶒夜逸','趙戣','宋','宋诗','song-poetry','','[]','草徑鬰紆溪隔村，誰抽關鐍逋孤鴛。',64,'全唐诗/poet.song.202000.json','["草徑鬰紆溪隔村，誰抽關鐍逋孤鴛。", "林樊搜糾崖廠邃，岸曲括責菰茭根。", "初擬布罟鼠盜夜，又恐缺月狐乘昏。", "死殻枯梗秘蹤跡，老圉勸我增垣藩。"]'),
('0c0d66cc-44f1-4543-80f8-7901467604cb','胡葦航寄古劍','盛世忠','宋','宋诗','song-poetry','','[]','有人尺錦長安來，遠寄寶匣手自開。',96,'全唐诗/poet.song.202000.json','["有人尺錦長安來，遠寄寶匣手自開。", "紅雲紫氣燦虛室，鋏中青蛇鱗生苔。", "誠携掌握一揮動，瞬息天地興風雷。", "少年志氣老益壯，惟願聖詔下九垓。", "廐中我有汗血馬，與汝直北清氛埃。", "丈夫當爲國雪恥，笑指經生真不才。"]'),
('e2c1715a-1e61-4e9a-8270-91f07776268a','柴門','盛世忠','宋','宋诗','song-poetry','','[]','石砌苔初合，柴門手自開。',48,'全唐诗/poet.song.202000.json','["石砌苔初合，柴門手自開。", "日催花影轉，風遞竹聲來。", "蟹眼翻茶鼎，鵝兒灧酒杯。", "不須憂歲計，魁芋已新栽。"]'),
('f0d13e19-aaeb-47ee-9132-6ff5a404afe1','劉常簿席上','盛世忠','宋','宋诗','song-poetry','','[]','近授長生券，從天下綺筵。',48,'全唐诗/poet.song.202000.json','["近授長生券，從天下綺筵。", "潞公專洛日，呂望佐姬年。", "坐語風生舌，梳頭雪滿肩。", "上思耆舊用，飛詔到林泉。"]'),
('11044554-daf0-4ba7-9d4e-82b9b6a04aae','觀棋','盛世忠','宋','宋诗','song-poetry','','[]','爭先劉與項，得勢楚侵秦。',48,'全唐诗/poet.song.202000.json','["爭先劉與項，得勢楚侵秦。", "本是知心友，翻成敵國人。", "運籌爭劫殺，敗局在逡巡。", "袖手旁觀者，機深亦損神。"]'),
('8c6b21aa-7c18-4172-a2f3-7a94196513d3','送呂東山之清漳','盛世忠','宋','宋诗','song-poetry','','[]','君是純陽派，神清性亦真。',48,'全唐诗/poet.song.202000.json','["君是純陽派，神清性亦真。", "有詩聊遣興，無術可醫貧。", "富貴皆尤物，江湖易老人。", "置山錢足矣，客路莫因循。"]'),
('f7f67d39-6183-4e2a-af3c-6ec3f1f2a214','寄藏叟僧善珍','盛世忠','宋','宋诗','song-poetry','','[]','訪友南山路，橋橫古木陰。',48,'全唐诗/poet.song.202000.json','["訪友南山路，橋橫古木陰。", "砌苔無俗跡，庭柏是禪心。", "舊衲連雲補，新詩带月吟。", "同袍嚴戒行，別是一叢林。"]'),
('c1427301-ca29-4d0f-915d-b5dad3b25c6c','生涯詩','盛世忠','宋','宋诗','song-poetry','','[]','壯歲欲飛騰，生涯亦可矜。',48,'全唐诗/poet.song.202000.json','["壯歲欲飛騰，生涯亦可矜。", "一千餘日戰，三十九年僧。", "硯枕秋風夢，書燈夜雨澄。", "儒生貴知命，飲水曲吾肱。"]'),
('16077c71-5a44-4c06-a6a5-24779f39612f','簡賈戶部','盛世忠','宋','宋诗','song-poetry','','[]','十五年前別，相逢各老成。',48,'全唐诗/poet.song.202000.json','["十五年前別，相逢各老成。", "舊遊如一夢，忽見似重生。", "劇飲無人敵，高談坐客驚。", "諸郎尤可喜，事業短燈檠。"]'),
('b03c28ed-584c-43c3-b41a-507c69628cd2','病起書院偶成','盛世忠','宋','宋诗','song-poetry','','[]','蓄水滋蘭畹，開窗近竹林。',48,'全唐诗/poet.song.202000.json','["蓄水滋蘭畹，開窗近竹林。", "敗糊黄螘鬨，斷簡老蟲侵。", "酒尚欺人病，詩能對客吟。", "晨昏一飽足，此外不關心。"]'),
('7ee1a104-a147-4172-88f1-84e68d8d225e','秦竹溪校書清漳未回','盛世忠','宋','宋诗','song-poetry','','[]','茅齋雅稱竹方牀，風過疎籬有暗香。',64,'全唐诗/poet.song.202000.json','["茅齋雅稱竹方牀，風過疎籬有暗香。", "劇飲一冬成酒病，得閑終日爲詩忙。", "新移橘本便霜信，貪看梅花倚夕陽。", "相望故人三百里，十宵九夢到清漳。"]'),
('f39aa819-dc96-40a9-ad56-2851e73cb335','今是行呈劉以道','盛世忠','宋','宋诗','song-poetry','','[]','少年湖海誤加鞭，久戍歸歟暫息肩。',64,'全唐诗/poet.song.202000.json','["少年湖海誤加鞭，久戍歸歟暫息肩。", "時有故山來夢裏，更無愁緒到吟邊。", "晨餐全仰數畦菜，歲計尤逋二頃田。", "閑倚瘦筇長嘯處，此身疑是結繩前。"]'),
('9fcb501b-feb3-4666-917a-13af5862b781','塞上聞角','盛世忠','宋','宋诗','song-poetry','','[]','刁斗城頭夜月寒，一聲嗚咽到江干。',32,'全唐诗/poet.song.202000.json','["刁斗城頭夜月寒，一聲嗚咽到江干。", "梅花吹落渾閑事，白首征人淚暗彈。"]'),
('78fdc68e-3b7c-4c93-a638-918744490e5b','倦妝圖','盛世忠','宋','宋诗','song-poetry','','[]','睡覺春山懶更添，起來餘恨鎖眉尖。',32,'全唐诗/poet.song.202000.json','["睡覺春山懶更添，起來餘恨鎖眉尖。", "料應春事關心曲，怕見楊花不捲簾。"]'),
('c0b73240-48c7-40ac-8a96-4676ac169f32','嬾讀書','盛世忠','宋','宋诗','song-poetry','','[]','不弄絲桐不作詩，槃池疊石學兒嬉。',32,'全唐诗/poet.song.202000.json','["不弄絲桐不作詩，槃池疊石學兒嬉。", "少年讀易都忘却，身似羲皇未畫時。"]'),
('0894600f-a63c-44c5-97a2-0b8ac48536e1','王昭君','盛世忠','宋','宋诗','song-poetry','','[]','漢使南歸絕信音，氈庭青草始知春。',32,'全唐诗/poet.song.202000.json','["漢使南歸絕信音，氈庭青草始知春。", "蛾眉却解安邦國，羞殺麒麟閣上人。"]'),
('b2263da4-5422-4b20-930e-16d8d3326d5f','次屏翁韻','戴燁','宋','宋诗','song-poetry','','[]','幾番樽酒遇書櫺，談笑清風起座屏。',64,'全唐诗/poet.song.202000.json','["幾番樽酒遇書櫺，談笑清風起座屏。", "一世猖狂渾似醉，此心明白固長醒。", "英雄自昔難虛老，鐘鼎他年要刻銘。", "若見旁人問消息，爲言桂子待秋馨。"]'),
('66893031-ce60-4af8-9fea-031cfd9755ad','題武夷','蔡模','宋','宋诗','song-poetry','','[]','絕壑藤蘿貯翠烟，水聲咄咄亂峰前。',32,'全唐诗/poet.song.202000.json','["絕壑藤蘿貯翠烟，水聲咄咄亂峰前。", "時人但說青山好，腸斷雲間雙髻仙。"]'),
('b03d4c14-bfa7-4868-8721-a1d3bd9cca7e','獻闕廷','鄭宷','宋','宋诗','song-poetry','','[]','韓陽風景世間無，堪與王維作畫圖。',64,'全唐诗/poet.song.202000.json','["韓陽風景世間無，堪與王維作畫圖。", "四顧羅山朝虎井，一條带小繞龜湖。", "形如丹鳳飛銜印，勢似蒼龍卧吐珠。", "此處不堪爲縣治，更於何處拜皇都。"]'),
('17058e71-4fb1-48fc-81ab-66f6ef065fd0','雲巖','金文剛','宋','宋诗','song-poetry','','[]','丹崖何突兀，與客共躋攀。',48,'全唐诗/poet.song.202000.json','["丹崖何突兀，與客共躋攀。", "一嘯九天潤，斷雲千古閑。", "杖行龍虎背，袖拂斗牛間。", "願言覓刀圭，乘風弄羽翰。"]'),
('f4374521-cfd4-4f7f-880e-21f6354a7ca5','慶元府人日鄉飲酒禮','顔頤仲','宋','宋诗','song-poetry','','[]','王春人日喜陰晴，文物衣冠萃四明。',64,'全唐诗/poet.song.202000.json','["王春人日喜陰晴，文物衣冠萃四明。", "禮樂幾年今一見，主賓百拜酒三行。", "人心天理須興起，士習民風悉變更。", "太守自慚才德薄，綱維全頼老先生。"]'),
('0499fec9-755c-4cab-b0b2-e0bb880da8f1','柳花','顔頤仲','宋','宋诗','song-poetry','','[]','柳漸成陰萬縷斜，無腰柔弱弄韶華。',32,'全唐诗/poet.song.202000.json','["柳漸成陰萬縷斜，無腰柔弱弄韶華。", "一庭春色無人管，簷雨聲中飛盡花。"]'),
('147b0df0-4df4-461f-9d63-7ad95598adb9','桐','顔頤仲','宋','宋诗','song-poetry','','[]','庭梧驚秋風，葉葉彫萎紅。',60,'全唐诗/poet.song.202000.json','["庭梧驚秋風，葉葉彫萎紅。", "行人何不歸，委魂逐孤鴻。", "去日良已賒，客身轉飄蓬。", "千里各一涯，關山月明中。", "兩臂恨不羽，飛逐君西東。"]'),
('378b87bc-01bf-40e8-883d-433612230c47','和碧玉千峰詩','顔頤仲','宋','宋诗','song-poetry','','[]','道在穹壤間，如日照萬國。',192,'全唐诗/poet.song.202000.json','["道在穹壤間，如日照萬國。", "淳乾再中天，斯文荷申錫。", "惟時朱夫子，一柱擎天力。", "勉齋妙心傳，月印寒潭碧。", "東野正始音，絕唱未易續。", "昕庭萬言對，珠璣燦盈掬。", "一麾壓南州，寒谷回春燠。", "煌煌漳水珠，照燿崑山玉。", "美哉巽齋守，傑構捐金錢。", "橫經踞臯比，冠劍來三千。", "賢侯揭新扁，偉觀還當年。", "孰能踵公武，名蓋東南天。", "經畬望有秋，譬彼田舍翁。", "學道猶學醫，百脈期疏通。", "立身尚名節，峻峙千仞峰。", "勉哉蹈前修，毋與流俗同。"]');
